const performQuotaReset = async (userId: string, role: UserRole) => {
    const newReset = Date.now() + 30 * 24 * 60 * 60 * 1000;
    const total = getQuotaForRole(role);

    if (!isMock) {
        await db.collection('users').doc(userId).update({
