                           </button>
                      </div>

                      {/* Results List */}
                      {generatedPosts.length > 0 && (
                          <div className="space-y-8 animate-fade-in">
                              <h3 className="text-xl font-bold text-gray-300">生成結果</h3>
                              {generatedPosts.map((post) => (
                                  <div key={post.id} className="bg-card rounded-xl border border-gray-700 overflow-hidden flex flex-col md:flex-row">
                                      {/* Preview Area */}
                                      <div className="w-full md:w-1/3 bg-black flex items-center justify-center relative min-h-[300px]">
                                          {getPreviewUrl(post) ? (
                                              <img src={getPreviewUrl(post)} alt="Post" className="w-full h-full object-cover" />
                                          ) : (
                                              <div className="text-gray-500 text-sm">無圖片</div>
                                          )}

                                          {/* Image Overlay Controls */}
                                          <div className="absolute bottom-2 left-2 right-2 flex gap-2 overflow-x-auto p-1 bg-black/50 rounded backdrop-blur-sm">
                                              <button onClick={() => handleImageModeChange(post, 'stock')} className="text-xs bg-gray-700 text-white px-2 py-1 rounded whitespace-nowrap">📷 換圖庫</button>
                                              <button onClick={() => handleImageModeChange(post, 'ai')} className="text-xs bg-purple-700 text-white px-2 py-1 rounded whitespace-nowrap">🎨 AI重繪</button>
                                              <button onClick={() => handleImageModeChange(post, 'news')} className="text-xs bg-blue-700 text-white px-2 py-1 rounded whitespace-nowrap">📰 找新聞圖</button>
                                          </div>

                                          {/* Manual Upload hidden input */}
                                          {post.imageSourceType === 'upload' && (
                                              <div className="absolute top-2 right-2">
                                                  <label className="bg-gray-800 text-white text-xs px-2 py-1 rounded cursor-pointer border border-gray-600">
                                                      📂 上傳
                                                      <input type="file" className="hidden" onChange={(e) => handleFileUpload(post.id, e)} accept="image/*" />
                                                  </label>
                                              </div>
                                          )}

                                          {isRegeneratingImage === post.id && (
                                              <div className="absolute inset-0 bg-black/70 flex items-center justify-center">
                                                  <div className="loader"></div>
                                              </div>
                                          )}
                                      </div>

                                      {/* Content Editor */}
                                      <div className="flex-1 p-6 flex flex-col">
                                          <div className="flex justify-between mb-2">
                                              <span className="text-xs text-gray-500 bg-gray-800 px-2 py-1 rounded">
                                                  {accounts.find(a => a.id === post.targetAccountId)?.username || 'Unknown'}
                                              </span>
                                              <div className="flex gap-2">
                                                  <label className="text-xs text-gray-400 flex items-center gap-1 cursor-pointer">
                                                      <input 
                                                          type="radio" 
                                                          checked={post.imageSourceType === 'none'} 
                                                          onChange={() => handleImageModeChange(post, 'none')}
                                                      /> 純文字
                                                  </label>
                                                  <label className="text-xs text-gray-400 flex items-center gap-1 cursor-pointer">
                                                      <input 
                                                          type="radio" 
                                                          checked={post.imageSourceType === 'upload'} 
                                                          onChange={() => setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, imageSourceType: 'upload' } : p))}
                                                      /> 手動上傳
                                                  </label>
                                              </div>
                                          </div>

                                          <textarea 
                                              value={post.caption}
                                              onChange={(e) => setGeneratedPosts(prev => prev.map(p => p.id === post.id ? { ...p, caption: e.target.value } : p))}
                                              className="w-full flex-1 bg-dark border border-gray-600 rounded p-3 text-white mb-4 resize-none focus:border-primary outline-none"
                                          />

                                          {post.log && (
                                              <div className="text-xs text-red-400 mb-2">{post.log}</div>
                                          )}

                                          <button 
                                              onClick={() => handlePublish(post)}
                                              disabled={post.status === 'publishing' || post.status === 'done'}
                                              className={`w-full py-3 rounded font-bold transition-all ${
                                                  post.status === 'done' ? 'bg-green-700 text-white cursor-default' :
                                                  post.status === 'publishing' ? 'bg-gray-600 text-gray-300' :
                                                  'bg-white text-black hover:bg-gray-200'
                                              }`}
                                          >
                                              {post.status === 'done' ? '✅ 已發佈' : post.status === 'publishing' ? '發送中...' : '🚀 發佈到 Threads'}
                                          </button>
                                      </div>
                                  </div>
                              ))}
                          </div>
                      )}
                  </div>
              )}
          </div>
      )}

      {/* VIEW: INTERACTION */}
      {activeTab === 'interaction' && (
          <div className="space-y-6">
              <div className="bg-card p-6 rounded-xl border border-gray-700">
                  <div className="flex justify-between items-center mb-6">
                      <div>
                          <h3 className="text-xl font-bold text-white">最新留言</h3>
                          <p className="text-sm text-gray-400">系統將掃描所有活躍帳號的最新 3 篇貼文留言</p>
                      </div>
                      <button onClick={handleScan} className="bg-pink-600 hover:bg-pink-500 text-white px-4 py-2 rounded font-bold">
                          🔄 掃描留言
                      </button>
                  </div>

                  {comments.length === 0 ? (
                      <div className="text-center py-10 text-gray-500 border border-dashed border-gray-700 rounded">
                          尚無新留言或未掃描
                      </div>
                  ) : (
                      <div className="space-y-4">
                          {comments.map(comment => (
                              <div key={comment.id} className="bg-dark p-4 rounded border border-gray-600">
                                  <div className="flex justify-between mb-2">
                                      <span className="font-bold text-white">@{comment.username}</span>
                                      <span className="text-xs text-gray-500 bg-gray-800 px-2 py-1 rounded">
                                          To: {accounts[comment.accountIndex]?.username}
                                      </span>
                                  </div>
                                  <p className="text-gray-300 mb-4">{comment.text}</p>

                                  {selectedCommentId === comment.id ? (
                                      <div className="bg-gray-800 p-3 rounded">
                                          {generatedReplies.length > 0 ? (
                                              <div className="space-y-2">
                                                  {generatedReplies.map((reply, idx) => (
                                                      <div key={idx} className="flex gap-2">
                                                          <div className="flex-1 text-sm bg-black/30 p-2 rounded text-gray-200">{reply}</div>
                                                          <button onClick={() => handleSendReply(comment, reply)} className="bg-primary text-white px-3 rounded text-sm hover:bg-blue-600">
                                                              發送
                                                          </button>
                                                      </div>
                                                  ))}
                                                  <div className="border-t border-gray-700 my-2 pt-2">
                                                      <input 
                                                          value={draftReply}
                                                          onChange={e => setDraftReply(e.target.value)}
                                                          placeholder="或手動輸入回覆..."
                                                          className="w-full bg-black/30 text-white p-2 rounded text-sm mb-2"
                                                      />
                                                      <button onClick={() => handleSendReply(comment, draftReply)} disabled={!draftReply} className="w-full bg-gray-600 hover:bg-gray-500 text-white py-1 rounded text-sm">
                                                          發送手動回覆
                                                      </button>
                                                  </div>
                                              </div>
                                          ) : (
                                              <div className="text-center text-sm text-gray-400 py-2">
                                                  AI 正在思考回覆...
                                              </div>
                                          )}
                                      </div>
                                  ) : (
                                      <button onClick={() => handleGenReply(comment)} className="text-sm text-primary hover:text-white underline">
                                          ✨ 生成 AI 回覆建議
                                      </button>
                                  )}
                              </div>
                          ))}
                      </div>
                  )}
              </div>
          </div>
      )}
    </div>
  );
};

export default ThreadsNurturePanel;

import React, { useState } from 'react';
import { generateSeoArticle } from '../services/geminiService';
import { checkAndUseQuota, logUserActivity } from '../services/authService';
import { UserProfile } from '../types';

interface Props {
    user: UserProfile | null;
    onQuotaUpdate: () => void;
}

const SeoArticleGenerator: React.FC<Props> = ({ user, onQuotaUpdate }) => {
    // Input States - Generic Defaults
    const [topic, setTopic] = useState('');
    const [length, setLength] = useState('約 800 字');
    const [keywords, setKeywords] = useState('');

    // Checkbox Options
    const [optAgenda, setOptAgenda] = useState(true);
    const [optMeta, setOptMeta] = useState(true);
    const [optFAQ, setOptFAQ] = useState(true);
    const [optRefLinks, setOptRefLinks] = useState(true);

    // Output States
    const [resultText, setResultText] = useState('');
    const [imageKeyword, setImageKeyword] = useState('');
    const [isGenerating, setIsGenerating] = useState(false);
    const [errorMsg, setErrorMsg] = useState('');
    const [copyBtnText, setCopyBtnText] = useState('複製全文');

    const handleGenerate = async () => {
        if (!topic.trim()) {
            setErrorMsg("請輸入核心關鍵字！");
            return;
        }
        if (!user || isGenerating) return;

        setErrorMsg('');

        // SEO Articles cost 15 Credits (High Value Replacement)
        const COST = 15;

        // Check Quota
        try {
            const allowed = await checkAndUseQuota(user.user_id, COST);
            if (!allowed) {
                setErrorMsg(`⚠️ 配額不足 (需要 ${COST} 點)，無法生成文章。請升級方案或聯絡管理員。`);
                return;
            }
            onQuotaUpdate();
        } catch (e) {
            setErrorMsg("資料庫連線錯誤，無法確認配額。");
            return;
        }

        setIsGenerating(true);
        setResultText('');
        setImageKeyword('');

        try {
            const result = await generateSeoArticle(
                topic, 
                length, 
                keywords, 
                { agenda: optAgenda, meta: optMeta, faq: optFAQ, refLinks: optRefLinks }
            );
            setResultText(result.fullText);
            setImageKeyword(result.imageKeyword);

            // --- Log Usage ---
            logUserActivity({
                uid: user.user_id,
                act: 'seo',
                topic: topic,
                prmt: `Keywords: ${keywords}, Length: ${length}`,
                res: result.fullText,
                params: JSON.stringify({ options: { optAgenda, optMeta, optFAQ } })
            });

        } catch (e: any) {
            console.error(e);
            setErrorMsg(`生成失敗: ${e.message || "未知錯誤"}`);
        } finally {
            setIsGenerating(false);
        }
    };

    const handleCopy = () => {
        if (!resultText) return;
        navigator.clipboard.writeText(resultText).then(() => {
            setCopyBtnText('已複製！');
            setTimeout(() => setCopyBtnText('複製全文'), 2000);
        });
    };

    const searchStock = (provider: 'pexels' | 'unsplash' | 'pixabay') => {
        const query = imageKeyword || topic;
        const encoded = encodeURIComponent(query);
        let url = '';

        if (provider === 'pexels') url = `https://www.pexels.com/zh-tw/search/${encoded}/`;
        else if (provider === 'unsplash') url = `https://unsplash.com/s/photos/${encoded}`;
        else if (provider === 'pixabay') url = `https://pixabay.com/images/search/${encoded}/`;

        window.open(url, '_blank');
    };

    return (
        <div className="max-w-4xl mx-auto space-y-8 animate-fade-in pb-20">
            <h2 className="text-3xl font-bold text-white mb-6 text-center">
                AI 部落格文章生成器 <span className="text-sm font-normal text-primary bg-blue-900/30 border border-blue-900 px-2 py-1 rounded-full ml-2">SEO 專用版</span>
            </h2>

            {/* Step 1: Input Form */}
            <div className="bg-card p-6 rounded-xl border border-gray-700 shadow-lg">
                <h2 className="text-xl font-semibold text-white mb-4 border-b border-gray-700 pb-2">步驟一：生成 SEO 文章</h2>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="col-span-1">
                        <label className="block text-sm font-medium text-gray-400 mb-1">核心關鍵字 (主題)</label>
                        <input 
                            type="text" 
                            value={topic} 
                            onChange={(e) => setTopic(e.target.value)}
                            placeholder="例如：2024 AI 趨勢、美食+旅遊"
                            className="w-full bg-dark border border-gray-600 rounded p-3 text-white focus:border-primary outline-none"
                        />
                    </div>
                    <div className="col-span-1">
                        <label className="block text-sm font-medium text-gray-400 mb-1">預計長度</label>
                        <select 
                            value={length} 
                            onChange={(e) => setLength(e.target.value)}
                            className="w-full bg-dark border border-gray-600 rounded p-3 text-white focus:border-primary outline-none"
                        >
                            <option value="約 800 字">約 800 字 (標準)</option>
                            <option value="約 1500 字">約 1500 字 (深度長文)</option>
                            <option value="約 2500 字">約 2500 字 (權威指南)</option>
                        </select>
                    </div>

                    <div className="col-span-2">
                        <label className="block text-sm font-medium text-gray-400 mb-1">LSI 關鍵字組 (長尾關鍵字)</label>
                        <textarea 
                            rows={2} 
                            value={keywords}
                            onChange={(e) => setKeywords(e.target.value)}
                            placeholder="例如：ChatGPT 應用, 數位行銷工具, 生產力提升"
                            className="w-full bg-dark border border-gray-600 rounded p-3 text-white focus:border-primary outline-none resize-y"
                        />
                    </div>

                    {/* SEO Options */}
                    <div className="col-span-2 bg-dark/50 p-4 rounded-lg border border-gray-600">
                        <span className="block text-sm font-medium text-gray-300 mb-3">文章必須要素 (SEO 優化選項)</span>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            <label className="inline-flex items-center cursor-pointer">
                                <input type="checkbox" checked={optAgenda} onChange={(e) => setOptAgenda(e.target.checked)} className="form-checkbox h-5 w-5 text-indigo-600 rounded bg-gray-700 border-gray-500" />
                                <span className="ml-2 text-gray-300 text-sm">生成文章目錄 (Agenda/TOC)</span>
                            </label>
                            <label className="inline-flex items-center cursor-pointer">
                                <input type="checkbox" checked={optMeta} onChange={(e) => setOptMeta(e.target.checked)} className="form-checkbox h-5 w-5 text-indigo-600 rounded bg-gray-700 border-gray-500" />
                                <span className="ml-2 text-gray-300 text-sm">Meta Description (摘要)</span>
                            </label>
                            <label className="inline-flex items-center cursor-pointer">
                                <input type="checkbox" checked={optFAQ} onChange={(e) => setOptFAQ(e.target.checked)} className="form-checkbox h-5 w-5 text-indigo-600 rounded bg-gray-700 border-gray-500" />
                                <span className="ml-2 text-gray-300 text-sm">FAQ 常見問題區塊</span>
                            </label>
                            <label className="inline-flex items-center cursor-pointer">
                                <input type="checkbox" checked={optRefLinks} onChange={(e) => setOptRefLinks(e.target.checked)} className="form-checkbox h-5 w-5 text-indigo-600 rounded bg-gray-700 border-gray-500" />
                                <span className="ml-2 text-gray-300 text-sm">自動附上權威參考連結 (E-E-A-T)</span>
                            </label>
                        </div>
                    </div>
                </div>

                {errorMsg && (
                    <div className="mt-4 p-3 bg-red-900/50 border border-red-500 text-red-200 rounded">
                        {errorMsg}
                    </div>
                )}

                <button 
                    onClick={handleGenerate}
                    disabled={isGenerating}
                    className="mt-6 w-full py-3 px-4 text-white font-bold bg-primary rounded-lg shadow-md hover:bg-blue-600 transition duration-200 flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    {isGenerating ? <div className="loader"></div> : null}
                    {isGenerating ? 'AI 正在撰寫中 (約需 10-20 秒)...' : '開始生成純文字文章 (消耗 15 配額)'}
                </button>
            </div>

            {/* Step 2: Result */}
            {resultText && (
                <div className="bg-card p-6 rounded-xl shadow-lg border border-gray-700 animate-fade-in">
                    <div className="flex justify-between items-center mb-4">
                        <h2 className="text-xl font-semibold text-white">文章內容 (純文字)</h2>
                        <button 
                            onClick={handleCopy}
                            className={`py-2 px-4 rounded-lg shadow-md transition duration-150 text-sm font-medium text-white ${copyBtnText === '已複製！' ? 'bg-green-600' : 'bg-primary hover:bg-blue-600'}`}
                        >
                            {copyBtnText}
                        </button>
                    </div>
                    <textarea 
                        readOnly
                        value={resultText}
                        rows={20} 
                        className="w-full bg-dark p-4 border border-gray-600 rounded-lg text-gray-200 text-base leading-relaxed resize-y font-sans focus:outline-none focus:border-primary"
                    />
                </div>
            )}

