  const [showReportModal, setShowReportModal] = useState(false);
  // #endregion

  // #region Storage Utilities
  /**
   * 安全儲存貼文至 LocalStorage，處理空間爆滿問題
   */
  const savePostsSafely = (updatedPosts: Post[]) => {
      const POSTS_KEY = 'autosocial_posts';
      try {
          localStorage.setItem(POSTS_KEY, JSON.stringify(updatedPosts));
          setPosts(updatedPosts);
      } catch (e: any) {
          console.warn("Storage Quota Exceeded. Attempting to prune old media data...");

          // 策略 1: 移除較舊貼文中的大型圖片 (Base64)，只保留文字紀錄
          const pruned = updatedPosts.map((p, index) => {
              // 保留最近 3 篇貼文的圖片，其餘已發佈或失敗的貼文移除圖片
              if (index > 2 && p.status !== 'scheduled' && p.mediaUrl?.startsWith('data:')) {
                  return { ...p, mediaUrl: undefined, note: '(圖片已因空間限制自動移除)' };
              }
              return p;
          });

          try {
              localStorage.setItem(POSTS_KEY, JSON.stringify(pruned));
              setPosts(pruned);
          } catch (e2) {
              // 策略 2: 如果還是存不下，強制只保留最近 20 篇文字紀錄
              const extraPruned = updatedPosts.slice(0, 20).map(p => ({ ...p, mediaUrl: p.mediaUrl?.startsWith('data:') ? undefined : p.mediaUrl }));
              localStorage.setItem(POSTS_KEY, JSON.stringify(extraPruned));
              setPosts(extraPruned);
          }
      }
  };
  // #endregion

  // #region Auth & Initialization
  useEffect(() => {
    const unsubscribe = subscribeAuth(async (currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        const profile = await getUserProfile(currentUser.uid);
        setUserProfile(profile);
        setView(AppView.CREATE);
        loadLocalData();
      } else {
        setUserProfile(null);
        setView(AppView.LOGIN);
      }
      setLoadingAuth(false);
    });
    return () => unsubscribe();
  }, []);

  const loadLocalData = () => {
    const savedSettings = localStorage.getItem('autosocial_settings');
    const savedPosts = localStorage.getItem('autosocial_posts');
    if (savedSettings) {
        const parsed = JSON.parse(savedSettings);
        const merged = { ...defaultSettings, ...parsed };
        if(!merged.autoReply) merged.autoReply = defaultSettings.autoReply;
        if(!merged.autoPilot) merged.autoPilot = defaultSettings.autoPilot;
        if(!merged.threadsAccounts) merged.threadsAccounts = []; 
        if (!Array.isArray(merged.competitors)) merged.competitors = [];
        if (!Array.isArray(merged.referenceFiles)) merged.referenceFiles = [];
        setSettings(merged);
