      <main className="flex-1 p-4 md:p-8 overflow-y-auto h-screen relative">
        {view === AppView.CREATE && (
          <PostCreator 
            settings={settings} 
            user={userProfile}
            onPostCreated={handlePostCreated} 
            onQuotaUpdate={refreshProfile}
