      </main>

      {showRedeemModal && <RedeemModal onClose={() => setShowRedeemModal(false)} onRedeem={handleRedeemKey} />}
      {showPwdModal && <ChangePasswordModal onClose={() => setShowPwdModal(false)} />}

      <button 
        onClick={() => setShowReportModal(true)}
