const LoadingOverlay: React.FC<{ message: string, detail?: string }> = ({ message, detail }) => {
    const [tipIndex, setTipIndex] = useState(0);
    const tips = [
        "💡 貼心提醒：排程貼文將安全存儲於 Firebase 雲端，不佔用手機空間。",
        "💡 節省空間：發佈成功的貼文，系統會自動刪除暫存大圖，僅保留紀錄。",
        "💡 流量密碼：在貼文第一則留言放連結，通常觸及率會比直接放在內文高。",
        "💡 AI 正在思考最吸引人的標題...",
        "💡 系統正在處理雲端同步..."
    ];

    useEffect(() => {
        const interval = setInterval(() => {
            setTipIndex(prev => (prev + 1) % tips.length);
        }, 4000);
        return () => clearInterval(interval);
    }, []);

    return (
        <div className="fixed inset-0 bg-dark/90 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-sm animate-fade-in">
            <div className="w-20 h-20 mb-6 relative">
                <div className="absolute inset-0 border-4 border-gray-600 rounded-full"></div>
                <div className="absolute inset-0 border-4 border-primary rounded-full border-t-transparent animate-spin"></div>
            </div>
            <h2 className="text-2xl font-bold text-white mb-2">{message}</h2>
            <p className="text-gray-400 mb-8 animate-pulse">{detail || "正在處理您的請求，請稍候..."}</p>
            <div className="bg-card p-4 rounded-lg border border-gray-600 max-w-md w-full text-center shadow-2xl">
                <p className="text-yellow-400 text-sm font-bold mb-1">你知道嗎？</p>
                <p className="text-gray-300 text-sm">{tips[tipIndex]}</p>
            </div>
        </div>
    );
};

const DRAFT_KEY = 'autosocial_post_draft';

export const PostCreator: React.FC<Props> = ({ settings: initialSettings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [currentSettings, setCurrentSettings] = useState<BrandSettings>(initialSettings);
  const [step, setStep] = useState<1 | 2 | 3>(1);
  const [topic, setTopic] = useState('');
  const [postMode, setPostMode] = useState<'standard' | 'viral'>('standard');
  const [selectedTopicData, setSelectedTopicData] = useState<TrendingTopic | null>(null);

  const role = user?.role || 'user';
  const isStarterPlus = ['starter', 'pro', 'business', 'admin'].includes(role);

  const [captionLength, setCaptionLength] = useState<string>('150-300字');
  const [ctaList, setCtaList] = useState<CtaItem[]>([{ text: '👉 點擊了解', url: '' }]);
  const [imageText, setImageText] = useState('');

  const [viralType, setViralType] = useState<ViralType>('regret');
  const [viralPlatform, setViralPlatform] = useState<ViralPlatform>('facebook');
  const [targetAudience, setTargetAudience] = useState('');

  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '', videoPrompt: '' });
  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);

  const [selectedMediaType, setSelectedMediaType] = useState<'image' | 'video'>('image'); 
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);

  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);

  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  // 計算排程上限
  const getScheduleLimit = () => {
      if (role === 'pro') return 5;
      if (role === 'business') return 10;
      if (role === 'admin') return 100;
      return 3;
  };
  const limit = getScheduleLimit();
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  useEffect(() => {
    if (editPost) {
        setStep(2); setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt, videoPrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl); setScheduleDate(editPost.scheduledDate || ''); setSyncInstagram(!!editPost.syncInstagram);
    } else {
        const savedDraft = localStorage.getItem(DRAFT_KEY);
        if (savedDraft) {
            try {
                const parsed = JSON.parse(savedDraft);
                setStep(parsed.step || 1); setTopic(parsed.topic || ''); setPostMode(parsed.postMode || 'standard');
                setDraft(parsed.draft || { caption: '', firstComment: '', imagePrompt: '', videoPrompt: '' });
                setMediaUrl(parsed.mediaUrl);
            } catch (e) {}
        }
    }
  }, [editPost]);

  useEffect(() => {
      if (!topic && step === 1) return;
      if (editPost) return;
      const stateToSave = { step, topic, postMode, draft, selectedMediaType, scheduleDate, syncInstagram };
      localStorage.setItem(DRAFT_KEY, JSON.stringify(stateToSave));
  }, [step, topic, postMode, draft, selectedMediaType, scheduleDate, syncInstagram]);

  const handleNextToDraft = async (overrideTopic?: string) => {
    const effectiveTopic = overrideTopic || topic;
    if (!effectiveTopic || isGeneratingDraft || !user) return;

    const cost = postMode === 'viral' ? 5 : 2;
    const allowed = await checkAndUseQuota(user.user_id, cost);
    if (!allowed) return alert(`⚠️ 配額不足`);

    onQuotaUpdate(); setStep(2); setIsGeneratingDraft(true);
    try {
      if (postMode === 'viral') {
          const viralRes = await generateViralContent(effectiveTopic, { audience: targetAudience || 'General', viralType, platform: viralPlatform, versionCount: 1 }, currentSettings);
          setDraft({ caption: viralRes.versions[0], firstComment: '', imagePrompt: viralRes.imagePrompt, videoPrompt: viralRes.imagePrompt });
      } else {
          const generated = await generatePostDraft(effectiveTopic, currentSettings, { length: captionLength, ctaList: ctaList.filter(l => l.url), tempHashtags: '', includeEngagement: false, imageText }, undefined, user.role);
          setDraft({ caption: generated.caption, firstComment: generated.ctaText || '', imagePrompt: generated.imagePrompt, videoPrompt: generated.videoPrompt });
      }
    } catch (e: any) { alert(`生成失敗: ${e.message}`); setStep(1); }
    finally { setIsGeneratingDraft(false); }
  };

  const handleGenerateMedia = async () => {
    if (!user || isGeneratingMedia) return;
    const cost = selectedMediaType === 'video' ? 20 : 5; 
    const allowed = await checkAndUseQuota(user.user_id, cost);
    if (!allowed) return alert(`配額不足`);

    onQuotaUpdate(); setMediaUrl(undefined); setIsGeneratingMedia(true);
    try {
      let url = '';
      if (selectedMediaType === 'video') url = await generateVideo(draft.videoPrompt || draft.imagePrompt);
      else {
          url = await generateImage(draft.imagePrompt, user.role, currentSettings.brandStylePrompt);
          if (currentSettings.logoUrl) url = await applyWatermark(url, currentSettings.logoUrl);
      }
      setMediaUrl(url);
    } catch (e: any) { alert(`素材失敗: ${e.message}`); }
    finally { setIsGeneratingMedia(false); }
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;
    if (schedule && !scheduleDate) return alert("請先選擇排程時間");

    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(),
          userId: user.user_id, topic: topic,
          caption: draft.caption, firstComment: draft.firstComment,
          mediaPrompt: draft.imagePrompt, mediaType: selectedMediaType,
          mediaUrl, status: schedule ? 'scheduled' : 'published',
          scheduledDate: schedule ? scheduleDate : undefined, syncInstagram,
          createdAt: editPost ? editPost.createdAt : Date.now()
        };

        if (schedule) {
          await onPostCreated(newPost);
          setPublishResult({ success: true, msg: "貼文已排入雲端排程系統！" });
          localStorage.removeItem(DRAFT_KEY);
        } else {
          const result = await publishPostToFacebook(currentSettings.facebookPageId, currentSettings.facebookToken, draft.caption, mediaUrl, draft.firstComment, syncInstagram);
          if (result.success) {
            newPost.publishedUrl = result.url; newPost.status = 'published';
            await onPostCreated(newPost);
            setPublishResult({ success: true, msg: "發佈成功！雲端空間已自動清理暫存大圖。" });
            localStorage.removeItem(DRAFT_KEY);
          } else {
            newPost.status = 'failed'; newPost.errorLog = result.error;
            await onPostCreated(newPost);
            setPublishResult({ success: false, msg: `發佈失敗: ${result.error}` });
          }
        }
    } catch (err: any) {
        setPublishResult({ success: false, msg: `系統錯誤: ${err.message}` });
    } finally {
        setIsPublishing(false);
    }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在撰寫文案" />;
  if (isGeneratingMedia) return <LoadingOverlay message="AI 正在生成圖片/影片" />;
  if (isPublishing) return <LoadingOverlay message="正在處理雲端同步" />;

  if (step === 1) {
      return (
          <div className="max-w-4xl mx-auto space-y-6 animate-fade-in">
               <h2 className="text-2xl font-bold mb-4">1. 設定貼文主題</h2>
               <div className="bg-card p-6 rounded-xl border border-gray-700 space-y-6">
                  <input value={topic} onChange={e => setTopic(e.target.value)} className="w-full bg-dark border-gray-600 rounded p-3 text-white" placeholder="輸入主題 (例如：夏季保養心得)" />
                  <button onClick={() => handleNextToDraft()} disabled={!topic} className="w-full py-3 rounded font-bold text-white bg-primary">生成文案</button>
               </div>
          </div>
      )
  }

  return (
    <div className="max-w-6xl auto grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in">
        <div className="space-y-6">
            <div className="bg-card p-6 rounded-xl border border-gray-700">
                <textarea value={draft.caption} onChange={e => setDraft({...draft, caption: e.target.value})} className="w-full h-64 bg-dark border-gray-600 rounded p-3 text-white mb-4" />
                <div className="flex gap-2 mb-4">
                    <button onClick={() => setSelectedMediaType('image')} className={`flex-1 p-2 rounded ${selectedMediaType === 'image' ? 'bg-primary' : 'bg-gray-700'}`}>🖼️ 圖片</button>
                    <button onClick={() => setSelectedMediaType('video')} className={`flex-1 p-2 rounded ${selectedMediaType === 'video' ? 'bg-primary' : 'bg-gray-700'}`}>🎥 影片</button>
                </div>
                <button onClick={handleGenerateMedia} className="w-full py-3 rounded font-bold bg-secondary text-white">重新生成素材</button>
            </div>
        </div>
        <div className="bg-card p-6 rounded-xl border border-gray-700 flex flex-col">
            <h3 className="text-xl font-bold mb-4">預覽與發佈</h3>
            <div className="bg-white text-black rounded p-4 flex-1 mb-4 overflow-hidden">
                <div className="whitespace-pre-wrap text-sm mb-4">{draft.caption}</div>
                {mediaUrl && (selectedMediaType === 'video' ? <video src={mediaUrl} controls className="w-full" /> : <img src={mediaUrl} className="w-full h-auto" />)}
            </div>
            {publishResult ? (
                <div className={`p-4 rounded text-center font-bold ${publishResult.success ? 'bg-green-900/50 text-green-200' : 'bg-red-900/50 text-red-200'}`}>
                    {publishResult.msg}
                    <button onClick={() => setPublishResult(null)} className="block w-full mt-2 text-xs underline">繼續編輯</button>
                </div>
            ) : (
                <div className="space-y-4">
                    <div className="bg-dark p-3 rounded border border-gray-600">
                        <div className="flex justify-between items-center mb-1">
                            <label className="block text-xs text-gray-500">排程日期與時間</label>
                            <span className={`text-[10px] px-1.5 rounded-full font-bold ${isLimitReached ? 'bg-red-900 text-red-200' : 'bg-blue-900 text-blue-200'}`}>
                                排程空間: {scheduledPostsCount}/{limit}
                            </span>
                        </div>
                        <input type="datetime-local" value={scheduleDate} onChange={e => setScheduleDate(e.target.value)} className="w-full bg-transparent text-white outline-none" />
                    </div>
                    <div className="flex gap-4">
                        <button 
                            onClick={() => handleFinalize(true)} 
                            disabled={isLimitReached}
                            className={`flex-1 border py-3 rounded font-bold transition-colors ${isLimitReached ? 'border-gray-700 text-gray-600 cursor-not-allowed' : 'border-primary text-primary hover:bg-primary/10'}`}
                        >
                            {isLimitReached ? '排程空間已滿' : '存入雲端排程'}
                        </button>
                        <button onClick={() => handleFinalize(false)} className="flex-1 bg-primary text-white py-3 rounded font-bold hover:bg-blue-600">立即發佈</button>
                    </div>
                    {isLimitReached && <p className="text-[10px] text-red-400 text-center">⚠️ 您已達到方案排程上限，請刪除舊貼文或升級方案。</p>}
                </div>
            )}
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppView, BrandSettings, Post, UserProfile } from './types';

// #region Components Import
import SettingsForm from './components/SettingsForm';
import { PostCreator } from './components/PostCreator';
import ScheduleList from './components/ScheduleList';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import AutomationPanel from './components/AutomationPanel';
import ThreadsNurturePanel from './components/ThreadsNurturePanel';
import Login from './components/Login';
import AdminPanel from './components/AdminPanel';
import SeoArticleGenerator from './components/SeoArticleGenerator';
import ReferralPanel from './components/ReferralPanel'; 
import ErrorReportModal from './components/ErrorReportModal'; 
// #endregion

// #region Services & Auth Import
import { subscribeAuth, logout, getUserProfile, fetchUserPostsFromCloud, syncPostToCloud, deletePostFromCloud } from './services/authService';
// #endregion

const defaultSettings: BrandSettings = {
  industry: '',
  brandType: 'enterprise',
  services: '',
  website: '',
  productInfo: '',
  brandTone: 'Professional',
  persona: '',
  facebookPageId: '',
  facebookToken: '',
  threadsAccounts: [], 
  competitors: [],
  referenceFiles: [],
  fixedHashtags: '',
  autoReply: { enabled: false, defaultResponse: '', rules: [] },
  autoPilot: {
    enabled: false,
    frequency: 'daily',
    postTime: '09:00',
    source: 'trending',
    keywords: [],
    mediaTypePreference: 'image'
  }
};

const App: React.FC = () => {
  const [user, setUser] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [loadingAuth, setLoadingAuth] = useState(true);
  const [view, setView] = useState<AppView>(AppView.LOGIN);
  const [settings, setSettings] = useState<BrandSettings>(defaultSettings);
  const [posts, setPosts] = useState<Post[]>([]);
  const [editingPost, setEditingPost] = useState<Post | null>(null);
  const [showReportModal, setShowReportModal] = useState(false);

  useEffect(() => {
    const unsubscribe = subscribeAuth(async (currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        const profile = await getUserProfile(currentUser.uid);
        setUserProfile(profile);
        setView(AppView.CREATE);
        loadLocalSettings();
        const cloudPosts = await fetchUserPostsFromCloud(currentUser.uid);
        setPosts(cloudPosts);
      } else {
        setUserProfile(null);
        setView(AppView.LOGIN);
      }
      setLoadingAuth(false);
    });
    return () => unsubscribe();
  }, []);

  const loadLocalSettings = () => {
    const savedSettings = localStorage.getItem('autosocial_settings');
    if (savedSettings) {
        try {
            const parsed = JSON.parse(savedSettings);
            setSettings({ ...defaultSettings, ...parsed });
        } catch (e) {}
    }
  };

  const handleLogout = async () => {
    await logout();
    setView(AppView.LOGIN);
  };

  const refreshProfile = async () => {
    if (user) {
      const profile = await getUserProfile(user.uid);
      setUserProfile(profile);
    }
  };

  const handleSaveSettings = (newSettings: BrandSettings) => {
    setSettings(newSettings);
    localStorage.setItem('autosocial_settings', JSON.stringify(newSettings));
  };

  /**
   * 建立/更新貼文：同步至雲端並執行「方案排程上限」檢查
   */
  const handlePostCreated = async (newPost: Post) => {
    if (!user || !userProfile) return;

    // 排程上限檢查
    if (newPost.status === 'scheduled') {
        const scheduledCount = posts.filter(p => p.status === 'scheduled' && p.id !== newPost.id).length;
        const role = userProfile.role;

        let limit = 3; 
        if (role === 'pro') limit = 5;
        else if (role === 'business') limit = 10;
        else if (role === 'admin') limit = 100;

        if (scheduledCount >= limit) {
            alert(`⚠️ 排程空間不足！\n您的方案 (${role.toUpperCase()}) 最多僅能儲存 ${limit} 篇雲端排程貼文。\n\n請刪除舊貼文或升級方案。`);
            return;
        }
    }

    try {
        setPosts(prev => {
            const exists = prev.find(p => p.id === newPost.id);
            if (exists) return prev.map(p => p.id === newPost.id ? newPost : p);
            return [newPost, ...prev];
        });

        await syncPostToCloud(user.uid, newPost);
        const updatedPosts = await fetchUserPostsFromCloud(user.uid);
        setPosts(updatedPosts);
        setEditingPost(null);
        setView(AppView.SCHEDULE);
    } catch (e: any) {
        alert(`同步失敗: ${e.message}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
      if (!user) return;
      if (confirm("確定要從雲端永久刪除此紀錄嗎？")) {
          try {
              await deletePostFromCloud(user.uid, postId);
              setPosts(prev => prev.filter(p => p.id !== postId));
          } catch (e) {
              alert("刪除失敗");
          }
      }
  };

  const handleEditPost = (post: Post) => {
      setEditingPost(post);
      setView(AppView.CREATE);
  };

  // 權限檢查邏輯
  const role = userProfile?.role || 'user';
  const isAdmin = role === 'admin';
  const isStarterPlus = ['starter', 'pro', 'business', 'admin'].includes(role);
  const isProPlus = ['pro', 'business', 'admin'].includes(role);
  const isBusinessPlus = ['business', 'admin'].includes(role);

  const hasAnalyticsAccess = isStarterPlus || userProfile?.unlockedFeatures?.includes('ANALYTICS');
  const hasAutomationAccess = isBusinessPlus || userProfile?.unlockedFeatures?.includes('AUTOMATION');
  const hasSeoAccess = isProPlus || userProfile?.unlockedFeatures?.includes('SEO');
  const hasThreadsAccess = isProPlus || userProfile?.unlockedFeatures?.includes('THREADS');

  if (loadingAuth) return <div className="h-screen flex items-center justify-center bg-dark text-white">載入中...</div>;
  if (view === AppView.LOGIN) return <Login onLoginSuccess={() => {}} />;

  return (
    <div className="min-h-screen bg-dark text-gray-200 flex flex-col md:flex-row relative">
      {/* 側邊導航欄 - 已恢復所有遺失功能 */}
      <aside className="w-full md:w-64 bg-card border-r border-gray-700 flex flex-col">
        <div className="p-6 border-b border-gray-700">
          <h1 className="text-2xl font-bold text-blue-400 cursor-pointer" onClick={() => setView(AppView.CREATE)}>AutoSocial AI</h1>
          <div className="mt-2 text-[10px] text-gray-400">
            {userProfile ? (
                <>
                    <p className="truncate font-mono">{userProfile.email}</p>
                    <div className="flex justify-between mt-1 items-center">
                        <p className="font-bold text-primary uppercase">{userProfile.role}</p>
                        <p className="text-gray-500">Q: {userProfile.quota_used}/{userProfile.quota_total}</p>
                    </div>
                </>
            ) : 'Guest'}
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-1 overflow-y-auto custom-scrollbar">
          <button onClick={() => setView(AppView.CREATE)} className={`w-full text-left px-4 py-3 rounded transition-colors ${view === AppView.CREATE ? 'bg-primary text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>✨ 建立貼文</button>
          <button onClick={() => setView(AppView.SCHEDULE)} className={`w-full text-left px-4 py-3 rounded transition-colors ${view === AppView.SCHEDULE ? 'bg-primary text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>📅 排程與歷史</button>
          <button onClick={() => setView(AppView.SETTINGS)} className={`w-full text-left px-4 py-3 rounded transition-colors ${view === AppView.SETTINGS ? 'bg-primary text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>⚙️ 品牌設定</button>

          <div className="pt-4 mt-4 border-t border-gray-700 space-y-1">
              <p className="px-4 text-[10px] text-gray-600 font-bold mb-2 tracking-widest uppercase">進階模組</p>
              <button onClick={() => { if(hasAnalyticsAccess) setView(AppView.ANALYTICS); else alert("需要 Starter 以上方案"); }} className={`w-full text-left px-4 py-3 rounded transition-colors ${view === AppView.ANALYTICS ? 'bg-indigo-900 text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>📊 數據分析</button>
              <button onClick={() => { if(hasAutomationAccess) setView(AppView.AUTOMATION); else alert("需要 Business 以上方案"); }} className={`w-full text-left px-4 py-3 rounded transition-colors ${view === AppView.AUTOMATION ? 'bg-indigo-900 text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>🤖 自動化中心</button>
              <button onClick={() => { if(hasSeoAccess) setView(AppView.SEO_ARTICLES); else alert("需要 Pro 以上方案"); }} className={`w-full text-left px-4 py-3 rounded transition-colors ${view === AppView.SEO_ARTICLES ? 'bg-indigo-900 text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>📝 SEO 文章</button>
              <button onClick={() => { if(hasThreadsAccess) setView(AppView.THREADS_NURTURE); else alert("需要 Pro 以上方案"); }} className={`w-full text-left px-4 py-3 rounded transition-colors ${view === AppView.THREADS_NURTURE ? 'bg-indigo-900 text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>🧵 Threads 養號</button>
              <button onClick={() => setView(AppView.REFERRAL)} className={`w-full text-left px-4 py-3 rounded transition-colors text-green-400 font-bold ${view === AppView.REFERRAL ? 'bg-green-900/30' : 'hover:bg-gray-800'}`}>🎁 推薦獎勵</button>
          </div>
        </nav>

        <div className="p-4 border-t border-gray-700 space-y-2">
          {isAdmin && <button onClick={() => setView(AppView.ADMIN)} className={`w-full text-left px-4 py-2 text-sm rounded ${view === AppView.ADMIN ? 'bg-red-900 text-white' : 'text-red-400 hover:bg-red-900/20'}`}>👮 管理員後台</button>}
          <button onClick={handleLogout} className="w-full text-left px-4 py-2 text-sm text-gray-500 hover:text-red-400 transition-colors">🚪 登出系統</button>
        </div>
      </aside>

      {/* 主內容區 - 確保所有視圖都被渲染 */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto h-screen custom-scrollbar">
        {view === AppView.CREATE && (
          <PostCreator 
            settings={settings} 
            user={userProfile} 
            onPostCreated={handlePostCreated} 
            onQuotaUpdate={refreshProfile} 
            editPost={editingPost} 
            onCancel={() => setEditingPost(null)}
            scheduledPostsCount={posts.filter(p => p.status === 'scheduled').length}
          />
        )}
        {view === AppView.SCHEDULE && (
          <ScheduleList posts={posts} onUpdatePosts={async (updated) => {
              const originalIds = posts.map(p => p.id);
              const updatedIds = updated.map(p => p.id);
              const deletedId = originalIds.find(id => !updatedIds.includes(id));
              if (deletedId) await handleDeletePost(deletedId);
              else {
                  const changed = updated.find((p, i) => JSON.stringify(p) !== JSON.stringify(posts.find(op => op.id === p.id)));
                  if (changed && user) await syncPostToCloud(user.uid, changed);
                  setPosts(updated);
              }
          }} onEditPost={handleEditPost} />
        )}
        {view === AppView.SETTINGS && <SettingsForm onSave={handleSaveSettings} initialSettings={settings} />}
        {view === AppView.ANALYTICS && <AnalyticsDashboard settings={settings} />}
        {view === AppView.AUTOMATION && <AutomationPanel settings={settings} onSave={handleSaveSettings} />}
        {view === AppView.SEO_ARTICLES && <SeoArticleGenerator user={userProfile} onQuotaUpdate={refreshProfile} />}
        {view === AppView.THREADS_NURTURE && <ThreadsNurturePanel settings={settings} user={userProfile} onSaveSettings={handleSaveSettings} onQuotaUpdate={refreshProfile} />}
        {view === AppView.REFERRAL && <ReferralPanel user={userProfile} onQuotaUpdate={refreshProfile} />}
        {view === AppView.ADMIN && isAdmin && <AdminPanel currentUser={userProfile!} />}
      </main>

      <button onClick={() => setShowReportModal(true)} className="fixed bottom-4 right-4 bg-red-900/80 text-white p-2 rounded-full z-40 shadow-xl hover:scale-110 transition-transform">🐞</button>
      {showReportModal && <ErrorReportModal user={userProfile} currentView={view} onClose={() => setShowReportModal(false)} />}
    </div>
  );
};

