            <div className="bg-card p-6 rounded-2xl border border-gray-700 max-w-lg w-full shadow-2xl">
                <p className="text-yellow-400 font-bold mb-2 uppercase tracking-widest text-sm">小撇步</p>
                <p className="text-gray-300 italic">{tips[tipIndex]}</p>
            </div>
        </div>
    );
};

const DRAFT_KEY = 'autosocial_post_draft';

export const PostCreator: React.FC<Props> = ({ settings: initialSettings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [postMode, setPostMode] = useState<'standard' | 'viral'>('standard');
  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '', videoPrompt: '' });
  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [selectedMediaType, setSelectedMediaType] = useState<'image' | 'video'>('image'); 
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);
  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  const role = user?.role || 'user';
  const getLimit = () => {
      if (role === 'pro') return 5;
      if (role === 'business') return 10;
      if (role === 'admin') return 100;
      return 3;
  };
  const limit = getLimit();
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  useEffect(() => {
    if (editPost) {
        setStep(2); setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt, videoPrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl); setScheduleDate(editPost.scheduledDate || ''); setSyncInstagram(!!editPost.syncInstagram);
    } else {
        const saved = localStorage.getItem(DRAFT_KEY);
        if (saved) {
            try {
                const p = JSON.parse(saved);
                if(p.topic) { setStep(2); setTopic(p.topic); setDraft(p.draft); setMediaUrl(p.mediaUrl); }
            } catch(e) {}
        }
    }
  }, [editPost]);

  useEffect(() => {
      if (step === 2 && !editPost) {
          localStorage.setItem(DRAFT_KEY, JSON.stringify({ topic, draft, mediaUrl }));
      }
  }, [topic, draft, mediaUrl]);

  const handleNext = async () => {
    if (!topic || !user) return;
    const allowed = await checkAndUseQuota(user.user_id, postMode === 'viral' ? 5 : 2);
    if (!allowed) return alert("配額不足");
    onQuotaUpdate(); setStep(2); setIsGeneratingDraft(true);
    try {
      if (postMode === 'viral') {
          const res = await generateViralContent(topic, { audience: 'General', viralType: 'regret', platform: 'facebook', versionCount: 1 }, initialSettings);
          setDraft({ caption: res.versions[0], firstComment: '', imagePrompt: res.imagePrompt, videoPrompt: res.imagePrompt });
      } else {
          const res = await generatePostDraft(topic, initialSettings, { length: '150-300字', ctaList: [], tempHashtags: '', includeEngagement: false, imageText: '' }, undefined, user.role);
          setDraft({ caption: res.caption, firstComment: res.ctaText || '', imagePrompt: res.imagePrompt, videoPrompt: res.videoPrompt });
      }
    } catch (e: any) { alert(`失敗: ${e.message}`); setStep(1); }
    finally { setIsGeneratingDraft(false); }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;
    const allowed = await checkAndUseQuota(user.user_id, selectedMediaType === 'video' ? 20 : 5);
    if (!allowed) return alert("配額不足");
    onQuotaUpdate(); setMediaUrl(undefined); setIsGeneratingMedia(true);
    try {
      let url = selectedMediaType === 'video' ? await generateVideo(draft.videoPrompt) : await generateImage(draft.imagePrompt, user.role, initialSettings.brandStylePrompt);
      if (initialSettings.logoUrl && selectedMediaType === 'image') url = await applyWatermark(url, initialSettings.logoUrl);
      setMediaUrl(url);
    } catch (e: any) { alert(`素材失敗: ${e.message}`); }
    finally { setIsGeneratingMedia(false); }
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;
    if (schedule && !scheduleDate) return alert("請選擇日期時間");
    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(), userId: user.user_id, topic, caption: draft.caption, 
          firstComment: draft.firstComment, mediaPrompt: draft.imagePrompt, mediaType: selectedMediaType,
          mediaUrl, status: schedule ? 'scheduled' : 'published', scheduledDate: schedule ? scheduleDate : undefined, 
          syncInstagram, createdAt: editPost ? editPost.createdAt : Date.now()
        };
        if (schedule) {
          await onPostCreated(newPost);
          setPublishResult({ success: true, msg: "雲端排程成功！" });
          localStorage.removeItem(DRAFT_KEY);
        } else {
          const res = await publishPostToFacebook(initialSettings.facebookPageId, initialSettings.facebookToken, draft.caption, mediaUrl, draft.firstComment, syncInstagram);
          if (res.success) {
            newPost.publishedUrl = res.url; newPost.status = 'published';
            await onPostCreated(newPost);
            setPublishResult({ success: true, msg: "發佈成功！空間已自動釋放。" });
            localStorage.removeItem(DRAFT_KEY);
          } else {
            newPost.status = 'failed'; newPost.errorLog = res.error;
            await onPostCreated(newPost);
            setPublishResult({ success: false, msg: `發佈失敗: ${res.error}` });
          }
        }
    } catch (err: any) { setPublishResult({ success: false, msg: `錯誤: ${err.message}` }); }
    finally { setIsPublishing(false); }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在撰寫文案" detail="我們正在為您生成最具轉換率的社群文案..." />;
  if (isGeneratingMedia) return <LoadingOverlay message="AI 正在製圖中" detail="正在根據文案內容創作高品質視覺素材..." />;
  if (isPublishing) return <LoadingOverlay message="雲端同步中" detail="正在將您的創意內容同步至雲端伺服器..." />;

  if (step === 1) return (
      <div className="max-w-3xl mx-auto space-y-8 animate-fade-in pt-10">
          <div className="text-center space-y-4">
              <h2 className="text-4xl font-bold text-white tracking-tight">你要聊什麼主題？</h2>
              <p className="text-gray-400">輸入一個簡單的想法，AI 將為您完成剩下的所有工作。</p>
          </div>
          <div className="bg-card p-8 rounded-3xl border border-gray-700 shadow-2xl space-y-6">
              <input value={topic} onChange={e => setTopic(e.target.value)} className="w-full bg-dark border-gray-600 rounded-2xl p-5 text-xl text-white outline-none focus:border-primary transition-all shadow-inner" placeholder="例如：夏季抗老保養品推薦、或是貼上一則新聞連結" />
              <div className="flex gap-4">
                  <button onClick={() => setPostMode('standard')} className={`flex-1 p-4 rounded-xl border-2 transition-all font-bold ${postMode === 'standard' ? 'border-primary bg-primary/10 text-white' : 'border-gray-700 text-gray-500 hover:border-gray-600'}`}>🏢 標準品牌模式</button>
                  <button onClick={() => setPostMode('viral')} className={`flex-1 p-4 rounded-xl border-2 transition-all font-bold ${postMode === 'viral' ? 'border-pink-600 bg-pink-900/10 text-white' : 'border-gray-700 text-gray-500 hover:border-gray-600'}`}>🔥 爆款營銷模式</button>
              </div>
              <button onClick={handleNext} disabled={!topic} className="w-full py-4 rounded-2xl font-bold text-white bg-gradient-to-r from-blue-600 to-indigo-600 shadow-lg hover:from-blue-500 hover:to-indigo-500 transform transition-all active:scale-95 disabled:opacity-50">啟動 AI 創作中心</button>
          </div>
      </div>
  );

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in pb-20">
        <div className="space-y-6">
            <div className="bg-card p-6 rounded-3xl border border-gray-700 shadow-xl">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="font-bold text-gray-300 flex items-center gap-2"><span className="text-xl">✍️</span> 編輯文案</h3>
                    <button onClick={() => { if(confirm("捨棄目前草稿？")) setStep(1); }} className="text-xs text-red-400 hover:underline">重新開始</button>
                </div>
                <textarea value={draft.caption} onChange={e => setDraft({...draft, caption: e.target.value})} className="w-full h-72 bg-dark border-gray-600 rounded-2xl p-4 text-white mb-6 resize-none focus:border-primary outline-none custom-scrollbar" />
                <div className="grid grid-cols-2 gap-4 mb-6">
                    <button onClick={() => setSelectedMediaType('image')} className={`p-4 rounded-xl border-2 font-bold transition-all ${selectedMediaType === 'image' ? 'border-primary bg-primary/10 text-white' : 'border-gray-700 text-gray-500'}`}>🖼️ AI 圖片</button>
                    <button onClick={() => setSelectedMediaType('video')} className={`p-4 rounded-xl border-2 font-bold transition-all ${selectedMediaType === 'video' ? 'border-primary bg-primary/10 text-white' : 'border-gray-700 text-gray-500'}`}>🎥 AI 影片</button>
                </div>
                <button onClick={handleGenMedia} className="w-full py-4 rounded-2xl font-bold bg-secondary text-white shadow-lg hover:opacity-90 transition-all">重新生成視覺素材</button>
            </div>
        </div>
        <div className="flex flex-col space-y-6">
            <div className="bg-card p-6 rounded-3xl border border-gray-700 shadow-xl flex-1 flex flex-col">
                <h3 className="font-bold text-gray-300 mb-4 flex items-center gap-2"><span className="text-xl">📱</span> 手機預覽</h3>
                <div className="bg-white rounded-2xl overflow-hidden flex-1 flex flex-col shadow-inner">
                    <div className="p-4 border-b flex items-center gap-2">
                        <div className="w-8 h-8 rounded-full bg-gray-200"></div>
                        <div><div className="h-2 w-20 bg-gray-200 rounded"></div><div className="h-2 w-10 bg-gray-100 rounded mt-1"></div></div>
                    </div>
                    <div className="p-4 flex-1 overflow-y-auto custom-scrollbar">
                        <p className="text-black text-sm whitespace-pre-wrap leading-relaxed mb-4">{draft.caption}</p>
                        {mediaUrl && (selectedMediaType === 'video' ? <video src={mediaUrl} controls className="w-full rounded-lg" /> : <img src={mediaUrl} className="w-full h-auto rounded-lg" />)}
                    </div>
                </div>
                {publishResult ? (
                    <div className={`mt-6 p-4 rounded-2xl text-center font-bold animate-fade-in ${publishResult.success ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-red-900/50 text-red-200 border border-red-700'}`}>
                        {publishResult.msg}
                        <button onClick={() => setPublishResult(null)} className="block w-full mt-2 text-xs underline opacity-70">繼續編輯內容</button>
                    </div>
                ) : (
                    <div className="mt-6 space-y-4">
                        <div className="bg-dark p-4 rounded-2xl border border-gray-600 flex justify-between items-center group">
                            <div className="flex-1">
                                <label className="block text-[10px] text-gray-500 font-bold uppercase tracking-widest mb-1 group-focus-within:text-primary">排程日期與時間</label>
                                <input type="datetime-local" value={scheduleDate} onChange={e => setScheduleDate(e.target.value)} className="w-full bg-transparent text-white outline-none font-bold" />
                            </div>
                            <div className={`px-3 py-1 rounded-full text-[10px] font-bold ${isLimitReached ? 'bg-red-900 text-red-200' : 'bg-blue-900 text-blue-200'}`}>
                                雲端空間: {scheduledPostsCount}/{limit}
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => handleFinalize(true)} disabled={isLimitReached} className={`flex-1 py-4 rounded-2xl font-bold transition-all border-2 ${isLimitReached ? 'border-gray-700 text-gray-600 cursor-not-allowed' : 'border-primary text-primary hover:bg-primary/10'}`}>{isLimitReached ? '排程已滿' : '存入雲端排程'}</button>
                            <button onClick={() => handleFinalize(false)} className="flex-1 bg-primary text-white py-4 rounded-2xl font-bold shadow-xl hover:bg-blue-600 transition-all transform active:scale-95">立即發佈</button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppView, BrandSettings, Post, UserProfile } from './types';

// #region Components Import
import SettingsForm from './components/SettingsForm';
import { PostCreator } from './components/PostCreator';
import ScheduleList from './components/ScheduleList';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import AutomationPanel from './components/AutomationPanel';
import ThreadsNurturePanel from './components/ThreadsNurturePanel';
import Login from './components/Login';
import AdminPanel from './components/AdminPanel';
import SeoArticleGenerator from './components/SeoArticleGenerator';
import ReferralPanel from './components/ReferralPanel'; 
import ErrorReportModal from './components/ErrorReportModal'; 
// #endregion

// #region Services & Auth Import
import { subscribeAuth, logout, getUserProfile, fetchUserPostsFromCloud, syncPostToCloud, deletePostFromCloud } from './services/authService';
// #endregion

const defaultSettings: BrandSettings = {
  industry: '',
  brandType: 'enterprise',
  services: '',
  website: '',
  productInfo: '',
  brandTone: 'Professional',
  persona: '',
  facebookPageId: '',
  facebookToken: '',
  threadsAccounts: [], 
  competitors: [],
  referenceFiles: [],
  fixedHashtags: '',
  autoReply: { enabled: false, defaultResponse: '', rules: [] },
  autoPilot: {
    enabled: false,
    frequency: 'daily',
    postTime: '09:00',
    source: 'trending',
    keywords: [],
    mediaTypePreference: 'image'
  }
};

const App: React.FC = () => {
  const [user, setUser] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [loadingAuth, setLoadingAuth] = useState(true);
  const [view, setView] = useState<AppView>(AppView.LOGIN);
  const [settings, setSettings] = useState<BrandSettings>(defaultSettings);
  const [posts, setPosts] = useState<Post[]>([]);
  const [editingPost, setEditingPost] = useState<Post | null>(null);
  const [showReportModal, setShowReportModal] = useState(false);

  useEffect(() => {
    const unsubscribe = subscribeAuth(async (currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        const profile = await getUserProfile(currentUser.uid);
        setUserProfile(profile);
        setView(AppView.CREATE);
        loadLocalSettings();
        const cloudPosts = await fetchUserPostsFromCloud(currentUser.uid);
        setPosts(cloudPosts);
      } else {
        setUserProfile(null);
        setView(AppView.LOGIN);
      }
      setLoadingAuth(false);
    });
    return () => unsubscribe();
  }, []);

  const loadLocalSettings = () => {
    const savedSettings = localStorage.getItem('autosocial_settings');
    if (savedSettings) {
        try {
            const parsed = JSON.parse(savedSettings);
            setSettings({ ...defaultSettings, ...parsed });
        } catch (e) {}
    }
  };

  const handleLogout = async () => {
    await logout();
    setView(AppView.LOGIN);
  };

  const refreshProfile = async () => {
    if (user) {
      const profile = await getUserProfile(user.uid);
      setUserProfile(profile);
    }
  };

  const handleSaveSettings = (newSettings: BrandSettings) => {
    setSettings(newSettings);
    localStorage.setItem('autosocial_settings', JSON.stringify(newSettings));
  };

  const handlePostCreated = async (newPost: Post) => {
    if (!user || !userProfile) return;

    // 排程上限檢查
    if (newPost.status === 'scheduled') {
        const scheduledCount = posts.filter(p => p.status === 'scheduled' && p.id !== newPost.id).length;
        const role = userProfile.role;
        let limit = 3; 
        if (role === 'pro') limit = 5;
        else if (role === 'business') limit = 10;
        else if (role === 'admin') limit = 100;

        if (scheduledCount >= limit) {
            alert(`⚠️ 排程空間不足！\n您的方案 (${role.toUpperCase()}) 最多僅能儲存 ${limit} 篇雲端排程貼文。`);
            return;
        }
    }

    try {
        setPosts(prev => {
            const exists = prev.find(p => p.id === newPost.id);
            if (exists) return prev.map(p => p.id === newPost.id ? newPost : p);
            return [newPost, ...prev];
        });

        await syncPostToCloud(user.uid, newPost);
        const updatedPosts = await fetchUserPostsFromCloud(user.uid);
        setPosts(updatedPosts);
        setEditingPost(null);
        setView(AppView.SCHEDULE);
    } catch (e: any) {
        alert(`同步失敗: ${e.message}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
      if (!user) return;
      if (confirm("確定要從雲端永久刪除此紀錄嗎？")) {
          try {
              await deletePostFromCloud(user.uid, postId);
              setPosts(prev => prev.filter(p => p.id !== postId));
          } catch (e) {
              alert("刪除失敗");
          }
      }
  };

  const handleEditPost = (post: Post) => {
      setEditingPost(post);
      setView(AppView.CREATE);
  };

  const role = userProfile?.role || 'user';
  const isAdmin = role === 'admin';
  const isStarterPlus = ['starter', 'pro', 'business', 'admin'].includes(role);
  const isProPlus = ['pro', 'business', 'admin'].includes(role);
  const isBusinessPlus = ['business', 'admin'].includes(role);

  const hasAnalyticsAccess = isStarterPlus || userProfile?.unlockedFeatures?.includes('ANALYTICS');
  const hasAutomationAccess = isBusinessPlus || userProfile?.unlockedFeatures?.includes('AUTOMATION');
  const hasSeoAccess = isProPlus || userProfile?.unlockedFeatures?.includes('SEO');
  const hasThreadsAccess = isProPlus || userProfile?.unlockedFeatures?.includes('THREADS');

  if (loadingAuth) return <div className="h-screen flex items-center justify-center bg-dark text-white text-2xl font-bold animate-pulse">AutoSocial AI 載入中...</div>;
  if (view === AppView.LOGIN) return <Login onLoginSuccess={() => {}} />;

  return (
    <div className="min-h-screen bg-dark text-gray-200 flex flex-col md:flex-row relative">
      <aside className="w-full md:w-64 bg-card border-r border-gray-700 flex flex-col shadow-2xl z-30">
        <div className="p-6 border-b border-gray-700">
          <h1 className="text-2xl font-bold text-blue-400 cursor-pointer" onClick={() => setView(AppView.CREATE)}>AutoSocial AI</h1>
          <div className="mt-2 text-[10px] text-gray-400">
            {userProfile ? (
                <>
                    <p className="truncate font-mono">{userProfile.email}</p>
                    <div className="flex justify-between mt-1 items-center">
                        <p className="font-bold text-primary uppercase">{userProfile.role}</p>
                        <p className="text-gray-500">Q: {userProfile.quota_used}/{userProfile.quota_total}</p>
                    </div>
                </>
            ) : 'Guest'}
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-1 overflow-y-auto custom-scrollbar">
          <button onClick={() => setView(AppView.CREATE)} className={`w-full text-left px-4 py-3 rounded transition-all ${view === AppView.CREATE ? 'bg-primary text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>✨ 建立貼文</button>
          <button onClick={() => setView(AppView.SCHEDULE)} className={`w-full text-left px-4 py-3 rounded transition-all ${view === AppView.SCHEDULE ? 'bg-primary text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>📅 排程與歷史</button>
          <button onClick={() => setView(AppView.SETTINGS)} className={`w-full text-left px-4 py-3 rounded transition-all ${view === AppView.SETTINGS ? 'bg-primary text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>⚙️ 品牌設定</button>

          <div className="pt-4 mt-4 border-t border-gray-700 space-y-1">
              <p className="px-4 text-[10px] text-gray-600 font-bold mb-2 tracking-widest uppercase">進階模組</p>
              <button onClick={() => { if(hasAnalyticsAccess) setView(AppView.ANALYTICS); else alert("權限不足"); }} className={`w-full text-left px-4 py-3 rounded ${view === AppView.ANALYTICS ? 'bg-indigo-900 text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>📊 數據分析</button>
              <button onClick={() => { if(hasAutomationAccess) setView(AppView.AUTOMATION); else alert("權限不足"); }} className={`w-full text-left px-4 py-3 rounded ${view === AppView.AUTOMATION ? 'bg-indigo-900 text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>🤖 自動化中心</button>
              <button onClick={() => { if(hasSeoAccess) setView(AppView.SEO_ARTICLES); else alert("權限不足"); }} className={`w-full text-left px-4 py-3 rounded ${view === AppView.SEO_ARTICLES ? 'bg-indigo-900 text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>📝 SEO 文章</button>
              <button onClick={() => { if(hasThreadsAccess) setView(AppView.THREADS_NURTURE); else alert("權限不足"); }} className={`w-full text-left px-4 py-3 rounded ${view === AppView.THREADS_NURTURE ? 'bg-indigo-900 text-white font-bold' : 'text-gray-400 hover:bg-gray-800'}`}>🧵 Threads 養號</button>
              <button onClick={() => setView(AppView.REFERRAL)} className={`w-full text-left px-4 py-3 rounded text-green-400 font-bold ${view === AppView.REFERRAL ? 'bg-green-900/30' : 'hover:bg-gray-800'}`}>🎁 推薦獎勵</button>
          </div>
        </nav>

        <div className="p-4 border-t border-gray-700 space-y-2">
          {isAdmin && <button onClick={() => setView(AppView.ADMIN)} className="w-full text-left px-4 py-2 text-sm text-red-400 hover:bg-red-900/20 rounded">👮 管理員後台</button>}
          <button onClick={handleLogout} className="w-full text-left px-4 py-2 text-sm text-gray-500 hover:text-red-400 transition-colors">🚪 登出系統</button>
        </div>
      </aside>

      <main className="flex-1 p-4 md:p-8 overflow-y-auto h-screen custom-scrollbar">
        {view === AppView.CREATE && (
          <PostCreator 
            settings={settings} 
            user={userProfile} 
            onPostCreated={handlePostCreated} 
            onQuotaUpdate={refreshProfile} 
            editPost={editingPost} 
            onCancel={() => setEditingPost(null)}
            scheduledPostsCount={posts.filter(p => p.status === 'scheduled').length}
          />
        )}
        {view === AppView.SCHEDULE && (
          <ScheduleList posts={posts} onUpdatePosts={async (updated) => {
              const originalIds = posts.map(p => p.id);
              const updatedIds = updated.map(p => p.id);
              const deletedId = originalIds.find(id => !updatedIds.includes(id));
              if (deletedId) await handleDeletePost(deletedId);
              else {
                  const changed = updated.find((p, i) => JSON.stringify(p) !== JSON.stringify(posts.find(op => op.id === p.id)));
                  if (changed && user) await syncPostToCloud(user.uid, changed);
                  setPosts(updated);
              }
          }} onEditPost={handleEditPost} />
        )}
        {view === AppView.SETTINGS && <SettingsForm onSave={handleSaveSettings} initialSettings={settings} />}
        {view === AppView.ANALYTICS && <AnalyticsDashboard settings={settings} />}
        {view === AppView.AUTOMATION && <AutomationPanel settings={settings} onSave={handleSaveSettings} />}
        {view === AppView.SEO_ARTICLES && <SeoArticleGenerator user={userProfile} onQuotaUpdate={refreshProfile} />}
        {view === AppView.THREADS_NURTURE && <ThreadsNurturePanel settings={settings} user={userProfile} onSaveSettings={handleSaveSettings} onQuotaUpdate={refreshProfile} />}
        {view === AppView.REFERRAL && <ReferralPanel user={userProfile} onQuotaUpdate={refreshProfile} />}
        {view === AppView.ADMIN && isAdmin && <AdminPanel currentUser={userProfile!} />}
      </main>

      <button onClick={() => setShowReportModal(true)} className="fixed bottom-4 right-4 bg-red-900/80 text-white p-2 rounded-full z-40 shadow-xl hover:scale-110 transition-transform">🐞</button>
      {showReportModal && <ErrorReportModal user={userProfile} currentView={view} onClose={() => setShowReportModal(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile, ViralType } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, generateVideo, applyWatermark, generateViralContent } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (post: Post) => void;
  onQuotaUpdate: () => void;
  editPost?: Post | null;
  onCancel?: () => void;
  scheduledPostsCount?: number;
}

const LoadingOverlay: React.FC<{ message: string, detail?: string }> = ({ message, detail }) => (
    <div className="fixed inset-0 bg-dark/95 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-md animate-fade-in text-center">
        <div className="w-24 h-24 mb-8 relative">
            <div className="absolute inset-0 border-8 border-gray-800 rounded-full"></div>
            <div className="absolute inset-0 border-8 border-primary rounded-full border-t-transparent animate-spin"></div>
        </div>
        <h2 className="text-3xl font-bold text-white mb-4">{message}</h2>
        <p className="text-gray-400 mb-12 animate-pulse text-lg">{detail || "AI 正在執行複雜運算..."}</p>
    </div>
);

const DRAFT_KEY = 'autosocial_post_draft';

export const PostCreator: React.FC<Props> = ({ settings: initialSettings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [postMode, setPostMode] = useState<'standard' | 'viral'>('standard');
  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);

  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '', videoPrompt: '' });
  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [selectedMediaType, setSelectedMediaType] = useState<'image' | 'video'>('image'); 
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);
  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  const role = user?.role || 'user';
  const getLimit = () => {
      if (role === 'pro') return 5;
      if (role === 'business') return 10;
      if (role === 'admin') return 100;
      return 3;
  };
  const limit = getLimit();
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  useEffect(() => {
    if (editPost) {
        setStep(2); setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt, videoPrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl); setScheduleDate(editPost.scheduledDate || ''); setSyncInstagram(!!editPost.syncInstagram);
    } else {
        const saved = localStorage.getItem(DRAFT_KEY);
        if (saved) {
            try {
                const p = JSON.parse(saved);
                if(p.topic) { setStep(2); setTopic(p.topic); setDraft(p.draft); setMediaUrl(p.mediaUrl); }
            } catch(e) {}
        }
    }
  }, [editPost]);

  const loadTrends = async () => {
      if (!user) return;
      setIsLoadingTrends(true);
      try {
          const industry = initialSettings.industry || '熱門話題';
          const trends = await getTrendingTopics(industry);
          setTrendingTopics(trends);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async (selectedTopic?: string) => {
    const finalTopic = selectedTopic || topic;
    if (!finalTopic || !user) return;
    const allowed = await checkAndUseQuota(user.user_id, postMode === 'viral' ? 5 : 2);
    if (!allowed) return alert("配額不足");
    onQuotaUpdate(); setStep(2); setIsGeneratingDraft(true); setTopic(finalTopic);
    try {
      if (postMode === 'viral') {
          const res = await generateViralContent(finalTopic, { audience: 'General', viralType: 'regret', platform: 'facebook', versionCount: 1 }, initialSettings);
          setDraft({ caption: res.versions[0], firstComment: '', imagePrompt: res.imagePrompt, videoPrompt: res.imagePrompt });
      } else {
          const res = await generatePostDraft(finalTopic, initialSettings, { length: '150-300字', ctaList: [], tempHashtags: '', includeEngagement: false, imageText: '' }, undefined, user.role);
          setDraft({ caption: res.caption, firstComment: res.ctaText || '', imagePrompt: res.imagePrompt, videoPrompt: res.videoPrompt });
      }
    } catch (e: any) { alert(`失敗: ${e.message}`); setStep(1); }
    finally { setIsGeneratingDraft(false); }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;
    const allowed = await checkAndUseQuota(user.user_id, selectedMediaType === 'video' ? 20 : 5);
    if (!allowed) return alert("配額不足");
    onQuotaUpdate(); setMediaUrl(undefined); setIsGeneratingMedia(true);
    try {
      let url = selectedMediaType === 'video' ? await generateVideo(draft.videoPrompt) : await generateImage(draft.imagePrompt, user.role, initialSettings.brandStylePrompt);
      if (initialSettings.logoUrl && selectedMediaType === 'image') url = await applyWatermark(url, initialSettings.logoUrl);
      setMediaUrl(url);
    } catch (e: any) { alert(`素材失敗: ${e.message}`); }
    finally { setIsGeneratingMedia(false); }
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;
    if (schedule && !scheduleDate) return alert("請選擇日期時間");
    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(), userId: user.user_id, topic, caption: draft.caption, 
          firstComment: draft.firstComment, mediaPrompt: draft.imagePrompt, mediaType: selectedMediaType,
          mediaUrl, status: schedule ? 'scheduled' : 'published', scheduledDate: schedule ? scheduleDate : undefined, 
          syncInstagram, createdAt: editPost ? editPost.createdAt : Date.now()
        };
        if (schedule) {
          await onPostCreated(newPost);
          setPublishResult({ success: true, msg: "排程成功！貼文已同步至雲端系統。" });
          localStorage.removeItem(DRAFT_KEY);
        } else {
          const res = await publishPostToFacebook(initialSettings.facebookPageId, initialSettings.facebookToken, draft.caption, mediaUrl, draft.firstComment, syncInstagram);
          if (res.success) {
            newPost.publishedUrl = res.url; newPost.status = 'published';
            await onPostCreated(newPost);
            setPublishResult({ success: true, msg: "發佈成功！" });
            localStorage.removeItem(DRAFT_KEY);
          } else {
            newPost.status = 'failed'; newPost.errorLog = res.error;
            await onPostCreated(newPost);
            setPublishResult({ success: false, msg: `發佈失敗: ${res.error}` });
          }
        }
    } catch (err: any) { setPublishResult({ success: false, msg: `錯誤: ${err.message}` }); }
    finally { setIsPublishing(false); }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在構思文案" detail="分析話題中..." />;
  if (isGeneratingMedia) return <LoadingOverlay message="AI 正在製作視覺素材" detail="繪圖中..." />;
  if (isPublishing) return <LoadingOverlay message="正在同步雲端發佈系統" detail="同步中..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-8 animate-fade-in pt-10">
          <div className="text-center space-y-2">
              <h2 className="text-4xl font-bold text-white tracking-tight">你要聊什麼主題？</h2>
              <p className="text-gray-400 text-lg">輸入想法或讓 AI 為您挖掘靈感</p>
          </div>
          <div className="bg-card p-8 rounded-3xl border border-gray-700 shadow-2xl space-y-6">
              <div className="flex gap-2">
                  <input value={topic} onChange={e => setTopic(e.target.value)} className="flex-1 bg-dark border-gray-600 rounded-2xl p-4 text-xl text-white outline-none focus:border-primary shadow-inner" placeholder="例如：夏季抗老保養品推薦..." />
                  <button onClick={loadTrends} className="bg-gray-700 hover:bg-gray-600 px-6 rounded-2xl text-white font-bold transition-all">🔍 挖掘靈感</button>
              </div>

              {isLoadingTrends ? (
                  <div className="flex justify-center py-4"><div className="loader"></div></div>
              ) : trendingTopics.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3 max-h-60 overflow-y-auto custom-scrollbar p-2">
                      {trendingTopics.map((t, i) => (
                          <div key={i} onClick={() => handleNext(t.title)} className="bg-dark/50 border border-gray-700 p-3 rounded-xl cursor-pointer hover:border-primary hover:bg-primary/10 transition-all">
                              <h4 className="font-bold text-blue-400 text-sm mb-1">{t.title}</h4>
                              <p className="text-xs text-gray-500 line-clamp-1">{t.description}</p>
                          </div>
                      ))}
                  </div>
              )}

              <div className="flex gap-4">
                  <button onClick={() => setPostMode('standard')} className={`flex-1 p-4 rounded-xl border-2 transition-all font-bold ${postMode === 'standard' ? 'border-primary bg-primary/10 text-white' : 'border-gray-700 text-gray-500 hover:border-gray-600'}`}>🏢 標準品牌模式</button>
                  <button onClick={() => setPostMode('viral')} className={`flex-1 p-4 rounded-xl border-2 transition-all font-bold ${postMode === 'viral' ? 'border-pink-600 bg-pink-900/10 text-white' : 'border-gray-700 text-gray-500 hover:border-gray-600'}`}>🔥 爆款營銷模式</button>
              </div>
              <button onClick={() => handleNext()} disabled={!topic} className="w-full py-4 rounded-2xl font-bold text-white bg-gradient-to-r from-blue-600 to-indigo-600 shadow-lg hover:opacity-90 transition-all transform active:scale-95 disabled:opacity-50">啟動 AI 創作中心</button>
          </div>
      </div>
  );

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in pb-20">
        <div className="space-y-6">
            <div className="bg-card p-6 rounded-3xl border border-gray-700 shadow-xl">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="font-bold text-gray-300 flex items-center gap-2">✍️ 編輯文案</h3>
                    <button onClick={() => { if(confirm("捨棄草稿？")) setStep(1); }} className="text-xs text-red-400 hover:underline">重新開始</button>
                </div>
                <textarea value={draft.caption} onChange={e => setDraft({...draft, caption: e.target.value})} className="w-full h-72 bg-dark border-gray-600 rounded-2xl p-4 text-white mb-6 resize-none focus:border-primary outline-none custom-scrollbar" />
                <div className="grid grid-cols-2 gap-4 mb-6">
                    <button onClick={() => setSelectedMediaType('image')} className={`p-4 rounded-xl border-2 font-bold transition-all ${selectedMediaType === 'image' ? 'border-primary bg-primary/10 text-white' : 'border-gray-700 text-gray-500'}`}>🖼️ AI 圖片</button>
                    <button onClick={() => setSelectedMediaType('video')} className={`p-4 rounded-xl border-2 font-bold transition-all ${selectedMediaType === 'video' ? 'border-primary bg-primary/10 text-white' : 'border-gray-700 text-gray-500'}`}>🎥 AI 影片</button>
                </div>
                <button onClick={handleGenMedia} className="w-full py-4 rounded-2xl font-bold bg-secondary text-white shadow-lg">重新生成視覺素材</button>
            </div>
        </div>
        <div className="flex flex-col space-y-6">
            <div className="bg-card p-6 rounded-3xl border border-gray-700 shadow-xl flex-1 flex flex-col">
                <h3 className="font-bold text-gray-300 mb-4 flex items-center gap-2">📱 預覽</h3>
                <div className="bg-white rounded-2xl overflow-hidden flex-1 flex flex-col shadow-inner">
                    <div className="p-4 border-b flex items-center gap-2">
                        <div className="w-8 h-8 rounded-full bg-gray-200"></div>
                        <div className="h-2 w-20 bg-gray-200 rounded"></div>
                    </div>
                    <div className="p-4 flex-1 overflow-y-auto custom-scrollbar">
                        <p className="text-black text-sm whitespace-pre-wrap leading-relaxed mb-4">{draft.caption}</p>
                        {mediaUrl && (selectedMediaType === 'video' ? <video src={mediaUrl} controls className="w-full rounded-lg" /> : <img src={mediaUrl} className="w-full h-auto rounded-lg" />)}
                    </div>
                </div>
                {publishResult ? (
                    <div className={`mt-6 p-4 rounded-2xl text-center font-bold ${publishResult.success ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-red-900/50 text-red-200 border border-red-700'}`}>
                        {publishResult.msg}
                        <button onClick={() => setPublishResult(null)} className="block w-full mt-2 text-xs underline opacity-70">繼續編輯</button>
                    </div>
                ) : (
                    <div className="mt-6 space-y-4">
                        <div className="bg-dark p-4 rounded-2xl border border-gray-600 flex justify-between items-center">
                            <div className="flex-1">
                                <label className="block text-[10px] text-gray-500 font-bold uppercase tracking-widest mb-1">排程日期與時間</label>
                                <input type="datetime-local" value={scheduleDate} onChange={e => setScheduleDate(e.target.value)} className="w-full bg-transparent text-white outline-none font-bold" />
                            </div>
                            <div className={`px-3 py-1 rounded-full text-[10px] font-bold ${isLimitReached ? 'bg-red-900 text-red-200' : 'bg-blue-900 text-blue-200'}`}>
                                雲端空間: {scheduledPostsCount}/{limit}
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => handleFinalize(true)} disabled={isLimitReached} className={`flex-1 py-4 rounded-2xl font-bold transition-all border-2 ${isLimitReached ? 'border-gray-700 text-gray-600 cursor-not-allowed' : 'border-primary text-primary hover:bg-primary/10'}`}>{isLimitReached ? '排程已滿' : '存入雲端排程'}</button>
                            <button onClick={() => handleFinalize(false)} className="flex-1 bg-primary text-white py-4 rounded-2xl font-bold shadow-xl hover:bg-blue-600 transition-all transform active:scale-95">立即發佈</button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, applyWatermark } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (post: Post) => void;
  onQuotaUpdate: () => void;
  editPost?: Post | null;
  onCancel?: () => void;
  scheduledPostsCount?: number;
}

const LoadingOverlay: React.FC<{ message: string }> = ({ message }) => (
    <div className="fixed inset-0 bg-dark/90 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-md animate-fade-in">
        <div className="loader mb-4 scale-150"></div>
        <h2 className="text-xl font-bold text-white">{message}</h2>
        <p className="text-gray-400 mt-2">AI 正在處理中...</p>
    </div>
);

const DRAFT_KEY = 'autosocial_post_draft';

export const PostCreator: React.FC<Props> = ({ settings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);

  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '' });
  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);

  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 100 : 3));
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  useEffect(() => {
    if (editPost) {
        setStep(2);
        setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl);
        setScheduleDate(editPost.scheduledDate || '');
        setSyncInstagram(!!editPost.syncInstagram);
    }
  }, [editPost]);

  // 1. 挖掘靈感 - 扣 1 點
  const loadTrends = async () => {
      if (!user) return;
      const allowed = await checkAndUseQuota(user.user_id, 1);
      if (!allowed) return alert("配額不足 (需要 1 點)");

      onQuotaUpdate();
      setIsLoadingTrends(true);
      try {
          const industry = settings.industry || '熱門話題';
          const trends = await getTrendingTopics(industry);
          setTrendingTopics(trends);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  // 2. 生成文案 - 扣 2 點
  const handleNext = async (selectedTopic?: string) => {
    const finalTopic = selectedTopic || topic;
    if (!finalTopic || !user) return;

    const allowed = await checkAndUseQuota(user.user_id, 2);
    if (!allowed) return alert("配額不足 (需要 2 點)");

    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setTopic(finalTopic);

    try {
        const res = await generatePostDraft(finalTopic, settings, { 
            length: '150-300字', 
            ctaList: [], 
            tempHashtags: '', 
            includeEngagement: false 
        }, undefined, user.role);
        setDraft({ 
            caption: res.caption, 
            firstComment: res.ctaText || '', 
            imagePrompt: res.imagePrompt 
        });
    } catch (e: any) { 
        alert(`失敗: ${e.message}`); 
        setStep(1); 
    } finally { 
        setIsGeneratingDraft(false); 
    }
  };

  // 3. 生成圖片 - 扣 5 點
  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;
    const allowed = await checkAndUseQuota(user.user_id, 5);
    if (!allowed) return alert("配額不足 (需要 5 點)");

    onQuotaUpdate();
    setMediaUrl(undefined);
    setIsGeneratingMedia(true);
    try {
      let url = await generateImage(draft.imagePrompt, user.role, settings.brandStylePrompt);
      if (settings.logoUrl) url = await applyWatermark(url, settings.logoUrl);
      setMediaUrl(url);
    } catch (e: any) { 
        alert(`製圖失敗: ${e.message}`); 
    } finally { 
        setIsGeneratingMedia(false); 
    }
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;
    if (schedule && !scheduleDate) return alert("請選擇日期時間");
    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(),
          userId: user.user_id,
          topic,
          caption: draft.caption, 
          firstComment: draft.firstComment,
          mediaPrompt: draft.imagePrompt,
          mediaType: 'image',
          mediaUrl,
          status: schedule ? 'scheduled' : 'published',
          scheduledDate: schedule ? scheduleDate : undefined, 
          syncInstagram,
          createdAt: editPost ? editPost.createdAt : Date.now()
        };

        if (schedule) {
          await onPostCreated(newPost);
          setPublishResult({ success: true, msg: "✅ 已存入雲端排程系統" });
        } else {
          const res = await publishPostToFacebook(settings.facebookPageId, settings.facebookToken, draft.caption, mediaUrl, draft.firstComment, syncInstagram);
          if (res.success) {
            newPost.publishedUrl = res.url;
            newPost.status = 'published';
            await onPostCreated(newPost);
            setPublishResult({ success: true, msg: "🚀 貼文已成功發佈！" });
          } else {
            newPost.status = 'failed';
            newPost.errorLog = res.error;
            await onPostCreated(newPost);
            setPublishResult({ success: false, msg: `❌ 發佈失敗: ${res.error}` });
          }
        }
    } catch (err: any) { 
        setPublishResult({ success: false, msg: `錯誤: ${err.message}` }); 
    } finally { 
        setIsPublishing(false); 
    }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在構思高轉換文案..." />;
  if (isGeneratingMedia) return <LoadingOverlay message="AI 正在為您繪製專屬圖片..." />;
  if (isPublishing) return <LoadingOverlay message="正在同步雲端發佈系統..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-8 animate-fade-in pt-6">
          <div className="text-center space-y-2">
              <h2 className="text-3xl font-bold text-white">你想聊什麼話題？</h2>
              <p className="text-gray-400">輸入核心主題，或讓 AI 幫你挖掘目前最夯的話題。</p>
          </div>

          <div className="bg-card p-6 rounded-2xl border border-gray-700 shadow-xl space-y-6">
              <div className="flex gap-2">
                  <input 
                    value={topic} 
                    onChange={e => setTopic(e.target.value)} 
                    className="flex-1 bg-dark border border-gray-600 rounded-xl p-4 text-white outline-none focus:border-primary" 
                    placeholder="例如：夏季保養心法、今日新聞重點..." 
                  />
                  <button 
                    onClick={loadTrends} 
                    className="bg-gray-700 hover:bg-gray-600 px-6 rounded-xl text-white font-bold transition-all flex items-center gap-2"
                  >
                    🔍 挖掘靈感 <span className="text-[10px] bg-blue-600 px-1 rounded">1點</span>
                  </button>
              </div>

              {isLoadingTrends ? (
                  <div className="flex justify-center py-6"><div className="loader"></div></div>
              ) : trendingTopics.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3 max-h-64 overflow-y-auto p-2 border border-gray-800 rounded-xl bg-dark/30">
                      {trendingTopics.map((t, i) => (
                          <div 
                            key={i} 
                            onClick={() => handleNext(t.title)} 
                            className="bg-dark/50 border border-gray-700 p-3 rounded-lg cursor-pointer hover:border-primary hover:bg-primary/10 transition-all"
                          >
                              <h4 className="font-bold text-blue-400 text-sm mb-1 line-clamp-1">{t.title}</h4>
                              <p className="text-xs text-gray-500 line-clamp-1">{t.description}</p>
                          </div>
                      ))}
                  </div>
              )}

              <button 
                onClick={() => handleNext()} 
                disabled={!topic} 
                className="w-full py-4 rounded-xl font-bold text-white bg-primary shadow-lg hover:opacity-90 transition-all disabled:opacity-50"
              >
                生成品牌文案 <span className="text-xs font-normal">(2點)</span>
              </button>
          </div>
      </div>
  );

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in">
        <div className="space-y-6">
            <div className="bg-card p-6 rounded-2xl border border-gray-700 shadow-xl">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="font-bold text-gray-300">✍️ 文案編輯</h3>
                    <button onClick={() => setStep(1)} className="text-xs text-red-400 hover:underline">返回重選主題</button>
                </div>
                <textarea 
                    value={draft.caption} 
                    onChange={e => setDraft({...draft, caption: e.target.value})} 
                    className="w-full h-80 bg-dark border border-gray-600 rounded-xl p-4 text-white mb-6 resize-none focus:border-primary outline-none" 
                />
                <button 
                    onClick={handleGenMedia} 
                    className="w-full py-4 rounded-xl font-bold bg-indigo-600 text-white shadow-lg hover:bg-indigo-500 transition-all"
                >
                    🖼️ 重新生成圖片素材 <span className="text-xs font-normal">(5點)</span>
                </button>
            </div>
        </div>

        <div className="space-y-6">
            <div className="bg-card p-6 rounded-2xl border border-gray-700 shadow-xl flex flex-col min-h-[500px]">
                <h3 className="font-bold text-gray-300 mb-4">📱 預覽</h3>
                <div className="bg-white rounded-xl overflow-hidden flex-1 border border-gray-200 shadow-inner">
                    <div className="p-4 border-b flex items-center gap-2">
                        <div className="w-8 h-8 rounded-full bg-gray-200"></div>
