    try {
        const snap = await db.collection('users').doc(userId).collection('posts').orderBy('createdAt', 'desc').get();
        return snap.docs.map(doc => doc.data() as Post);
    } catch (e) {
        console.error("Fetch Cloud Posts Failed", e);
        return [];
    }
};

