import SeoArticleGenerator from './components/SeoArticleGenerator';
import ReferralPanel from './components/ReferralPanel'; 
import ErrorReportModal from './components/ErrorReportModal'; 
// #endregion

// #region Services & Auth Import
import { subscribeAuth, logout, getUserProfile, fetchUserPostsFromCloud, syncPostToCloud, deletePostFromCloud } from './services/authService';
// #endregion

const defaultSettings: BrandSettings = {
  industry: '',
  brandType: 'enterprise',
  services: '',
  website: '',
  productInfo: '',
  brandTone: 'Professional',
  persona: '',
  facebookPageId: '',
  facebookToken: '',
  threadsAccounts: [], 
  competitors: [],
  referenceFiles: [],
  fixedHashtags: '',
  autoReply: { enabled: false, defaultResponse: '', rules: [] },
  autoPilot: {
    enabled: false,
    frequency: 'daily',
    postTime: '09:00',
    source: 'trending',
    keywords: [],
    mediaTypePreference: 'image'
  }
};

const App: React.FC = () => {
  const [user, setUser] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [loadingAuth, setLoadingAuth] = useState(true);
  const [view, setView] = useState<AppView>(AppView.LOGIN);
  const [settings, setSettings] = useState<BrandSettings>(defaultSettings);
  const [posts, setPosts] = useState<Post[]>([]);
  const [editingPost, setEditingPost] = useState<Post | null>(null);
  const [showReportModal, setShowReportModal] = useState(false);

  useEffect(() => {
    const unsubscribe = subscribeAuth(async (currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        const profile = await getUserProfile(currentUser.uid);
        setUserProfile(profile);
        setView(AppView.CREATE);
        loadLocalSettings();
        const cloudPosts = await fetchUserPostsFromCloud(currentUser.uid);
        setPosts(cloudPosts);
      } else {
        setUserProfile(null);
        setView(AppView.LOGIN);
      }
      setLoadingAuth(false);
    });
    return () => unsubscribe();
  }, []);

  const loadLocalSettings = () => {
    const savedSettings = localStorage.getItem('autosocial_settings');
    if (savedSettings) {
        try {
            const parsed = JSON.parse(savedSettings);
            setSettings({ ...defaultSettings, ...parsed });
        } catch (e) {}
    }
  };

  const handleLogout = async () => {
    await logout();
    setView(AppView.LOGIN);
  };

  const refreshProfile = async () => {
    if (user) {
      const profile = await getUserProfile(user.uid);
      setUserProfile(profile);
    }
  };

  const handleSaveSettings = (newSettings: BrandSettings) => {
    setSettings(newSettings);
    localStorage.setItem('autosocial_settings', JSON.stringify(newSettings));
  };

  const handlePostCreated = async (newPost: Post) => {
    if (!user || !userProfile) return;

    if (newPost.status === 'scheduled') {
        const scheduledCount = posts.filter(p => p.status === 'scheduled' && p.id !== newPost.id).length;
        const role = userProfile.role;
        let limit = 3; 
        if (role === 'pro') limit = 5;
        else if (role === 'business') limit = 10;
        else if (role === 'admin') limit = 100;

        if (scheduledCount >= limit) {
            alert(`⚠️ 排程空間不足！您的方案最多儲存 ${limit} 篇排程貼文。`);
            return;
        }
    }

    try {
        setPosts(prev => {
            const exists = prev.find(p => p.id === newPost.id);
            if (exists) return prev.map(p => p.id === newPost.id ? newPost : p);
            return [newPost, ...prev];
        });

        await syncPostToCloud(user.uid, newPost);
        const updatedPosts = await fetchUserPostsFromCloud(user.uid);
        setPosts(updatedPosts);
        setEditingPost(null);
        setView(AppView.SCHEDULE);
    } catch (e: any) {
        alert(`同步失敗: ${e.message}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
      if (!user) return;
      if (confirm("確定要從雲端永久刪除此紀錄嗎？")) {
          try {
              await deletePostFromCloud(user.uid, postId);
              setPosts(prev => prev.filter(p => p.id !== postId));
          } catch (e) {
              alert("刪除失敗");
          }
      }
  };

  const handleEditPost = (post: Post) => {
      setEditingPost(post);
      setView(AppView.CREATE);
  };

  const role = userProfile?.role || 'user';
  const isAdmin = role === 'admin';
  const isStarterPlus = ['starter', 'pro', 'business', 'admin'].includes(role);
  const isProPlus = ['pro', 'business', 'admin'].includes(role);
  const isBusinessPlus = ['business', 'admin'].includes(role);

  const hasAnalyticsAccess = isStarterPlus || userProfile?.unlockedFeatures?.includes('ANALYTICS');
  const hasAutomationAccess = isBusinessPlus || userProfile?.unlockedFeatures?.includes('AUTOMATION');
  const hasSeoAccess = isProPlus || userProfile?.unlockedFeatures?.includes('SEO');
  const hasThreadsAccess = isProPlus || userProfile?.unlockedFeatures?.includes('THREADS');

  if (loadingAuth) return <div className="h-screen flex items-center justify-center bg-dark text-white text-xl animate-pulse">AutoSocial AI 啟動中...</div>;
  if (view === AppView.LOGIN) return <Login onLoginSuccess={() => {}} />;

  const NavItem = ({ viewId, label, active, onClick, disabled = false, badge = "" }: any) => (
    <button 
      onClick={() => !disabled && onClick(viewId)} 
      className={`relative w-full text-left px-6 py-3 transition-all flex items-center justify-between group ${active ? 'bg-primary/10 text-primary font-bold' : 'text-gray-400 hover:bg-gray-800/50 hover:text-gray-200'} ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
    >
      {active && <div className="absolute left-0 top-0 bottom-0 w-1 bg-primary"></div>}
      <span className="text-[15px] tracking-wide">{label}</span>
      {badge && <span className="text-[9px] bg-gray-700 px-1.5 py-0.5 rounded uppercase tracking-tighter text-gray-400">{badge}</span>}
    </button>
  );

  return (
    <div className="min-h-screen bg-dark text-gray-200 flex flex-col md:flex-row relative font-sans">
      <aside className="w-full md:w-64 bg-card border-r border-gray-800 flex flex-col shadow-2xl z-30">
        <div className="p-8 border-b border-gray-800">
          <h1 className="text-xl font-black text-white tracking-tighter cursor-pointer flex items-center gap-2" onClick={() => setView(AppView.CREATE)}>
            AUTOSOCIAL <span className="text-primary">AI</span>
          </h1>
          <div className="mt-4 p-3 bg-dark/50 rounded-lg border border-gray-800">
            {userProfile ? (
                <>
                    <p className="truncate text-[10px] text-gray-500 mb-1 font-mono">{userProfile.email}</p>
                    <div className="flex justify-between items-center">
                        <p className="text-[11px] font-bold text-blue-400 uppercase tracking-widest">{userProfile.role}</p>
                        <p className="text-[10px] text-gray-500 font-bold">{userProfile.quota_used}/{userProfile.quota_total}</p>
                    </div>
                </>
            ) : <p className="text-xs text-gray-500">訪客模式</p>}
          </div>
        </div>

        <nav className="flex-1 py-4 space-y-0.5 overflow-y-auto custom-scrollbar">
          <NavItem viewId={AppView.CREATE} label="建立貼文" active={view === AppView.CREATE} onClick={setView} />
          <NavItem viewId={AppView.SCHEDULE} label="排程與歷史" active={view === AppView.SCHEDULE} onClick={setView} />
          <NavItem viewId={AppView.SETTINGS} label="品牌設定" active={view === AppView.SETTINGS} onClick={setView} />

          <div className="pt-8 mb-2 px-6">
              <p className="text-[10px] text-gray-600 font-black tracking-[0.2em] uppercase">進階管理模組</p>
          </div>

          <NavItem viewId={AppView.ANALYTICS} label="數據分析中心" active={view === AppView.ANALYTICS} onClick={() => hasAnalyticsAccess ? setView(AppView.ANALYTICS) : alert("需升級至 Starter 方案")} disabled={!hasAnalyticsAccess} badge={!hasAnalyticsAccess ? "LOCK" : ""} />
          <NavItem viewId={AppView.AUTOMATION} label="全自動化中心" active={view === AppView.AUTOMATION} onClick={() => hasAutomationAccess ? setView(AppView.AUTOMATION) : alert("需升級至 Business 方案")} disabled={!hasAutomationAccess} badge={!hasAutomationAccess ? "LOCK" : ""} />
          <NavItem viewId={AppView.SEO_ARTICLES} label="SEO 文章生成" active={view === AppView.SEO_ARTICLES} onClick={() => hasSeoAccess ? setView(AppView.SEO_ARTICLES) : alert("需升級至 Pro 方案")} disabled={!hasSeoAccess} badge={!hasSeoAccess ? "LOCK" : ""} />
          <NavItem viewId={AppView.THREADS_NURTURE} label="Threads 養號系統" active={view === AppView.THREADS_NURTURE} onClick={() => hasThreadsAccess ? setView(AppView.THREADS_NURTURE) : alert("需升級至 Pro 方案")} disabled={!hasThreadsAccess} badge={!hasThreadsAccess ? "LOCK" : ""} />
          <NavItem viewId={AppView.REFERRAL} label="好友推薦計畫" active={view === AppView.REFERRAL} onClick={setView} />
        </nav>

        <div className="p-4 border-t border-gray-800 bg-dark/20 space-y-2">
          {isAdmin && (
            <button onClick={() => setView(AppView.ADMIN)} className={`w-full text-left px-4 py-2 text-xs rounded transition-colors font-bold ${view === AppView.ADMIN ? 'bg-red-900 text-white' : 'text-red-400 hover:bg-red-900/10'}`}>
              管理員後台
            </button>
          )}
          <button onClick={handleLogout} className="w-full text-left px-4 py-2 text-xs text-gray-500 hover:text-red-400 transition-colors">
            登出系統
          </button>
        </div>
      </aside>

      <main className="flex-1 p-4 md:p-10 overflow-y-auto h-screen custom-scrollbar bg-dark/95">
        {view === AppView.CREATE && (
          <PostCreator 
            settings={settings} 
            user={userProfile} 
            onPostCreated={handlePostCreated} 
            onQuotaUpdate={refreshProfile} 
            editPost={editingPost} 
            onCancel={() => setEditingPost(null)}
            scheduledPostsCount={posts.filter(p => p.status === 'scheduled').length}
          />
        )}
        {view === AppView.SCHEDULE && (
          <ScheduleList posts={posts} onUpdatePosts={async (updated) => {
              const originalIds = posts.map(p => p.id);
              const updatedIds = updated.map(p => p.id);
              const deletedId = originalIds.find(id => !updatedIds.includes(id));
              if (deletedId) await handleDeletePost(deletedId);
              else {
                  const changed = updated.find((p, i) => JSON.stringify(p) !== JSON.stringify(posts.find(op => op.id === p.id)));
                  if (changed && user) await syncPostToCloud(user.uid, changed);
                  setPosts(updated);
              }
          }} onEditPost={handleEditPost} />
        )}
        {view === AppView.SETTINGS && <SettingsForm onSave={handleSaveSettings} initialSettings={settings} />}
        {view === AppView.ANALYTICS && <AnalyticsDashboard settings={settings} />}
        {view === AppView.AUTOMATION && <AutomationPanel settings={settings} onSave={handleSaveSettings} />}
        {view === AppView.SEO_ARTICLES && <SeoArticleGenerator user={userProfile} onQuotaUpdate={refreshProfile} />}
        {view === AppView.THREADS_NURTURE && <ThreadsNurturePanel settings={settings} user={userProfile} onSaveSettings={handleSaveSettings} onQuotaUpdate={refreshProfile} />}
        {view === AppView.REFERRAL && <ReferralPanel user={userProfile} onQuotaUpdate={refreshProfile} />}
        {view === AppView.ADMIN && isAdmin && <AdminPanel currentUser={userProfile!} />}
      </main>

      <button onClick={() => setShowReportModal(true)} className="fixed bottom-6 right-6 bg-red-600 hover:bg-red-500 text-white w-10 h-10 rounded-full z-40 shadow-2xl transition-transform active:scale-90 flex items-center justify-center font-bold text-lg">!</button>
      {showReportModal && <ErrorReportModal user={userProfile} currentView={view} onClose={() => setShowReportModal(false)} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile, ViralType, ViralPlatform } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, applyWatermark, generateViralContent } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (post: Post) => void;
  onQuotaUpdate: () => void;
  editPost?: Post | null;
  onCancel?: () => void;
  scheduledPostsCount?: number;
}

const LoadingOverlay: React.FC<{ message: string }> = ({ message }) => (
    <div className="fixed inset-0 bg-dark/95 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-md animate-fade-in text-center border border-gray-800">
        <div className="loader mb-4 scale-150 border-t-primary"></div>
        <h2 className="text-2xl font-bold text-white mb-2">{message}</h2>
        <p className="text-gray-400">AI 正在努力處理中，請稍候...</p>
    </div>
);

export const PostCreator: React.FC<Props> = ({ settings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [mode, setMode] = useState<'brand' | 'viral'>('brand');
  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);

  const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '' });
  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);

  const [scheduleDate, setScheduleDate] = useState('');
  const [syncInstagram, setSyncInstagram] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

  // 排程上限判定
  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 100 : 3));
  const isLimitReached = !editPost && scheduledPostsCount >= limit;

  useEffect(() => {
    if (editPost) {
        setStep(2);
        setTopic(editPost.topic);
        setDraft({ caption: editPost.caption, firstComment: editPost.firstComment || '', imagePrompt: editPost.mediaPrompt });
        setMediaUrl(editPost.mediaUrl);
        setScheduleDate(editPost.scheduledDate || '');
        setSyncInstagram(!!editPost.syncInstagram);
    }
  }, [editPost]);

  const loadTrends = async () => {
      if (!user) return alert("請先登入");
      const allowed = await checkAndUseQuota(user.user_id, 1);
      if (!allowed) return alert("配額不足 (需要 1 點)");
      onQuotaUpdate();
      setIsLoadingTrends(true);
      try {
          const industry = settings.industry || '台灣熱門話題';
          const trends = await getTrendingTopics(industry);
          setTrendingTopics(trends);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async (selectedTopic?: string) => {
    const finalTopic = selectedTopic || topic;
    if (!finalTopic || !user) return;

    const allowed = await checkAndUseQuota(user.user_id, 2);
    if (!allowed) return alert("配額不足 (需要 2 點)");

    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setTopic(finalTopic);

    try {
        if (mode === 'brand') {
            const res = await generatePostDraft(finalTopic, settings, { 
                length: '150-300字', 
                ctaList: [], 
                tempHashtags: '', 
                includeEngagement: false 
            }, undefined, user.role);
            setDraft({ 
                caption: res.caption, 
                firstComment: res.ctaText || '', 
                imagePrompt: res.imagePrompt 
            });
        } else {
            const res = await generateViralContent(finalTopic, {
                audience: '社群大眾',
                viralType: 'regret',
                platform: 'facebook',
                versionCount: 1
            }, settings);
            setDraft({
                caption: res.versions[0],
                firstComment: '',
                imagePrompt: res.imagePrompt
            });
        }
    } catch (e: any) { 
        alert(`失敗: ${e.message}`); 
        setStep(1); 
    } finally { 
        setIsGeneratingDraft(false); 
    }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;
    const cost = mediaUrl ? 2 : 5;
    const allowed = await checkAndUseQuota(user.user_id, cost);
    if (!allowed) return alert(`配額不足 (需要 ${cost} 點)`);

    onQuotaUpdate();
    setMediaUrl(undefined);
    setIsGeneratingMedia(true);
    try {
      let url = await generateImage(draft.imagePrompt, user.role, settings.brandStylePrompt);
      if (settings.logoUrl) url = await applyWatermark(url, settings.logoUrl);
      setMediaUrl(url);
    } catch (e: any) { 
        alert(`製圖失敗: ${e.message}`); 
    } finally { 
        setIsGeneratingMedia(false); 
    }
  };

  const handleFinalize = async (schedule: boolean) => {
    if (!user || isPublishing) return;
    if (schedule && !scheduleDate) return alert("請選擇預計發佈時間");
    setIsPublishing(true);
    try {
        const newPost: Post = {
          id: editPost ? editPost.id : Date.now().toString(),
          userId: user.user_id,
          topic,
          caption: draft.caption, 
          firstComment: draft.firstComment,
          mediaPrompt: draft.imagePrompt,
          mediaType: 'image',
          mediaUrl,
          status: schedule ? 'scheduled' : 'published',
          scheduledDate: schedule ? scheduleDate : undefined, 
          syncInstagram,
          createdAt: editPost ? editPost.createdAt : Date.now()
        };

        if (schedule) {
          await onPostCreated(newPost);
          setPublishResult({ success: true, msg: "已存入雲端排程系統" });
        } else {
          const res = await publishPostToFacebook(settings.facebookPageId, settings.facebookToken, draft.caption, mediaUrl, draft.firstComment, syncInstagram);
          if (res.success) {
            newPost.publishedUrl = res.url;
            newPost.status = 'published';
            await onPostCreated(newPost);
            setPublishResult({ success: true, msg: "貼文已成功發佈！" });
          } else {
            newPost.status = 'failed';
            newPost.errorLog = res.error;
            await onPostCreated(newPost);
            setPublishResult({ success: false, msg: `發佈失敗: ${res.error}` });
          }
        }
    } catch (err: any) { 
        setPublishResult({ success: false, msg: `錯誤: ${err.message}` }); 
    } finally { 
        setIsPublishing(false); 
    }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在構思文案..." />;
  if (isGeneratingMedia) return <LoadingOverlay message="AI 正在繪製視覺素材..." />;
  if (isPublishing) return <LoadingOverlay message="正在執行同步發佈..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-12 animate-fade-in pt-4">
          <div className="text-center space-y-3">
              <h2 className="text-4xl font-black text-white tracking-tight">你想聊什麼話題？</h2>
              <p className="text-gray-500 font-medium">輸入核心主題，讓 AI 為您打造吸睛內容。</p>
          </div>

          <div className="bg-card p-10 rounded-3xl border border-gray-800 shadow-2xl space-y-8">
              <div className="flex p-1.5 bg-dark/80 rounded-2xl border border-gray-800">
                  <button 
                    onClick={() => setMode('brand')}
                    className={`flex-1 py-4 rounded-xl font-bold tracking-wide transition-all ${mode === 'brand' ? 'bg-primary text-white shadow-xl' : 'text-gray-500 hover:text-gray-300'}`}
                  >
                    品牌模式
                  </button>
                  <button 
                    onClick={() => setMode('viral')}
                    className={`flex-1 py-4 rounded-xl font-bold tracking-wide transition-all ${mode === 'viral' ? 'bg-orange-600 text-white shadow-xl' : 'text-gray-500 hover:text-gray-300'}`}
                  >
                    爆文模式
                  </button>
              </div>

              <div className="flex gap-3">
                  <input 
                    value={topic} 
                    onChange={e => setTopic(e.target.value)} 
                    className="flex-1 bg-dark/50 border border-gray-700 rounded-2xl p-5 text-white outline-none focus:border-primary transition-all text-xl font-medium placeholder-gray-600" 
                    placeholder="輸入主題 (例如：夏季保養、今日新聞...)" 
                  />
                  <button 
                    onClick={loadTrends} 
                    className="bg-gray-800 hover:bg-gray-700 px-8 rounded-2xl text-white font-bold transition-all flex flex-col items-center justify-center gap-1 border border-gray-700"
                  >
                    <span className="text-sm">挖掘靈感</span>
                    <span className="text-[9px] bg-blue-500/20 text-blue-400 px-2 rounded-full border border-blue-500/30 font-black">1 點</span>
                  </button>
              </div>

              {isLoadingTrends ? (
                  <div className="flex justify-center py-6"><div className="loader border-t-primary"></div></div>
              ) : trendingTopics.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-72 overflow-y-auto p-4 border border-gray-800 rounded-2xl bg-dark/20 custom-scrollbar">
                      {trendingTopics.map((t, i) => (
                          <div 
                            key={i} 
                            onClick={() => handleNext(t.title)} 
                            className="bg-dark/40 border border-gray-800 p-4 rounded-xl cursor-pointer hover:border-primary hover:bg-primary/5 transition-all group"
                          >
                              <h4 className="font-bold text-blue-400 text-sm mb-1 line-clamp-1 group-hover:text-white transition-colors">{t.title}</h4>
                              <p className="text-[11px] text-gray-500 line-clamp-1">{t.description}</p>
                          </div>
                      ))}
                  </div>
              )}

              <button 
                onClick={() => handleNext()} 
                disabled={!topic} 
                className={`w-full py-6 rounded-2xl font-black text-white shadow-2xl hover:opacity-90 transition-all disabled:opacity-30 text-xl tracking-widest uppercase ${mode === 'viral' ? 'bg-orange-600' : 'bg-primary'}`}
              >
                生成內容 <span className="text-sm font-normal opacity-50 ml-2">需消耗 2 點</span>
              </button>
          </div>
      </div>
  );

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-10 animate-fade-in pt-4">
        <div className="space-y-8">
            <div className="bg-card p-8 rounded-3xl border border-gray-800 shadow-2xl">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm">內容編輯 ({mode === 'viral' ? '爆文模式' : '品牌模式'})</h3>
                    <button onClick={() => setStep(1)} className="text-[11px] font-bold text-red-400/80 hover:text-red-400 transition-colors uppercase tracking-widest underline underline-offset-4">返回更換主題</button>
                </div>
                <textarea 
                    value={draft.caption} 
                    onChange={e => setDraft({...draft, caption: e.target.value})} 
                    className="w-full h-[450px] bg-dark/50 border border-gray-800 rounded-2xl p-6 text-white mb-6 resize-none focus:border-primary outline-none custom-scrollbar leading-relaxed text-[15px]" 
                />

                <div className="space-y-4">
                    <button 
                        onClick={handleGenMedia} 
                        className={`w-full py-5 rounded-2xl font-black text-white shadow-xl transition-all flex items-center justify-center gap-3 tracking-widest uppercase ${mediaUrl ? 'bg-indigo-900/50 border border-indigo-500/50' : 'bg-indigo-600'}`}
                    >
                        {mediaUrl ? (
                            <>重新繪製圖片素材 <span className="text-[10px] font-black bg-white/10 px-2 py-0.5 rounded-full">2 點</span></>
                        ) : (
                            <>生成視覺素材 <span className="text-[10px] font-black bg-white/10 px-2 py-0.5 rounded-full">5 點</span></>
                        )}
                    </button>
                </div>
            </div>
        </div>

        <div className="space-y-8">
