const db = admin.firestore();

module.exports = async function (req, res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'POST,OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

  if (req.method === 'OPTIONS') return res.status(200).end();
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method Not Allowed' });

  class KeyManager {
      constructor() {
          this.keys = [
              { id: 'key_1', value: process.env.API_KEY },
              { id: 'key_2', value: process.env.API_KEY_2 },
              { id: 'key_3', value: process.env.API_KEY_3 },
              { id: 'key_4', value: process.env.API_KEY_4 },
              { id: 'key_5', value: process.env.API_KEY_5 }
          ].filter(k => k.value && k.value.length > 10);
          this.currentIndex = 0;
      }

      getCurrent() { return this.keys[this.currentIndex]; }

      switchToNext() {
          if (this.currentIndex < this.keys.length - 1) {
              this.currentIndex++;
              return true;
          }
          return false;
      }

      async logUsage() {
          const keyId = this.getCurrent().id;
          const today = new Date().toISOString().split('T')[0];
          try {
              await db.collection('system_stats').doc('api_usage').set({
                  [keyId]: admin.firestore.FieldValue.increment(1),
                  [`${keyId}_last_used`]: today,
                  total_calls: admin.firestore.FieldValue.increment(1)
              }, { merge: true });
          } catch (e) { console.error("Log failed", e); }
      }
  }

  const keyManager = new KeyManager();

  async function executeWithRetry(operation) {
      if (!keyManager.getCurrent()) throw new Error("API_KEY_MISSING");

      try {
          const { GoogleGenAI } = await import("@google/genai");
          const ai = new GoogleGenAI({ apiKey: keyManager.getCurrent().value });
          const result = await operation(ai);

          // 成功後非同步記錄計數
          keyManager.logUsage();
          return result;
      } catch (error) {
          const isQuota = error.message.includes('429') || error.message.includes('quota') || error.message.includes('exhausted');
          if (isQuota && keyManager.switchToNext()) {
              console.warn(`[Rotation] Key exhausted, switching to ${keyManager.getCurrent().id}`);
              return executeWithRetry(operation);
          }
          throw error;
      }
  }

  try {
    const { action, payload } = req.body;

    if (action === 'fetchRss') {
        const r = await fetch(payload.url);
        return res.status(200).json({ text: await r.text() });
    }

    if (action === 'generateContent') {
        const result = await executeWithRetry(async (ai) => {
            const resp = await ai.models.generateContent({ model: payload.model, contents: payload.contents, config: payload.config });
            return { text: resp.text };
        });
        return res.status(200).json(result);
    }

    if (action === 'generateImages') {
        const result = await executeWithRetry(async (ai) => {
            const resp = await ai.models.generateImages({ model: payload.model, prompt: payload.prompt, config: { numberOfImages: 1 } });
            return { base64: resp.generatedImages[0].image.imageBytes };
        });
        return res.status(200).json(result);
    }

    return res.status(400).json({ error: "Unknown action" });
  } catch (error) {
    return res.status(500).json({ error: error.message });
  }
};

