import { BrandSettings, TrendingTopic, CachedTrendData, CtaItem, ViralType, ViralPlatform, TitleScore, ViralPostDraft } from "../types";
import { db, isMock, firebase } from "./firebase";

// Local Type Definition
const Type = {
  STRING: 'STRING',
  NUMBER: 'NUMBER',
  INTEGER: 'INTEGER',
  BOOLEAN: 'BOOLEAN',
  ARRAY: 'ARRAY',
  OBJECT: 'OBJECT'
};

// #region Utilities

const cleanJsonText = (text: string): string => {
    if (!text) return '{}';
    let clean = text.replace(/```json/g, '').replace(/```/g, '').trim();
    const firstOpen = clean.search(/[\{\[]/);
    const lastClose = Math.max(clean.lastIndexOf('}'), clean.lastIndexOf(']'));
    if (firstOpen !== -1 && lastClose !== -1 && lastClose > firstOpen) {
        clean = clean.substring(firstOpen, lastClose + 1);
    }
    return clean;
};

// #endregion

// #region Backend Caller
const callBackend = async (action: string, payload: any) => {
    try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 55000);

        const res = await fetch('/api/gemini', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action, payload }),
            signal: controller.signal
        });

        clearTimeout(timeoutId);
        const text = await res.text();
        let data;
        try { data = JSON.parse(text); } catch (e) { throw new Error(`Invalid format: ${text.substring(0, 50)}`); }
        if (!res.ok) throw new Error(data.error || 'Server Error');
        return data;
    } catch (e: any) {
        console.error(`Backend API Error [${action}]:`, e);
        throw e;
    }
};
// #endregion

// #region Smart Cache Logic (2 Hours)
const CACHE_TTL = 2 * 60 * 60 * 1000; // 2 小時

export const getTrendingTopics = async (industry: string = "台灣熱門時事", minCount: number = 10): Promise<TrendingTopic[]> => {
    const dateKey = new Date().toISOString().split('T')[0];
    const cacheId = `${dateKey}_${industry.replace(/\s+/g, '_')}`;

    // 1. 檢查快取
    try {
        const doc = await db.collection('global_trend_cache').doc(cacheId).get();
        if (doc.exists) {
            const data = doc.data() as CachedTrendData;
            const age = Date.now() - data.createdAt;

            // 判斷條件：快取未過期 且 快取內容數量充足
            if (age < CACHE_TTL && data.topics && data.topics.length >= minCount) {
                console.log(`[TrendCache] Hit: ${cacheId} (${data.topics.length} items)`);
                return data.topics;
            }
            console.log(`[TrendCache] ${age < CACHE_TTL ? 'Insufficient items' : 'Expired'}. Refetching...`);
        }
    } catch (e) { console.warn("Cache read failed", e); }

    // 2. 獲取新靈感 (RSS + Gemini Fallback)
    let topics: TrendingTopic[] = [];

    // 嘗試從 RSS 獲取
    try {
        const rssUrl = industry.includes('時事') ? 'https://tw.news.yahoo.com/rss' : `https://news.google.com/rss/search?q=${encodeURIComponent(industry)}+when:1d&hl=zh-TW&gl=TW&ceid=TW:zh-Hant`;
        const data = await callBackend('fetchRss', { url: rssUrl });
        const parser = new DOMParser();
        const xml = parser.parseFromString(data.text, "text/xml");
        const items = xml.querySelectorAll("item");

        items.forEach(item => {
            const title = item.querySelector("title")?.textContent || "";
            const link = item.querySelector("link")?.textContent || "";
            if (title && link) topics.push({ title, description: title, url: link });
        });
    } catch (e) { console.warn("RSS fetch failed", e); }

    // 如果 RSS 數量不足或失敗，調用 Gemini 補充
    if (topics.length < minCount) {
        try {
            const response = await callBackend('generateContent', {
                model: 'gemini-3-flash-preview',
                contents: `列出目前台灣關於「${industry}」的至少 ${minCount} 個熱門社群話題。
                請直接回傳純 JSON 陣列。格式: [{ "title": "...", "description": "..." }]`,
                config: { responseMimeType: "application/json" }
            });
            const raw = JSON.parse(cleanJsonText(response.text || '[]'));
            if (Array.isArray(raw)) {
                raw.forEach((t: any) => {
                    if (!topics.find(ex => ex.title === t.title)) {
                        topics.push({ title: t.title, description: t.description || t.title, url: '#' });
                    }
                });
            }
        } catch (e) { console.error("Gemini fallback failed", e); }
    }

    // 3. 存入快取
    if (topics.length > 0) {
        try {
            await db.collection('global_trend_cache').doc(cacheId).set({
                id: cacheId, industry, topics, createdAt: Date.now()
            });
        } catch (e) { console.warn("Cache write failed", e); }
    }

    return topics;
};
// #endregion

