export const generatePostDraft = async (topic: string, settings: BrandSettings, options: any, topicContext?: any, userRole: string = 'user') => {
    const isHighTier = ['business', 'admin'].includes(userRole);
    const selectedModel = isHighTier ? "gemini-3-pro-preview" : "gemini-3-flash-preview";
    const prompt = `針對主題「${topic}」編寫 Facebook 貼文。風格：${settings.brandTone}。Output JSON: { caption, imagePrompt }`;
    const res = await callBackend('generateContent', { model: selectedModel, contents: prompt, config: { responseMimeType: "application/json" } });
    return JSON.parse(cleanJsonText(res.text || '{}'));
