const createMockDb = () => {
  const mockDoc = () => ({
    get: async () => ({ exists: false, data: () => null }),
    set: async () => {},
    update: async () => {},
    delete: async () => {},
    collection: (name: string) => createMockCollection(),
    onSnapshot: (cb: any) => () => {},
  });

  const createMockCollection = () => ({
    doc: (id: string) => mockDoc() as any,
    where: () => createMockCollection() as any,
    orderBy: () => createMockCollection() as any,
    limit: () => createMockCollection() as any,
    get: async () => ({ docs: [] }),
    add: async () => ({ id: 'mock-id' }),
  });

  return {
    collection: (name: string) => createMockCollection() as any,
    doc: (path: string) => mockDoc() as any,
  } as firebase.firestore.Firestore;
};

