  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<any>(null);

  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 999 : 3));
  const isLimitReached = !editPost && (scheduledPostsCount || 0) >= limit;

  const loadTrends = async () => {
      if (!user) return;
      setIsLoadingTrends(true);
      try {
          const trends = await getTrendingTopics(settings.industry || '台灣熱門話題', 12);
          setTrendingTopics(trends);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async (selectedTopic?: string) => {
    const finalTopic = selectedTopic || topic;
    if (!finalTopic || !user) return;
    const allowed = await checkAndUseQuota(user.user_id, 2);
    if (!allowed) return alert("配額不足 (2 點)");
    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setTopic(finalTopic);
    try {
        if (mode === 'brand') {
            const res = await generatePostDraft(finalTopic, settings, {}, undefined, user.role);
            setDraft({ caption: res.caption, imagePrompt: res.imagePrompt });
        } else {
            const res = await generateViralContent(finalTopic, {}, settings);
            setDraft({ caption: res.versions[0], imagePrompt: res.imagePrompt });
        }
    } catch (e: any) { alert(`失敗: ${e.message}`); setStep(1); }
    finally { setIsGeneratingDraft(false); }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;
    const cost = mediaUrl ? 2 : 5;
    const allowed = await checkAndUseQuota(user.user_id, cost);
    if (!allowed) return alert(`配額不足 (${cost} 點)`);
    onQuotaUpdate();
    setMediaUrl(undefined);
    setIsGeneratingMedia(true);
    try {
      let url = await generateImage(draft.imagePrompt, user.role);
      setMediaUrl(url);
    } catch (e: any) { alert(`製圖失敗: ${e.message}`); }
    finally { setIsGeneratingMedia(false); }
  };

  const handleFinalize = async () => {
    if (!user || isPublishing) return;
    setIsPublishing(true);
    try {
        const res = await publishPostToFacebook(settings.facebookPageId, settings.facebookToken, draft.caption, mediaUrl);
        setPublishResult({ success: res.success, msg: res.success ? "發佈成功" : "發佈失敗: " + res.error });
    } catch (err: any) { setPublishResult({ success: false, msg: err.message }); }
    finally { setIsPublishing(false); }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="AI 正在構思文案" detail="正在提取品牌設定與產品亮點..." />;
  if (isGeneratingMedia) return <LoadingOverlay message="AI 正在繪製圖片" detail="Gemini Pro Image 正在運算高精細度視覺..." />;
  if (isPublishing) return <LoadingOverlay message="正在執行發佈" detail="正在與 Facebook Graph API 進行安全握手..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-12 animate-fade-in pt-4">
          <div className="text-center space-y-3">
              <h2 className="text-4xl font-black text-white tracking-tight uppercase">你想聊什麼話題？</h2>
              <p className="text-gray-500 font-medium">輸入核心主題，讓 AI 為您打造吸睛內容。</p>
          </div>
          <div className="bg-card p-10 rounded-3xl border border-gray-800 shadow-2xl space-y-8">
              <div className="flex p-1.5 bg-dark/80 rounded-2xl border border-gray-800">
                  <button onClick={() => setMode('brand')} className={`flex-1 py-4 rounded-xl font-bold transition-all ${mode === 'brand' ? 'bg-primary text-white' : 'text-gray-500'}`}>品牌模式</button>
                  <button onClick={() => setMode('viral')} className={`flex-1 py-4 rounded-xl font-bold transition-all ${mode === 'viral' ? 'bg-orange-600 text-white' : 'text-gray-500'}`}>爆文模式</button>
              </div>
              <div className="flex gap-3">
                  <input value={topic} onChange={e => setTopic(e.target.value)} className="flex-1 bg-dark/50 border border-gray-700 rounded-2xl p-5 text-white outline-none focus:border-primary text-xl font-medium" placeholder="輸入主題..." />
                  <button onClick={loadTrends} className="bg-gray-800 hover:bg-gray-700 px-8 rounded-2xl text-white font-bold transition-all">
                    挖掘靈感
                  </button>
              </div>
              {isLoadingTrends ? (
                  <div className="flex justify-center py-6"><div className="loader"></div></div>
              ) : trendingTopics.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-72 overflow-y-auto p-4 border border-gray-800 rounded-2xl bg-dark/20 custom-scrollbar">
                      {trendingTopics.map((t, i) => (
                          <div key={i} onClick={() => handleNext(t.title)} className="bg-dark/40 border border-gray-800 p-4 rounded-xl cursor-pointer hover:border-primary transition-all group">
                              <h4 className="font-bold text-blue-400 text-sm mb-1">{t.title}</h4>
                              <p className="text-[11px] text-gray-500 line-clamp-1">{t.description}</p>
                          </div>
                      ))}
                  </div>
              )}
              <button onClick={() => handleNext()} disabled={!topic} className={`w-full py-6 rounded-2xl font-black text-white shadow-2xl disabled:opacity-30 text-xl tracking-widest uppercase ${mode === 'viral' ? 'bg-orange-600' : 'bg-primary'}`}>生成文案 (2 點)</button>
          </div>
      </div>
  );

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-10 animate-fade-in pt-4">
        <div className="space-y-8">
            <div className="bg-card p-8 rounded-3xl border border-gray-800 shadow-2xl">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm">內容編輯</h3>
                    <button onClick={() => setStep(1)} className="text-[11px] font-bold text-red-400/80 hover:text-red-400 uppercase tracking-widest underline">重新選擇話題</button>
                </div>
                <textarea value={draft.caption} onChange={e => setDraft({...draft, caption: e.target.value})} className="w-full h-[450px] bg-dark/50 border border-gray-800 rounded-2xl p-6 text-white mb-6 resize-none focus:border-primary outline-none custom-scrollbar leading-relaxed" />
                <button onClick={handleGenMedia} className={`w-full py-5 rounded-2xl font-black text-white shadow-xl transition-all flex items-center justify-center gap-3 tracking-widest uppercase ${mediaUrl ? 'bg-indigo-900/50' : 'bg-indigo-600'}`}>
                    {mediaUrl ? "重新繪製圖片 (2 點)" : "生成 AI 圖片 (5 點)"}
                </button>
            </div>
        </div>
        <div className="space-y-8">
            <div className="bg-card p-8 rounded-3xl border border-gray-800 shadow-2xl flex flex-col min-h-[600px]">
                <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm mb-6">發佈預覽</h3>
                <div className="bg-white rounded-2xl overflow-hidden flex-1 border border-gray-200 shadow-inner flex flex-col">
                    <div className="p-4 border-b flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center text-primary font-bold">P</div>
                        <div className="h-2 w-28 bg-gray-200 rounded"></div>
                    </div>
                    <div className="p-5 overflow-y-auto max-h-[500px] flex-1">
                        <p className="text-black text-[14px] whitespace-pre-wrap mb-5 leading-relaxed font-sans">{draft.caption}</p>
                        {mediaUrl && <img src={mediaUrl} className="w-full h-auto rounded-xl shadow-lg border border-gray-100" />}
                    </div>
                </div>
                {publishResult ? (
                    <div className={`mt-8 p-5 rounded-2xl text-center font-bold border ${publishResult.success ? 'bg-green-900/40 text-green-200 border-green-700/50' : 'bg-red-900/40 text-red-200 border-red-700/50'}`}>
                        {publishResult.msg}
                        <button onClick={() => setPublishResult(null)} className="block mx-auto mt-2 text-[10px] uppercase font-black tracking-widest text-white/50 hover:text-white underline">繼續編輯</button>
                    </div>
                ) : (
                    <div className="mt-8">
                        <button onClick={handleFinalize} disabled={isLimitReached} className={`w-full bg-primary text-white py-5 rounded-2xl font-black shadow-2xl hover:bg-blue-600 transition-all text-sm uppercase tracking-widest ${isLimitReached ? 'opacity-50 cursor-not-allowed' : ''}`}>
                            {isLimitReached ? "排程空間已滿" : "立即發佈至 Facebook"}
                        </button>
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

