export const checkAndUseQuota = async (uId: string, amt: number = 1): Promise<boolean> => {
    const profile = await getUserProfile(uId);
    if (!profile || profile.isSuspended) return false;
    if (profile.quota_used + amt > profile.quota_total) return false;
    if (!isMock) {
        await db.collection('users').doc(uId).update({ 
            quota_used: firebase.firestore.FieldValue.increment(amt),
            updated_at: Date.now()
        });
    } else {
        const users = getMockDb(DB_USERS);
        if (users[uId]) { users[uId].quota_used += amt; saveMockDb(DB_USERS, users); }
    }
    return true;
};

