// Fix: Add missing useAdminKey export to fix import error in apiClient.ts
export const useAdminKey = async (userId: string, key: string) => {
    if (!isMock) {
        const keyRef = db.collection('admin_keys').doc(key);
        const userRef = db.collection('users').doc(userId);

        try {
            const kDoc = await keyRef.get();
            if (!kDoc.exists) throw new Error("Invalid Key");

            const kData = kDoc.data();
            if (kData?.isUsed) throw new Error("Key already used");
            if (Date.now() > kData?.expiresAt) throw new Error("Key expired");

            if (kData?.type === 'RESET_QUOTA') {
                await userRef.update({ quota_used: 0 });
            } else if (kData?.type === 'UPGRADE_ROLE') {
                const newRole = kData.targetRole as UserRole;
                const newQuotaTotal = getQuotaForRole(newRole);
                await userRef.update({ 
                    role: newRole,
                    quota_total: newQuotaTotal 
                });
            }

            await keyRef.update({ isUsed: true, usedBy: userId });
            return { success: true, message: 'Key applied successfully' };
        } catch (error: any) {
            throw new Error(error.message);
        }
    }
    return { success: true, message: 'Mock Key Applied' };
};

