    if (!isMock) {
        const keyRef = db.collection('admin_keys').doc(key);
        const userRef = db.collection('users').doc(userId);
        try {
            return await db.runTransaction(async (t) => {
                const doc = await t.get(keyRef);
                if (!doc.exists || doc.data()?.isUsed) throw new Error("無效金鑰");
                const kData = doc.data();
                if (kData?.type === 'UPGRADE_ROLE') {
                    const role = kData.targetRole;
                    t.update(userRef, { role, quota_total: getQuotaForRole(role) });
                }
                t.update(keyRef, { isUsed: true, usedBy: userId });
                return { success: true };
            });
        } catch (e: any) { throw new Error(e.message); }
    }
    return { success: true };
};

