              </div>
              <div className="grid grid-cols-1 md:grid-cols-5 gap-6">
                  {[1, 2, 3, 4, 5].map(idx => {
                      const key = `key_${idx}`;
                      const count = apiUsage[key] || 0;
                      // 假設每組 Key 每日上限 1500 次 (Flash Free Tier)
                      const percentage = Math.min(100, (count / 1500) * 100);
                      return (
                          <div key={key} className="bg-dark/50 p-6 rounded-2xl border border-gray-800 flex flex-col items-center text-center group hover:border-primary/50 transition-all">
                              <span className="text-[10px] text-gray-500 font-bold uppercase tracking-widest mb-4">Slot {idx}</span>
                              <div className="relative w-24 h-24 mb-4">
                                  <svg className="w-full h-full transform -rotate-90">
                                      <circle cx="48" cy="48" r="40" stroke="currentColor" strokeWidth="8" fill="transparent" className="text-gray-800" />
                                      <circle cx="48" cy="48" r="40" stroke="currentColor" strokeWidth="8" fill="transparent" 
                                              className={`transition-all duration-1000 ${percentage > 80 ? 'text-red-500' : percentage > 50 ? 'text-yellow-500' : 'text-primary'}`} 
                                              strokeDasharray={251} strokeDashoffset={251 - (251 * percentage) / 100} />
                                  </svg>
                                  <div className="absolute inset-0 flex flex-col items-center justify-center">
                                      <span className="font-black text-white text-lg">{count}</span>
                                      <span className="text-[8px] text-gray-500 uppercase">Requests</span>
                                  </div>
                              </div>
                              <p className="text-xs text-gray-400 font-bold">{percentage.toFixed(1)}% 消耗</p>
                          </div>
                      );
                  })}
              </div>
              <div className="mt-8 p-4 bg-primary/10 border border-primary/20 rounded-xl">
                  <p className="text-primary text-xs flex items-center gap-2">
                      💡 提示：系統會在發生 429 錯誤時自動切換至下一組 Slot。每日 UTC 00:00 自動重置計數。
                  </p>
              </div>
          </div>
      )}

      {activeTab === 'reports' && (
          <div className="bg-card rounded-2xl border border-gray-800 shadow-2xl overflow-hidden">
              <div className="p-6 border-b border-gray-800 bg-dark/20"><h3 className="font-bold text-white">問題回報單</h3></div>
              <div className="divide-y divide-gray-800">
                  {reports.length === 0 ? (
                      <div className="p-20 text-center text-gray-500 text-sm italic">目前無待處理回報。</div>
                  ) : reports.map(r => (
                      <div key={r.id} className="p-6 hover:bg-white/5 transition-colors">
                          <div className="flex justify-between items-start mb-2">
                              <div>
                                  <span className="text-white font-bold">{r.userEmail}</span>
                                  <span className="text-xs text-gray-500 ml-4 font-mono">{new Date(r.timestamp).toLocaleString()}</span>
                              </div>
                              <span className={`px-2 py-0.5 rounded text-[10px] font-bold ${r.status === 'OPEN' ? 'bg-red-900 text-red-200' : 'bg-green-900 text-green-200'}`}>{r.status}</span>
                          </div>
                          <p className="text-sm text-gray-300 leading-relaxed mb-4">{r.description}</p>
                          <div className="flex gap-2 text-[10px] text-gray-600">
                              <span className="bg-dark px-2 py-1 rounded">頁面: {r.currentView}</span>
                              <span className="bg-dark px-2 py-1 rounded truncate max-w-sm">{r.userAgent}</span>
                          </div>
                      </div>
                  ))}
              </div>
          </div>
      )}
    </div>
  );
};

