import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, generateViralContent } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (newPost: Post) => void;
  onQuotaUpdate: () => void;
  editPost: Post | null;
  onCancel: () => void;
  scheduledPostsCount?: number;
}

