export const PostCreator: React.FC<Props> = ({ settings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [mode, setMode] = useState<'brand' | 'viral'>('brand');
  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);
  const [draft, setDraft] = useState({ caption: '', imagePrompt: '' });
  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<any>(null);

  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 999 : 3));
  const isLimitReached = !editPost && (scheduledPostsCount || 0) >= limit;

  const loadTrends = async () => {
      if (!user) return;
      setIsLoadingTrends(true);
      try {
          const industry = settings.industry || '台灣熱門話題';
          const trends = await getTrendingTopics(industry, 15);
          setTrendingTopics(trends);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async (selectedTopic?: string) => {
    const finalTopic = selectedTopic || topic;
    if (!finalTopic || !user) return;
    const allowed = await checkAndUseQuota(user.user_id, 2);
    if (!allowed) return alert("配額不足 (需要 2 點)");
    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setTopic(finalTopic);
    try {
        if (mode === 'brand') {
            const res = await generatePostDraft(finalTopic, settings, {}, undefined, user.role);
            setDraft({ caption: res.caption, imagePrompt: res.imagePrompt });
        } else {
            const res = await generateViralContent(finalTopic, {}, settings);
            setDraft({ caption: res.versions[0], imagePrompt: res.imagePrompt });
        }
    } catch (e: any) { alert(`內容生成失敗: ${e.message}`); setStep(1); }
    finally { setIsGeneratingDraft(false); }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;
    const cost = mediaUrl ? 2 : 5;
    const allowed = await checkAndUseQuota(user.user_id, cost);
    if (!allowed) return alert(`配額不足 (需要 ${cost} 點)`);
    onQuotaUpdate();
    setMediaUrl(undefined);
    setIsGeneratingMedia(true);
    try {
      let url = await generateImage(draft.imagePrompt, user.role);
      setMediaUrl(url);
    } catch (e: any) { alert(`視覺生成失敗: ${e.message}`); }
    finally { setIsGeneratingMedia(false); }
  };

  const handleFinalize = async () => {
    if (!user || isPublishing) return;
    setIsPublishing(true);
    try {
        const res = await publishPostToFacebook(settings.facebookPageId, settings.facebookToken, draft.caption, mediaUrl);
        setPublishResult({ success: res.success, msg: res.success ? "✅ 貼文發佈成功" : "❌ 發佈失敗: " + res.error });
    } catch (err: any) { setPublishResult({ success: false, msg: err.message }); }
    finally { setIsPublishing(false); }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="🧠 AI 正在構思文案" detail="正在提取品牌設定與產品亮點，並優化 Hook 吸引力..." />;
  if (isGeneratingMedia) return <LoadingOverlay message="🎨 AI 正在繪製視覺" detail="Gemini Pro Image 正在針對文案主題進行高精細度視覺運算..." />;
  if (isPublishing) return <LoadingOverlay message="🚀 正在執行同步發佈" detail="正在與 Facebook Graph API 進行安全交握並上傳多媒體素材..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-12 animate-fade-in pt-4">
          <div className="text-center space-y-3">
              <h2 className="text-4xl font-black text-white tracking-tight uppercase">你想聊什麼話題？</h2>
              <p className="text-gray-500 font-medium">輸入核心主題或挖掘靈感，讓 AI 為您打造吸睛內容。</p>
          </div>
          <div className="bg-card p-10 rounded-3xl border border-gray-800 shadow-2xl space-y-8">
              <div className="flex p-1.5 bg-dark/80 rounded-2xl border border-gray-800">
                  <button onClick={() => setMode('brand')} className={`flex-1 py-4 rounded-xl font-bold transition-all ${mode === 'brand' ? 'bg-primary text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>品牌模式</button>
                  <button onClick={() => setMode('viral')} className={`flex-1 py-4 rounded-xl font-bold transition-all ${mode === 'viral' ? 'bg-orange-600 text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>爆文模式</button>
              </div>
              <div className="flex gap-3">
                  <input value={topic} onChange={e => setTopic(e.target.value)} className="flex-1 bg-dark/50 border border-gray-700 rounded-2xl p-5 text-white outline-none focus:border-primary text-xl font-medium" placeholder="輸入主題 (例如：夏季保養趨勢)..." />
                  <button onClick={loadTrends} className="bg-gray-800 hover:bg-gray-700 px-8 rounded-2xl text-white font-bold transition-all border border-gray-700 flex flex-col items-center justify-center">
                    <span className="text-sm">靈感</span>
                    <span className="text-[10px] text-blue-400">挖掘</span>
                  </button>
              </div>
              {isLoadingTrends ? (
                  <div className="flex justify-center py-6"><div className="loader"></div></div>
              ) : trendingTopics.length > 0 && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-72 overflow-y-auto p-4 border border-gray-800 rounded-2xl bg-dark/20 custom-scrollbar">
                      {trendingTopics.map((t, i) => (
                          <div key={i} onClick={() => handleNext(t.title)} className="bg-dark/40 border border-gray-800 p-4 rounded-xl cursor-pointer hover:border-primary transition-all group">
                              <h4 className="font-bold text-blue-400 text-sm mb-1 line-clamp-1">{t.title}</h4>
                              <p className="text-[11px] text-gray-500 line-clamp-1">{t.description}</p>
                          </div>
                      ))}
                  </div>
              )}
              <button onClick={() => handleNext()} disabled={!topic} className={`w-full py-6 rounded-2xl font-black text-white shadow-2xl disabled:opacity-30 text-xl tracking-widest uppercase transition-all transform active:scale-95 ${mode === 'viral' ? 'bg-orange-600 hover:bg-orange-500' : 'bg-primary hover:bg-blue-600'}`}>生成文案 (2 點)</button>
          </div>
      </div>
  );

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-10 animate-fade-in pt-4">
        <div className="space-y-8">
            <div className="bg-card p-8 rounded-3xl border border-gray-800 shadow-2xl">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm">內容編輯中</h3>
                    <button onClick={() => setStep(1)} className="text-[11px] font-bold text-red-400/80 hover:text-red-400 uppercase tracking-widest underline underline-offset-4">放棄改回話題</button>
                </div>
                <textarea value={draft.caption} onChange={e => setDraft({...draft, caption: e.target.value})} className="w-full h-[450px] bg-dark/50 border border-gray-800 rounded-2xl p-6 text-white mb-6 resize-none focus:border-primary outline-none custom-scrollbar leading-relaxed font-sans" />
                <button onClick={handleGenMedia} className={`w-full py-5 rounded-2xl font-black text-white shadow-xl transition-all flex items-center justify-center gap-3 tracking-widest uppercase ${mediaUrl ? 'bg-indigo-900/40 border border-indigo-500/50' : 'bg-indigo-600 hover:bg-indigo-500'}`}>
                    {mediaUrl ? "重新繪製視覺 (2 點)" : "生成 AI 高畫質圖片 (5 點)"}
                </button>
            </div>
        </div>
        <div className="space-y-8">
            <div className="bg-card p-8 rounded-3xl border border-gray-800 shadow-2xl flex flex-col min-h-[600px]">
                <h3 className="font-black text-gray-300 tracking-tighter uppercase text-sm mb-6">社群發佈預覽</h3>
                <div className="bg-white rounded-2xl overflow-hidden flex-1 border border-gray-200 shadow-inner flex flex-col">
                    <div className="p-4 border-b flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-blue-500 flex items-center justify-center text-white font-bold shadow-lg">P</div>
                        <div className="space-y-1">
                            <div className="h-2.5 w-32 bg-gray-200 rounded"></div>
                            <div className="h-2 w-20 bg-gray-100 rounded"></div>
                        </div>
                    </div>
                    <div className="p-5 overflow-y-auto max-h-[500px] flex-1 custom-scrollbar">
                        <p className="text-black text-[14px] whitespace-pre-wrap mb-5 leading-relaxed font-sans">{draft.caption}</p>
                        {mediaUrl && <img src={mediaUrl} className="w-full h-auto rounded-xl shadow-lg border border-gray-100" alt="AI Generated" />}
                    </div>
                </div>
                {publishResult ? (
                    <div className={`mt-8 p-5 rounded-2xl text-center font-bold border ${publishResult.success ? 'bg-green-900/40 text-green-200 border-green-700/50' : 'bg-red-900/40 text-red-200 border-red-700/50'}`}>
                        {publishResult.msg}
                        <button onClick={() => setPublishResult(null)} className="block mx-auto mt-2 text-[10px] uppercase font-black tracking-widest text-white/50 hover:text-white underline">繼續編輯文案</button>
                    </div>
                ) : (
                    <div className="mt-8">
                        <button onClick={handleFinalize} disabled={isLimitReached} className={`w-full bg-primary text-white py-5 rounded-2xl font-black shadow-2xl hover:bg-blue-600 transition-all text-sm uppercase tracking-widest transform active:scale-95 ${isLimitReached ? 'opacity-50 cursor-not-allowed' : ''}`}>
                            {isLimitReached ? "排程儲存空間已滿" : "立即發佈至 Facebook"}
                        </button>
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  getAllUsers, updateUserRole, getDashboardStats, 
  toggleUserSuspension, manualUpdateQuota, getUserReports, resetUserQuota
} from '../services/authService';
import { db, isMock } from '../services/firebase';
import { UserProfile, UserRole, DashboardStats, UserReport } from '../types';

interface Props {
  currentUser: UserProfile;
}

const AdminPanel: React.FC<Props> = ({ currentUser }) => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'users' | 'api_monitor' | 'reports'>('dashboard');
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [reports, setReports] = useState<UserReport[]>([]);
  const [apiUsage, setApiUsage] = useState<any>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    loadData();
  }, [activeTab]);

  const loadData = async () => {
    setLoading(true);
    if (activeTab === 'dashboard') setStats(await getDashboardStats());
    if (activeTab === 'users') setUsers(await getAllUsers());
    if (activeTab === 'reports') setReports(await getUserReports());
    if (activeTab === 'api_monitor') loadApiUsage();
    setLoading(false);
  };

  const loadApiUsage = async () => {
      if (isMock) {
          setApiUsage({ key_1: 450, key_2: 120, key_3: 0, key_4: 0, key_5: 0, total_calls: 570 });
          return;
      }
      try {
          const doc = await db.collection('system_stats').doc('api_usage').get();
          if (doc.exists) setApiUsage(doc.data());
      } catch (e) { console.error("Load API Usage failed", e); }
  };

  const handleEditQuota = async (u: UserProfile) => {
      const newUsed = prompt(`修改 [${u.email}] 的已用配額 (目前: ${u.quota_used})`, u.quota_used.toString());
      if (newUsed === null) return;
      const newTotal = prompt(`修改 [${u.email}] 的配額總量 (目前: ${u.quota_total})`, u.quota_total.toString());
      if (newTotal === null) return;

      const used = parseInt(newUsed);
      const total = parseInt(newTotal);
      if (!isNaN(used) && !isNaN(total)) {
          await manualUpdateQuota(u.user_id, used, total);
          loadData();
      }
  };

  const handleOneClickReset = async (uid: string) => {
      if (confirm("確定要重置該用戶的已使用配額為 0 嗎？")) {
          await resetUserQuota(uid);
          loadData();
      }
  };

  const filteredUsers = users.filter(u => 
    u.email.toLowerCase().includes(searchTerm.toLowerCase()) || 
    u.user_id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="w-full max-w-[1200px] mx-auto p-4 md:p-8 space-y-6 animate-fade-in pb-24 overflow-x-hidden">
      <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-6 border-b border-gray-800 pb-6">
          <div className="space-y-1">
              <h2 className="text-3xl font-black text-white flex items-center gap-3 tracking-tighter uppercase">
                  👮 管理員中控台 
              </h2>
              <p className="text-xs text-gray-500 font-bold tracking-widest uppercase">System Administrator Portal</p>
          </div>
          <div className="flex bg-card p-1 rounded-2xl border border-gray-700 overflow-x-auto no-scrollbar shadow-2xl">
            {[
                { id: 'dashboard', label: '📊 數據看板' },
                { id: 'users', label: '👥 會員管理' },
                { id: 'api_monitor', label: '🔌 API 監控' },
                { id: 'reports', label: '🐞 故障回報' }
            ].map((tab) => (
                <button 
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id as any)} 
                    className={`px-6 py-2.5 text-xs font-black rounded-xl transition-all whitespace-nowrap uppercase tracking-widest ${activeTab === tab.id ? 'bg-primary text-white shadow-xl scale-105' : 'text-gray-500 hover:text-gray-300'}`}
                >
                    {tab.label}
                </button>
            ))}
          </div>
      </div>

      {activeTab === 'dashboard' && stats && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
              {[
                { label: '註冊總數', val: stats.totalUsers, color: 'text-white', bg: 'bg-primary/10' },
                { label: '今日活躍', val: stats.activeUsersToday, color: 'text-blue-400', bg: 'bg-blue-400/10' },
                { label: '累積 API 調用', val: stats.totalApiCallsToday, color: 'text-green-400', bg: 'bg-green-400/10' },
                { label: '待處理回報', val: reports.filter(r => r.status === 'OPEN').length, color: 'text-red-400', bg: 'bg-red-400/10' }
              ].map((item, i) => (
                <div key={i} className={`p-8 rounded-3xl border border-gray-800 shadow-xl transition-transform hover:scale-[1.02] ${item.bg}`}>
                    <p className="text-gray-500 text-[10px] font-black uppercase tracking-[0.2em]">{item.label}</p>
                    <p className={`text-4xl font-black mt-3 ${item.color}`}>{item.val.toLocaleString()}</p>
                </div>
              ))}
          </div>
      )}

      {activeTab === 'users' && (
          <div className="bg-card rounded-3xl border border-gray-800 shadow-2xl overflow-hidden">
              <div className="p-6 border-b border-gray-800 flex flex-col md:flex-row gap-4 justify-between bg-dark/40">
                  <div className="relative flex-1 max-w-md">
                      <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500">🔍</span>
                      <input 
                        placeholder="搜尋 Email 或 ID..." 
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                        className="w-full bg-dark/60 border border-gray-700 rounded-2xl pl-12 pr-4 py-3 text-sm text-white focus:border-primary outline-none"
                      />
                  </div>
