                      🔄 刷新數據
                  </button>
              </div>
              <div className="overflow-x-auto custom-scrollbar">
                  <table className="w-full text-left min-w-[900px]">
                      <thead className="bg-dark/80 text-[10px] text-gray-500 uppercase tracking-[0.2em]">
                          <tr>
