      {activeTab === 'api_monitor' && apiUsage && (
          <div className="bg-card p-10 rounded-3xl border border-gray-800 shadow-2xl">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
