                                      <circle cx="56" cy="56" r="48" stroke="currentColor" strokeWidth="10" fill="transparent" 
                                              className={`transition-all duration-1000 ${percentage > 85 ? 'text-red-500' : percentage > 60 ? 'text-yellow-500' : 'text-primary'}`} 
                                              strokeDasharray={301.6} strokeDashoffset={301.6 - (301.6 * percentage) / 100} />
                                  </svg>
                                  <div className="absolute inset-0 flex flex-col items-center justify-center">
                                      <span className="font-black text-white text-xl">{count}</span>
                                      <span className="text-[8px] text-gray-500 uppercase font-bold">REQ</span>
