                          </div>
                      );
                  })}
              </div>
          </div>
      )}

      {activeTab === 'reports' && (
          <div className="bg-card rounded-3xl border border-gray-800 shadow-2xl overflow-hidden min-h-[400px]">
              <div className="p-8 border-b border-gray-800 bg-dark/40">
