              <div className="divide-y divide-gray-800">
                  {reports.length === 0 ? (
                      <div className="p-20 text-center text-gray-600 text-sm font-bold uppercase tracking-widest italic">目前尚無待處理的異常回報。</div>
                  ) : reports.map(r => (
                      <div key={r.id} className="p-8 hover:bg-white/[0.02] transition-colors">
                          <div className="flex justify-between items-start mb-4">
                              <div className="space-y-1">
                                  <span className="text-white font-black text-lg block">{r.userEmail}</span>
                                  <span className="text-[10px] text-gray-600 font-mono tracking-widest">{new Date(r.timestamp).toLocaleString()}</span>
                              </div>
                              <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${r.status === 'OPEN' ? 'bg-red-500/10 text-red-500 border border-red-500/20' : 'bg-green-500/10 text-green-500 border border-green-500/20'}`}>{r.status}</span>
                          </div>
                          <p className="text-sm text-gray-300 leading-relaxed mb-6 bg-dark/60 p-4 rounded-2xl border border-gray-800">{r.description}</p>
