import React, { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, UserProfile } from '../types';
import { getTrendingTopics, generatePostDraft, generateImage, generateViralContent } from '../services/geminiService';
import { publishPostToFacebook } from '../services/facebookService';
import { checkAndUseQuota } from '../services/authService';

interface Props {
  settings: BrandSettings;
  user: UserProfile | null;
  onPostCreated: (newPost: Post) => void;
  onQuotaUpdate: () => void;
  editPost: Post | null;
  onCancel: () => void;
  scheduledPostsCount?: number;
}

const LoadingOverlay: React.FC<{ message: string, detail?: string }> = ({ message, detail }) => {
    const [tipIndex, setTipIndex] = useState(0);
    const tips = [
        "💡 行銷撇步：在貼文第一行使用「痛點提問」能增加 30% 點擊率。",
        "💡 功能介紹：系統會自動根據您的品牌設定調整 AI 寫作風格。",
        "💡 專家建議：圖片色調與品牌 Logo 統一，能強化品牌視覺記憶。",
        "💡 流量密碼：台灣用戶在晚上 9 點到 11 點的互動率最高。",
        "💡 安全提醒：已為您開啟 API 備援機制，確保生成穩定流暢。",
        "🚀 進度追蹤：正在嘗試與 Facebook 伺服器建立加密握手連線...",
        "🧠 運算中：Gemini 3 Pro 正在深度分析您的產品知識庫與參考文件..."
    ];

    useEffect(() => {
        const interval = setInterval(() => {
            setTipIndex(prev => (prev + 1) % tips.length);
        }, 3500);
        return () => clearInterval(interval);
    }, []);

    return (
        <div className="fixed inset-0 bg-dark/95 z-[100] flex flex-col items-center justify-center p-8 backdrop-blur-md animate-fade-in text-center">
            <div className="relative mb-8">
                <div className="w-24 h-24 border-4 border-gray-800 rounded-full"></div>
                <div className="absolute top-0 left-0 w-24 h-24 border-4 border-primary rounded-full border-t-transparent animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center"><span className="text-3xl animate-pulse">🤖</span></div>
            </div>
            <h2 className="text-3xl font-black text-white mb-2 tracking-tighter uppercase">{message}</h2>
            <p className="text-blue-400 font-bold mb-10 animate-pulse text-sm">{detail || "深度神經網路運算中..."}</p>

            <div className="bg-card p-6 rounded-2xl border border-gray-700 max-w-md w-full shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-primary to-blue-600"></div>
                <p className="text-gray-200 text-sm font-medium leading-relaxed transition-all duration-500 min-h-[60px] flex items-center justify-center">
