};

export const PostCreator: React.FC<Props> = ({ settings, user, onPostCreated, onQuotaUpdate, editPost, onCancel, scheduledPostsCount = 0 }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [topic, setTopic] = useState('');
  const [mode, setMode] = useState<'brand' | 'viral'>('brand');
  const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
  const [isLoadingTrends, setIsLoadingTrends] = useState(false);
  const [draft, setDraft] = useState({ caption: '', imagePrompt: '' });
  const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);
  const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
  const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishResult, setPublishResult] = useState<any>(null);

  const role = user?.role || 'user';
  const limit = role === 'pro' ? 5 : (role === 'business' ? 10 : (role === 'admin' ? 999 : 3));
  const isLimitReached = !editPost && (scheduledPostsCount || 0) >= limit;

  const loadTrends = async () => {
      if (!user) return;
      setIsLoadingTrends(true);
      try {
          const industry = settings.industry || '台灣熱門話題';
          const trends = await getTrendingTopics(industry, 15);
          setTrendingTopics(trends);
      } catch (e) { console.error(e); }
      finally { setIsLoadingTrends(false); }
  };

  const handleNext = async (selectedTopic?: string) => {
    const finalTopic = selectedTopic || topic;
    if (!finalTopic || !user) return;
    const allowed = await checkAndUseQuota(user.user_id, 2);
    if (!allowed) return alert("配額不足 (需要 2 點)");
    onQuotaUpdate();
    setStep(2);
    setIsGeneratingDraft(true);
    setTopic(finalTopic);
    try {
        if (mode === 'brand') {
            const res = await generatePostDraft(finalTopic, settings, {}, undefined, user.role);
            setDraft({ caption: res.caption, imagePrompt: res.imagePrompt });
        } else {
            const res = await generateViralContent(finalTopic, {}, settings);
            setDraft({ caption: res.versions[0], imagePrompt: res.imagePrompt });
        }
    } catch (e: any) { alert(`內容生成失敗: ${e.message}`); setStep(1); }
    finally { setIsGeneratingDraft(false); }
  };

  const handleGenMedia = async () => {
    if (!user || isGeneratingMedia) return;
    const cost = mediaUrl ? 2 : 5;
    const allowed = await checkAndUseQuota(user.user_id, cost);
    if (!allowed) return alert(`配額不足 (需要 ${cost} 點)`);
    onQuotaUpdate();
    setMediaUrl(undefined);
    setIsGeneratingMedia(true);
    try {
      let url = await generateImage(draft.imagePrompt, user.role);
      setMediaUrl(url);
    } catch (e: any) { alert(`視覺生成失敗: ${e.message}`); }
    finally { setIsGeneratingMedia(false); }
  };

  const handleFinalize = async () => {
    if (!user || isPublishing) return;
    setIsPublishing(true);
    try {
        const res = await publishPostToFacebook(settings.facebookPageId, settings.facebookToken, draft.caption, mediaUrl);
        setPublishResult({ success: res.success, msg: res.success ? "✅ 貼文發佈成功" : "❌ 發佈失敗: " + res.error });
    } catch (err: any) { setPublishResult({ success: false, msg: err.message }); }
    finally { setIsPublishing(false); }
  };

  if (isGeneratingDraft) return <LoadingOverlay message="🧠 AI 正在構思文案" detail="正在提取品牌設定與產品亮點，並優化 Hook 吸引力..." />;
  if (isGeneratingMedia) return <LoadingOverlay message="🎨 AI 正在繪製視覺" detail="Gemini Pro Image 正在針對文案主題進行高精細度視覺運算..." />;
  if (isPublishing) return <LoadingOverlay message="🚀 正在執行同步發佈" detail="正在與 Facebook Graph API 進行安全交握並上傳多媒體素材..." />;

  if (step === 1) return (
      <div className="max-w-4xl mx-auto space-y-12 animate-fade-in pt-8 pb-20">
          <div className="text-center space-y-3">
              <h2 className="text-5xl font-black text-white tracking-tighter uppercase">你想聊什麼話題？</h2>
              <p className="text-gray-500 font-bold uppercase tracking-widest text-xs">Enter a topic or discover inspiration</p>
          </div>
          <div className="bg-card p-10 rounded-[40px] border border-gray-800 shadow-2xl space-y-10 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-primary via-blue-500 to-indigo-600"></div>

              <div className="flex p-2 bg-dark/80 rounded-[28px] border border-gray-800">
                  <button onClick={() => setMode('brand')} className={`flex-1 py-5 rounded-[22px] font-black transition-all uppercase tracking-widest text-xs ${mode === 'brand' ? 'bg-primary text-white shadow-xl scale-[1.02]' : 'text-gray-500 hover:text-gray-300'}`}>品牌經營模式</button>
                  <button onClick={() => setMode('viral')} className={`flex-1 py-5 rounded-[22px] font-black transition-all uppercase tracking-widest text-xs ${mode === 'viral' ? 'bg-orange-600 text-white shadow-xl scale-[1.02]' : 'text-gray-500 hover:text-gray-300'}`}>流量爆文模式</button>
              </div>

              <div className="space-y-4">
                  <div className="flex gap-4">
                      <input 
                        value={topic} 
                        onChange={e => setTopic(e.target.value)} 
                        className="flex-1 bg-dark/50 border border-gray-700 rounded-3xl px-8 py-6 text-white outline-none focus:border-primary text-xl font-bold placeholder:text-gray-700" 
                        placeholder="在此輸入貼文核心主題..." 
                      />
                      <button onClick={loadTrends} className="bg-gray-800 hover:bg-gray-700 w-24 h-20 rounded-3xl text-white font-black transition-all border border-gray-700 flex flex-col items-center justify-center gap-1 flex-shrink-0 group">
                        <span className="text-xl group-hover:scale-125 transition-transform">🔭</span>
                        <span className="text-[10px] uppercase tracking-tighter">靈感</span>
                      </button>
                  </div>

                  {isLoadingTrends ? (
                      <div className="flex justify-center py-10 bg-dark/30 rounded-3xl border border-dashed border-gray-800 animate-pulse">
                          <div className="loader !w-8 !h-8 !border-t-primary"></div>
                      </div>
                  ) : trendingTopics.length > 0 && (
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-80 overflow-y-auto p-4 border border-gray-800 rounded-3xl bg-dark/40 custom-scrollbar shadow-inner">
                          {trendingTopics.map((t, i) => (
                              <div key={i} onClick={() => handleNext(t.title)} className="bg-dark/60 border border-gray-800 p-5 rounded-2xl cursor-pointer hover:border-primary/50 transition-all group flex flex-col gap-1">
                                  <h4 className="font-black text-blue-400 text-sm tracking-tight line-clamp-1 group-hover:text-white">{t.title}</h4>
                                  <p className="text-[11px] text-gray-500 font-medium line-clamp-1">{t.description}</p>
                              </div>
                          ))}
                      </div>
                  )}
              </div>

              <button 
                  onClick={() => handleNext()} 
                  disabled={!topic} 
                  className={`w-full h-20 rounded-3xl font-black text-white shadow-2xl disabled:opacity-30 text-xl tracking-[0.2em] uppercase transition-all transform active:scale-95 flex items-center justify-center gap-4 ${mode === 'viral' ? 'bg-orange-600 hover:bg-orange-500 shadow-orange-900/20' : 'bg-primary hover:bg-blue-600 shadow-primary/20'}`}
              >
                  <span>立即生成文案</span>
                  <span className="bg-black/20 px-4 py-1.5 rounded-full text-xs font-bold tracking-widest">- 2 點</span>
              </button>
          </div>
      </div>
  );

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-10 animate-fade-in pt-8 pb-24">
        <div className="space-y-8">
            <div className="bg-card p-10 rounded-[40px] border border-gray-800 shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-blue-600 to-indigo-700"></div>
                <div className="flex justify-between items-center mb-8">
                    <div className="space-y-1">
                        <h3 className="font-black text-white tracking-tighter uppercase text-lg">內容編輯工作區</h3>
                        <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">Editing Workspace</p>
                    </div>
                    <button onClick={() => setStep(1)} className="px-4 py-2 bg-red-900/10 text-red-400 rounded-xl text-[10px] font-black uppercase tracking-widest border border-red-500/20 hover:bg-red-500 hover:text-white transition-all">← 重選話題</button>
                </div>

                <textarea 
                    value={draft.caption} 
                    onChange={e => setDraft({...draft, caption: e.target.value})} 
                    className="w-full h-[480px] bg-dark/50 border border-gray-800 rounded-3xl p-8 text-white mb-8 resize-none focus:border-primary outline-none custom-scrollbar leading-relaxed font-sans text-[15px]" 
                />

                <button 
                    onClick={handleGenMedia} 
                    className={`w-full h-16 rounded-2xl font-black text-white shadow-xl transition-all flex items-center justify-center gap-4 tracking-widest uppercase transform active:scale-[0.98] ${mediaUrl ? 'bg-indigo-900/40 border border-indigo-500/30 text-indigo-200' : 'bg-indigo-600 hover:bg-indigo-500'}`}
                >
                    <span>{mediaUrl ? "重新生成視覺素材" : "生成 AI 視覺素材"}</span>
                    <span className="bg-black/20 px-3 py-1 rounded-lg text-[10px] font-bold">-{mediaUrl ? '2' : '5'} 點</span>
                </button>
            </div>
        </div>

        <div className="space-y-8">
            <div className="bg-card p-10 rounded-[40px] border border-gray-800 shadow-2xl flex flex-col min-h-[700px] relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-green-500 to-blue-500"></div>
                <div className="mb-8">
                    <h3 className="font-black text-white tracking-tighter uppercase text-lg">Facebook 貼文預覽</h3>
                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">Live Desktop Preview</p>
                </div>

                <div className="bg-white rounded-3xl overflow-hidden flex-1 border border-gray-200 shadow-inner flex flex-col">
                    <div className="p-5 border-b flex items-center gap-4">
                        <div className="w-12 h-12 rounded-full bg-blue-600 flex items-center justify-center text-white font-black shadow-lg">FB</div>
                        <div className="space-y-1.5">
                            <div className="h-3 w-40 bg-gray-200 rounded-full"></div>
                            <div className="h-2 w-24 bg-gray-100 rounded-full"></div>
                        </div>
                    </div>
                    <div className="p-6 overflow-y-auto max-h-[550px] flex-1 custom-scrollbar">
                        <p className="text-black text-[15px] whitespace-pre-wrap mb-6 leading-relaxed font-sans">{draft.caption}</p>
                        {mediaUrl && <img src={mediaUrl} className="w-full h-auto rounded-2xl shadow-2xl border border-gray-100" alt="AI Generated" />}
                    </div>
                </div>

                {publishResult ? (
                    <div className={`mt-8 p-6 rounded-3xl text-center font-black border transition-all animate-bounce-subtle ${publishResult.success ? 'bg-green-500/10 text-green-500 border-green-500/20' : 'bg-red-500/10 text-red-500 border-red-500/20'}`}>
                        {publishResult.msg}
                        <button onClick={() => setPublishResult(null)} className="block mx-auto mt-2 text-[10px] uppercase font-black tracking-widest text-white/40 hover:text-white underline decoration-dashed">關閉提示</button>
                    </div>
                ) : (
                    <div className="mt-8">
                        <button 
                            onClick={handleFinalize} 
                            disabled={isLimitReached} 
                            className={`w-full h-20 bg-primary text-white rounded-3xl font-black shadow-2xl hover:bg-blue-600 transition-all text-lg uppercase tracking-[0.2em] transform active:scale-95 shadow-primary/20 ${isLimitReached ? 'opacity-50 cursor-not-allowed grayscale' : ''}`}
                        >
                            {isLimitReached ? "排程儲存空間已滿" : "立即發佈至專頁"}
                        </button>
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

