import React, { useState, useEffect } from 'react';
import { 
  getAllUsers, updateUserRole, getDashboardStats, 
  toggleUserSuspension, manualUpdateQuota, getUserReports, resetUserQuota
} from '../services/authService';
import { db, isMock } from '../services/firebase';
import { UserProfile, UserRole, DashboardStats, UserReport } from '../types';

interface Props {
  currentUser: UserProfile;
}

const AdminPanel: React.FC<Props> = ({ currentUser }) => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'users' | 'api_monitor' | 'reports'>('dashboard');
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [reports, setReports] = useState<UserReport[]>([]);
  const [apiUsage, setApiUsage] = useState<any>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    loadData();
  }, [activeTab]);

  const loadData = async () => {
    setLoading(true);
    if (activeTab === 'dashboard') setStats(await getDashboardStats());
    if (activeTab === 'users') setUsers(await getAllUsers());
    if (activeTab === 'reports') setReports(await getUserReports());
    if (activeTab === 'api_monitor') loadApiUsage();
    setLoading(false);
  };

  const loadApiUsage = async () => {
      if (isMock) {
          setApiUsage({ key_1: 450, key_2: 120, key_3: 0, key_4: 0, key_5: 0, total_calls: 570 });
          return;
      }
      try {
          const doc = await db.collection('system_stats').doc('api_usage').get();
          if (doc.exists) setApiUsage(doc.data());
      } catch (e) { console.error("Load API Usage failed", e); }
  };

  const handleEditQuota = async (u: UserProfile) => {
      const newUsed = prompt(`修改 [${u.email}] 的已用配額 (目前: ${u.quota_used})`, u.quota_used.toString());
      if (newUsed === null) return;
      const newTotal = prompt(`修改 [${u.email}] 的配額總量 (目前: ${u.quota_total})`, u.quota_total.toString());
      if (newTotal === null) return;

      const used = parseInt(newUsed);
      const total = parseInt(newTotal);
      if (!isNaN(used) && !isNaN(total)) {
          await manualUpdateQuota(u.user_id, used, total);
          loadData();
      }
