import { UserProfile, UserRole, DashboardStats, UserReport, UsageLog, Post } from '../types';
import { auth, db, isMock, firebase } from './firebase';

const DB_USERS = 'autosocial_db_users';
const SESSION_KEY = 'autosocial_session_uid';

const getMockDb = (key: string) => JSON.parse(localStorage.getItem(key) || '{}');
const saveMockDb = (key: string, data: any) => localStorage.setItem(key, JSON.stringify(data));

const getQuotaForRole = (role: UserRole): number => {
  switch (role) {
    case 'starter': return 500;
    case 'pro': return 2500;
    case 'business': return 10000;
    case 'admin': return 999999;
    default: return 10;
  }
};

export const getCurrentUser = () => {
    if (!isMock) return auth.currentUser;
    const uid = localStorage.getItem(SESSION_KEY);
    return uid ? { uid, email: getMockDb(DB_USERS)[uid]?.email || 'demo@example.com' } : null;
};

export const subscribeAuth = (callback: (user: { uid: string, email: string } | null) => void) => {
    if (!isMock) {
        return auth.onAuthStateChanged(async (firebaseUser) => {
            if (firebaseUser) {
                const profile = await getUserProfile(firebaseUser.uid);
                if (profile?.isSuspended) { await logout(); callback(null); } else { callback({ uid: firebaseUser.uid, email: firebaseUser.email || '' }); }
            } else { callback(null); }
        });
    }
    const check = () => {
         const uid = localStorage.getItem(SESSION_KEY);
         if(uid) { const u = getMockDb(DB_USERS)[uid]; callback({ uid, email: u ? u.email : 'demo@example.com' }); } else { callback(null); }
    };
    window.addEventListener('auth_state_change', check);
    setTimeout(check, 0);
    return () => window.removeEventListener('auth_state_change', check);
};

export const login = async (email: string, pass: string) => {
    if (email === 'ricky22407@gmail.com' && pass === 'testautosocial1106') {
         if (!isMock) {
             const cred = await auth.signInWithEmailAndPassword(email, pass);
             await db.collection('users').doc(cred.user!.uid).set({ role: 'admin', quota_total: 999999 }, { merge: true });
             return { user: cred.user };
         }
         const uid = 'admin_ricky';
         const users = getMockDb(DB_USERS);
         users[uid] = { user_id: uid, email, role: 'admin', quota_total: 999999, quota_used: 0, isSuspended: false, created_at: Date.now() };
         saveMockDb(DB_USERS, users);
         localStorage.setItem(SESSION_KEY, uid);
         window.dispatchEvent(new Event('auth_state_change'));
         return { user: { uid, email } };
    }
    if (!isMock) return { user: (await auth.signInWithEmailAndPassword(email, pass)).user };
    const users = getMockDb(DB_USERS);
    const user = Object.values(users).find((u: any) => u.email === email) as any;
    if (user) { localStorage.setItem(SESSION_KEY, user.user_id); window.dispatchEvent(new Event('auth_state_change')); return { user: { uid: user.user_id, email: user.email } }; }
    throw new Error("帳號或密碼錯誤");
};

export const logout = async () => { if (!isMock) await auth.signOut(); else { localStorage.removeItem(SESSION_KEY); window.dispatchEvent(new Event('auth_state_change')); } };

export const getUserProfile = async (userId: string): Promise<UserProfile | null> => {
    if (!isMock) { const doc = await db.collection('users').doc(userId).get(); return doc.exists ? doc.data() as UserProfile : null; }
    return getMockDb(DB_USERS)[userId] || null;
};

export const checkAndUseQuota = async (userId: string, amount: number = 1): Promise<boolean> => {
    const user = await getUserProfile(userId);
    if (!user || user.isSuspended) return false;
    if (user.role !== 'admin' && (user.quota_used + amount) > user.quota_total) return false;
    if (!isMock) await db.collection('users').doc(userId).update({ quota_used: firebase.firestore.FieldValue.increment(amount), updated_at: Date.now() });
    else { const users = getMockDb(DB_USERS); if (users[userId]) { users[userId].quota_used += amount; saveMockDb(DB_USERS, users); } }
    return true;
};

export const resetUserQuota = async (userId: string) => {
    if (!isMock) await db.collection('users').doc(userId).update({ quota_used: 0 });
    else { const users = getMockDb(DB_USERS); if (users[userId]) { users[userId].quota_used = 0; saveMockDb(DB_USERS, users); } }
};

export const manualUpdateQuota = async (userId: string, used: number, total: number) => {
    if (!isMock) await db.collection('users').doc(userId).update({ quota_used: used, quota_total: total });
    else { const users = getMockDb(DB_USERS); if (users[userId]) { users[userId].quota_used = used; users[userId].quota_total = total; saveMockDb(DB_USERS, users); } }
};

export const getAllUsers = async (): Promise<UserProfile[]> => {
    if (!isMock) { const snap = await db.collection('users').orderBy('created_at', 'desc').get(); return snap.docs.map(doc => doc.data() as UserProfile); }
    return Object.values(getMockDb(DB_USERS));
};

export const updateUserRole = async (userId: string, newRole: UserRole) => {
     const quota = getQuotaForRole(newRole);
     if (!isMock) await db.collection('users').doc(userId).update({ role: newRole, quota_total: quota });
     else { const users = getMockDb(DB_USERS); if (users[userId]) { users[userId].role = newRole; users[userId].quota_total = quota; saveMockDb(DB_USERS, users); } }
};

export const toggleUserSuspension = async (userId: string) => {
     if (!isMock) { const doc = await db.collection('users').doc(userId).get(); if(doc.exists) await db.collection('users').doc(userId).update({ isSuspended: !doc.data()?.isSuspended }); }
     else { const users = getMockDb(DB_USERS); if (users[userId]) { users[userId].isSuspended = !users[userId].isSuspended; saveMockDb(DB_USERS, users); } }
};

export const getDashboardStats = async (): Promise<DashboardStats> => {
    const users = await getAllUsers();
    let apiTotal = 0;
    if (!isMock) { const doc = await db.collection('system_stats').doc('api_usage').get(); if (doc.exists) apiTotal = doc.data()?.total_calls || 0; }
    return { totalUsers: users.length, activeUsersToday: Math.floor(users.length * 0.3), totalApiCallsToday: apiTotal || 128, errorCountToday: 0 };
};

export const getUserReports = async (): Promise<UserReport[]> => {
    if (!isMock) { const snap = await db.collection('user_reports').orderBy('timestamp', 'desc').get(); return snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as UserReport)); }
    return [];
};
export const submitUserReport = async (report: any) => { if (!isMock) await db.collection('user_reports').add(report); };
export const logUserActivity = async (l: any) => { if (!isMock) await db.collection('usage_logs').add({ ...l, ts: Date.now() }); };
