                                      </div>
                                  </td>
                                  <td className="p-6">
                                      <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${u.isSuspended ? 'bg-red-500/10 text-red-500' : 'bg-green-500/10 text-green-500'}`}>
