                                      <button onClick={() => toggleUserSuspension(u.user_id).then(loadData)} className="px-4 py-2 bg-red-900/10 text-red-400 rounded-xl text-[10px] font-black hover:bg-red-600 hover:text-white">{u.isSuspended ? '解封' : '封鎖'}</button>
                                      <button onClick={() => handleDeleteUser(u)} className="px-4 py-2 bg-red-600 text-white rounded-xl text-[10px] font-black">刪除</button>
                                  </td>
                              </tr>
                          ))}
                      </tbody>
                  </table>
              </div>
          </div>
      )}

      {activeTab === 'keys' && (
          <div className="bg-card p-10 rounded-3xl border border-gray-800 shadow-2xl space-y-8">
              <h3 className="text-2xl font-black text-white uppercase tracking-tighter">🔑 系統管理金鑰生成</h3>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  <button onClick={() => handleGenerateKey('RESET_QUOTA')} className="p-6 bg-blue-900/20 border border-blue-500 text-blue-400 rounded-2xl font-black hover:bg-blue-500 hover:text-white transition-all">生成「重置配額」金鑰</button>
                  <button onClick={() => handleGenerateKey('UPGRADE_ROLE', 'pro')} className="p-6 bg-purple-900/20 border border-purple-500 text-purple-400 rounded-2xl font-black hover:bg-purple-500 hover:text-white transition-all">生成「升級 PRO」金鑰</button>
                  <button onClick={() => handleGenerateKey('UPGRADE_ROLE', 'business')} className="p-6 bg-yellow-900/20 border border-yellow-500 text-yellow-400 rounded-2xl font-black hover:bg-yellow-500 hover:text-white transition-all">生成「升級 Business」金鑰</button>
