              {generatedKey && (
                  <div className="p-8 bg-dark/60 border border-primary rounded-3xl text-center">
                      <p className="text-xs text-gray-500 font-bold mb-2">生成成功！金鑰 10 分鐘內有效：</p>
                      <p className="text-3xl font-mono font-black text-white tracking-widest">{generatedKey}</p>
