              <h3 className="text-2xl font-black text-white uppercase tracking-tighter mb-10">🔌 API 負載平衡監控 (Slot 01-05)</h3>
              <div className="grid grid-cols-2 md:grid-cols-5 gap-8 text-center">
                  {[1, 2, 3, 4, 5].map(idx => {
                      const count = apiUsage[`key_${idx}`] || 0;
                      const percent = Math.min(100, (count / 1500) * 100);
                      return (
                          <div key={idx} className="space-y-4">
                              <div className="relative w-28 h-28 mx-auto">
