// Add useAdminKey export
export const useAdminKey = async (userId: string, key: string) => {
    if (!isMock) {
        const keyRef = db.collection('admin_keys').doc(key);
        const userRef = db.collection('users').doc(userId);

        return await db.runTransaction(async (transaction) => {
            const kDoc = await transaction.get(keyRef);
            if (!kDoc.exists) throw new Error("無效的金鑰");
            const kData = kDoc.data();
            if (kData?.isUsed) throw new Error("此金鑰已被使用");
            if (Date.now() > kData?.expiresAt) throw new Error("此金鑰已過期");

            const uDoc = await transaction.get(userRef);
            if (!uDoc.exists) throw new Error("找不到使用者");

            if (kData?.type === 'RESET_QUOTA') {
                transaction.update(userRef, { quota_used: 0 });
            } else if (kData?.type === 'UPGRADE_ROLE') {
                const newRole = kData.targetRole as UserRole;
                transaction.update(userRef, { role: newRole, quota_total: getQuotaForRole(newRole) });
            }

            transaction.update(keyRef, { isUsed: true, usedBy: userId });
            return { success: true };
        });
    } else {
        const keys = getMockDb('autosocial_keys');
        const kData = keys[key];
        if (!kData || kData.isUsed) throw new Error("金鑰無效或已使用");
        const users = getMockDb(DB_USERS);
        if (kData.type === 'RESET_QUOTA') users[userId].quota_used = 0;
        else if (kData.type === 'UPGRADE_ROLE') {
            users[userId].role = kData.targetRole;
            users[userId].quota_total = getQuotaForRole(kData.targetRole);
        }
        kData.isUsed = true;
        saveMockDb('autosocial_keys', keys);
        saveMockDb(DB_USERS, users);
        return { success: true };
    }
};

// Add redeemReferralCode export
export const redeemReferralCode = async (userId: string, code: string) => {
    if (!isMock) {
        const q = await db.collection('users').where('referralCode', '==', code).get();
        if (q.empty) throw new Error("查無此邀請碼");
        const referrer = q.docs[0];
        const referrerId = referrer.id;

        const userRef = db.collection('users').doc(userId);
        const userDoc = await userRef.get();
        const userData = userDoc.data();

        if (userData?.referredBy) throw new Error("您已領取過推薦獎勵");
        if (referrerId === userId) throw new Error("不能使用自己的邀請碼");

        await db.runTransaction(async (t) => {
            t.update(userRef, { 
                referredBy: code, 
                quota_total: firebase.firestore.FieldValue.increment(50), 
                updated_at: Date.now() 
            });
            t.update(referrer.ref, { 
                referralCount: firebase.firestore.FieldValue.increment(1),
                quota_total: firebase.firestore.FieldValue.increment(50)
            });
        });
        return { reward: 50 };
    } else {
        const users = getMockDb(DB_USERS);
        const referrer = Object.values(users).find((u: any) => u.referralCode === code) as any;
        if (!referrer) throw new Error("無效邀請碼");
        if (users[userId].referredBy) throw new Error("已領取過獎勵");
        users[userId].referredBy = code;
        users[userId].quota_total += 50;
        referrer.referralCount = (referrer.referralCount || 0) + 1;
        referrer.quota_total += 50;
        saveMockDb(DB_USERS, users);
        return { reward: 50 };
    }
};

