        <button onClick={() => setActiveTab('api_monitor')} className={`px-6 py-3 font-bold whitespace-nowrap ${activeTab === 'api_monitor' ? 'text-green-400 border-b-2 border-green-400' : 'text-gray-400 hover:text-white'}`}>🔌 API 流量監控</button>
        <button onClick={() => setActiveTab('reports')} className={`px-6 py-3 font-bold whitespace-nowrap ${activeTab === 'reports' ? 'text-primary border-b-2 border-primary' : 'text-gray-400 hover:text-white'}`}>🚨 問題回報</button>
        <button onClick={() => setActiveTab('system')} className={`px-6 py-3 font-bold whitespace-nowrap ${activeTab === 'system' ? 'text-primary border-b-2 border-primary' : 'text-gray-400 hover:text-white'}`}>🛠 系統設定</button>
      </div>

      {/* VIEW: DASHBOARD */}
      {activeTab === 'dashboard' && stats && (
        <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div className="bg-card p-6 rounded-xl border border-gray-700">
                    <p className="text-gray-400 text-sm">總會員數</p>
                    <p className="text-3xl font-bold text-white mt-2">{stats.totalUsers}</p>
