            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-card p-6 rounded-xl border border-gray-700">
                    <h3 className="text-xl font-bold text-white mb-4">🔑 方案升級金鑰 (Upgrade Key)</h3>
                    <div className="flex flex-wrap gap-2 mb-4">
                         <button onClick={() => handleGenerateKey('UPGRADE_ROLE', 'starter')} className="bg-green-700 hover:bg-green-600 text-white px-4 py-2 rounded font-bold">Starter</button>
                         <button onClick={() => handleGenerateKey('UPGRADE_ROLE', 'pro')} className="bg-purple-700 hover:bg-purple-600 text-white px-4 py-2 rounded font-bold">Pro</button>
                         <button onClick={() => handleGenerateKey('UPGRADE_ROLE', 'business')} className="bg-yellow-700 hover:bg-yellow-600 text-white px-4 py-2 rounded font-bold">Business</button>
                         <button onClick={() => handleGenerateKey('RESET_QUOTA')} className="bg-gray-700 hover:bg-gray-600 text-white px-4 py-2 rounded font-bold">重置配額</button>
                    </div>
                    {generatedKey && (
                        <div className="mt-4 p-3 bg-black/30 border border-green-500 rounded text-green-400 font-mono text-center select-all">
                            {generatedKey}
                        </div>
                    )}
                </div>
                <div className="bg-card p-6 rounded-xl border border-gray-700 overflow-y-auto max-h-[300px]">
                    <h3 className="text-xl font-bold text-white mb-4">📝 最近系統日誌</h3>
                    <ul className="space-y-2 text-xs">
                        {logs.slice(0, 10).map(log => (
                            <li key={log.id} className="border-b border-gray-800 pb-1">
                                <span className="text-gray-500">{new Date(log.timestamp).toLocaleTimeString()}</span>
                                <span className={`mx-2 font-bold ${log.status === 'error' ? 'text-red-400' : log.status === 'warning' ? 'text-yellow-400' : 'text-green-400'}`}>[{log.status.toUpperCase()}]</span>
                                <span className="text-gray-300">{log.action}: {log.details}</span>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
        </div>
      )}

      {/* VIEW: API MONITOR */}
      {activeTab === 'api_monitor' && (
          <div className="space-y-6">
              <div className="bg-card p-8 rounded-xl border border-gray-700 shadow-2xl">
                  <div className="flex justify-between items-end mb-8 border-b border-gray-700 pb-4">
