                          <UsageRing count={apiUsage.key_2 || 0} max={2000} label="Slot 02 (Sec)" color="#10b981" />
                          <UsageRing count={apiUsage.key_3 || 0} max={2000} label="Slot 03 (Bak)" color="#8b5cf6" />
                          <UsageRing count={apiUsage.key_4 || 0} max={2000} label="Slot 04 (Res)" color="#f59e0b" />
                          <UsageRing count={apiUsage.key_5 || 0} max={2000} label="Slot 05 (Emg)" color="#ef4444" />
                      </div>
                  ) : (
                      <div className="text-center py-20 text-gray-500 animate-pulse">
