                            <th className="p-4">角色權限</th>
                            <th className="p-4">配額 (已用 / 總量)</th>
                            <th className="p-4">狀態</th>
                            <th className="p-4 text-right">操作</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-800">
                        {filteredUsers.map(user => (
                            <tr key={user.user_id} className="hover:bg-gray-800/50 transition-colors">
                                <td className="p-4">
                                    <div className="font-bold text-white">{user.email}</div>
                                    <div className="text-xs text-gray-500 font-mono">{user.user_id}</div>
                                </td>
                                <td className="p-4">
                                    <select 
                                        value={user.role} 
                                        onChange={(e) => handleRoleChange(user.user_id, e.target.value as UserRole)}
                                        className={`bg-dark border border-gray-600 rounded px-2 py-1 text-xs text-white ${user.role === 'admin' ? 'text-red-400 font-bold' : user.role === 'business' ? 'text-yellow-400 font-bold' : ''}`}
                                    >
                                        <option value="user">User</option>
                                        <option value="starter">Starter</option>
                                        <option value="pro">Pro</option>
                                        <option value="business">Business</option>
                                        <option value="admin">Admin</option>
                                    </select>
                                </td>
                                <td className="p-4">
                                    {editingQuotaId === user.user_id ? (
                                        <div className="flex items-center gap-2 text-sm">
                                            <input type="number" value={editUsed} onChange={e => setEditUsed(parseInt(e.target.value))} className="w-16 bg-dark border border-gray-600 rounded px-1 text-white text-center" />
                                            <span className="text-gray-400">/</span>
                                            <input type="number" value={editTotal} onChange={e => setEditTotal(parseInt(e.target.value))} className="w-16 bg-dark border border-gray-600 rounded px-1 text-white text-center" />
                                            <button onClick={() => handleManualQuotaSave(user.user_id)} className="text-green-400 text-xs ml-1">💾</button>
                                            <button onClick={() => setEditingQuotaId(null)} className="text-red-400 text-xs">❌</button>
                                        </div>
                                    ) : (
                                        <div className="flex items-center gap-2">
                                            <span className={`${user.quota_used >= user.quota_total ? 'text-red-400 font-bold' : 'text-white'}`}>{user.quota_used}</span>
                                            <span className="text-gray-500">/</span>
                                            <span className="text-white">{user.quota_total}</span>
                                            <button onClick={() => { setEditingQuotaId(user.user_id); setEditUsed(user.quota_used); setEditTotal(user.quota_total); }} className="text-gray-500 hover:text-blue-400 text-xs ml-2">✎</button>
                                        </div>
                                    )}
                                </td>
                                <td className="p-4">
                                    {user.isSuspended ? <span className="bg-red-900 text-red-200 px-2 py-1 rounded text-xs font-bold">已停用</span> : <span className="bg-green-900 text-green-200 px-2 py-1 rounded text-xs">正常</span>}
                                </td>
                                <td className="p-4 text-right flex gap-2 justify-end">
                                    <button onClick={() => setSecurityTarget({uid: user.user_id, type: 'DOWNLOAD'})} className="text-xs bg-blue-900/50 text-blue-200 px-2 py-1 rounded hover:bg-blue-900 border border-blue-800">📥</button>
                                    <button onClick={() => setSecurityTarget({uid: user.user_id, type: 'DELETE'})} className="text-xs bg-red-900/50 text-red-200 px-2 py-1 rounded hover:bg-red-900 border border-red-800">🗑️</button>
                                    <button onClick={() => handleToggleSuspend(user.user_id, user.isSuspended)} className={`px-3 py-1 rounded text-xs border ${user.isSuspended ? 'border-green-600 text-green-400 hover:bg-green-900' : 'border-red-600 text-red-400 hover:bg-red-900'}`}>{user.isSuspended ? '啟用' : '停用'}</button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
      )}

      {/* VIEW: REPORTS */}
      {activeTab === 'reports' && (
          <div className="bg-card p-6 rounded-xl border border-gray-700">
              <div className="flex justify-between items-center mb-4">
                  <h3 className="text-xl font-bold text-white">🚨 用戶問題回報 ({reports.length})</h3>
                  <button onClick={loadAllData} className="text-sm text-primary hover:underline">刷新</button>
              </div>
              {reports.length === 0 ? <div className="text-center py-10 text-gray-500 border border-dashed border-gray-700 rounded">目前無待處理的回報單。</div> : (
                  <div className="space-y-4">
                      {reports.map((report) => (
                          <div key={report.id} className="bg-dark p-4 rounded border border-gray-600">
                              <div className="flex justify-between items-start mb-2">
                                  <div><span className="font-bold text-white">{report.userEmail}</span><span className="text-xs text-gray-500 ml-2">{new Date(report.timestamp).toLocaleString()}</span></div>
                                  <span className="text-xs bg-red-900 text-red-200 px-2 py-1 rounded">{report.status}</span>
                              </div>
                              <div className="bg-gray-800 p-3 rounded text-sm text-gray-200 mb-2">{report.description}</div>
                              <div className="text-xs text-gray-500 font-mono break-all bg-black/20 p-2 rounded"><div>View: {report.currentView}</div><div>UA: {report.userAgent}</div></div>
                          </div>
                      ))}
                  </div>
              )}
          </div>
      )}

      {/* VIEW: SYSTEM */}
      {activeTab === 'system' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              <div className="space-y-6">
                  <div className="bg-card p-6 rounded-xl border border-gray-700">
                      <h3 className="text-xl font-bold text-white mb-4">🔧 系統全域設定</h3>
                      <div className="space-y-4">
                          <div className="flex items-center justify-between p-4 bg-dark rounded border border-gray-600">
                              <div><div className="font-bold text-white">🧪 Dry Run 模擬模式</div><div className="text-xs text-gray-400">開啟後，不扣除真實配額，不連接外部 API。</div></div>
                              <button onClick={toggleDryRun} className={`w-12 h-6 rounded-full transition-colors relative ${config.dryRunMode ? 'bg-yellow-500' : 'bg-gray-600'}`}><div className={`absolute top-1 left-1 bg-white w-4 h-4 rounded-full transition-transform ${config.dryRunMode ? 'translate-x-6' : ''}`}></div></button>
                          </div>
                          <div className="flex items-center justify-between p-4 bg-dark rounded border border-gray-600">
                              <div><div className="font-bold text-white">🚧 系統維護模式</div><div className="text-xs text-gray-400">開啟後，一般用戶無法登入。</div></div>
                              <button onClick={toggleMaintenance} className={`w-12 h-6 rounded-full transition-colors relative ${config.maintenanceMode ? 'bg-red-500' : 'bg-gray-600'}`}><div className={`absolute top-1 left-1 bg-white w-4 h-4 rounded-full transition-transform ${config.maintenanceMode ? 'translate-x-6' : ''}`}></div></button>
                          </div>
                      </div>
                  </div>
              </div>
              <div className="bg-card p-6 rounded-xl border border-gray-700 flex flex-col h-[500px]">
                  <div className="flex justify-between items-center mb-4"><h3 className="text-xl font-bold text-white">📜 完整錯誤日誌</h3><button onClick={loadAllData} className="text-sm text-primary hover:underline">刷新</button></div>
                  <div className="flex-1 overflow-y-auto bg-dark p-2 rounded border border-gray-800 font-mono text-xs">
                      {logs.map(log => (
                          <div key={log.id} className="mb-2 pb-2 border-b border-gray-800 last:border-0">
                              <div className="flex gap-2 mb-1"><span className="text-gray-500">{new Date(log.timestamp).toLocaleTimeString()}</span><span className={`font-bold ${log.status === 'error' ? 'text-red-500' : log.status === 'warning' ? 'text-yellow-500' : 'text-green-500'}`}>[{log.status.toUpperCase()}]</span><span className="text-blue-400">{log.action}</span></div>
