                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {securityTarget && (
          <SecurityActionModal targetUserId={securityTarget.uid} actionType={securityTarget.type} onClose={() => setSecurityTarget(null)} />
      )}
    </div>
  );
};

