const buildCtaPrompt = (ctaList: CtaItem[]) => {
    if (!ctaList || ctaList.length === 0) return "無特定 CTA";
    let prompt = "必須包含以下行動呼籲 (CTA) 資訊，請將其整理成吸引人的語句 (不要只放連結)：\n";
    ctaList.forEach(cta => {
        prompt += `- ${cta.text}: ${cta.url}\n`;
