export const getTrendingTopics = async (industry: string = "台灣熱門時事", requestedCount: number = 10): Promise<TrendingTopic[]> => {
  // 1. Check existing cache
  let cached = await checkTrendCache(industry) || [];

  // 2. Logic: If cache has enough, return it. If not, generate bypass content.
  if (cached.length >= requestedCount) {
      console.log(`[Trend] Cache hit sufficient (${cached.length} items).`);
      return shuffleArray(cached).slice(0, requestedCount);
  }

  // 3. Fallback/Augmentation Needed
  // First, try basic RSS fetch if cache was empty
  let fetchedTopics: TrendingTopic[] = [];
  if (cached.length === 0) {
      fetchedTopics = await fetchRealtimeRss(industry);
  }

  // Combine fetched with cache (simple dedup by title)
  let combined = [...cached, ...fetchedTopics];
  const uniqueMap = new Map();
  combined.forEach(t => uniqueMap.set(t.title, t));
  combined = Array.from(uniqueMap.values());

  // 4. "Bypass & Generate" - If still not enough, force AI generation excluding existing titles
  const deficit = requestedCount - combined.length;
  if (deficit > 0) {
      console.log(`[Trend] Not enough topics (Have ${combined.length}, Need ${requestedCount}). Triggering AI generation...`);

      const existingTitles = combined.map(t => t.title).slice(0, 20).join(", ");

      try {
        const response = await callBackend('generateContent', {
            model: 'gemini-2.5-flash',
            contents: `Role: Trend Hunter.
            Task: Generate ${Math.max(5, deficit + 2)} NEW trending social media topics about "${industry}" in Taiwan.
            Constraint: DO NOT include these already known topics: [${existingTitles}].
            Output: Pure JSON Array of objects: [{ "title": "...", "description": "...", "url": "#" }]`,
            config: { responseMimeType: "application/json" }
        });

        const cleanText = cleanJsonText(response.text || '[]');
        let raw = JSON.parse(cleanText);
        if (Array.isArray(raw)) {
            const aiTopics = raw.map((t: any) => ({
                title: t.title,
                description: t.description || t.title,
                url: t.url || '#',
                imageUrl: undefined // AI generated topics usually don't have images unless specifically requested
            }));

            // Merge AI topics
            combined = [...combined, ...aiTopics];
        }
      } catch (e) { 
          console.error("Gemini bypass generation failed", e); 
      }
  }

  // 5. Final Dedup and Save Cache
  const finalMap = new Map();
  combined.forEach(t => finalMap.set(t.title, t));
  const finalTopics = Array.from(finalMap.values());

  if (finalTopics.length > 0) {
      await saveTrendCache(industry, finalTopics);
  }

  return shuffleArray(finalTopics).slice(0, requestedCount);
};

