// --- SVG Ring Component ---
const UsageRing = ({ count, max, label, color }: { count: number, max: number, label: string, color: string }) => {
    const radius = 36;
    const circumference = 2 * Math.PI * radius;
    const progress = Math.min(100, Math.max(0, (count / max) * 100));
    const offset = circumference - (progress / 100) * circumference;

    return (
        <div className="flex flex-col items-center">
            <div className="relative w-32 h-32">
                <svg className="transform -rotate-90 w-full h-full">
                    <circle 
                        cx="64" cy="64" r={radius} 
                        stroke="rgba(255,255,255,0.1)" strokeWidth="8" fill="transparent" 
                    />
                    <circle 
                        cx="64" cy="64" r={radius} 
                        stroke={color} strokeWidth="8" fill="transparent" 
                        strokeDasharray={circumference} 
                        strokeDashoffset={offset}
                        strokeLinecap="round"
                        className="transition-all duration-1000 ease-out"
                    />
                </svg>
                <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className="text-2xl font-black text-white">{count}</span>
                    <span className="text-[10px] text-gray-400">次調用</span>
                </div>
            </div>
            <p className="mt-2 text-xs font-bold text-gray-400 uppercase tracking-widest">{label}</p>
            <p className="text-[10px] text-gray-600 mt-1">{(progress).toFixed(1)}% Load</p>
        </div>
    );
};

