// Public Exports
// ==========================================

export const validateFacebookToken = async (token: string): Promise<{ 
    valid: boolean; 
    status: 'VALID' | 'INVALID' | 'PARTIAL'; 
    missingPermissions: string[]; 
    error?: string;
    debugInfo?: any;
}> => {
  if (!token || token.trim() === '') {
    return { valid: false, status: 'INVALID', missingPermissions: [], error: '請輸入 Token' };
  }

  const cleanToken = token.trim();

  try {
    // 步驟 1: 基礎身份與類型檢查
    // 請求 metadata=1 可以知道這個 Token 的類型 (User 或 Page)
    const meRes = await graphApi('me?fields=id,name,category', cleanToken);

    if (!meRes || !meRes.id) {
        return { valid: false, status: 'INVALID', missingPermissions: [], error: '無法識別身份' };
    }

    // 如果有 category 欄位，代表這是一個 Page Token
    const isPageToken = !!meRes.category;

    if (isPageToken) {
        // Page Token 通常不支援 /me/permissions，但具備發文能力
        return { 
            valid: true, 
            status: 'VALID', 
            missingPermissions: [], 
            debugInfo: { ...meRes, type: 'Page Token' } 
        };
    }

    // 步驟 2: 用戶 Token 權限檢查
    let missing: string[] = [];
    try {
        const permRes = await graphApi('me/permissions', cleanToken);
        const perms = permRes.data || [];

        const required = ['pages_manage_posts', 'pages_read_engagement'];
        const granted = perms
            .filter((p: any) => p.status === 'granted')
            .map((p: any) => p.permission);

        missing = required.filter(p => !granted.includes(p));
    } catch (permErr) {
        return {
            valid: true,
            status: 'PARTIAL',
            missingPermissions: ['無法讀取詳細權限清單'],
            debugInfo: meRes
        };
    }

    return { 
        valid: true, 
        status: missing.length === 0 ? 'VALID' : 'PARTIAL', 
        missingPermissions: missing,
        debugInfo: meRes
    };

  } catch (e: any) {
    let errorMsg = e.message || '連線失敗';
    if (e.code === 190) errorMsg = 'Token 已失效或已過期。';
    return { valid: false, status: 'INVALID', missingPermissions: [], error: errorMsg, debugInfo: e.fbError };
  }
};

export const publishPostToFacebook = async (
  pageId: string,
  token: string,
  message: string,
  mediaUrl?: string,
  firstComment?: string,
  syncInstagram?: boolean
): Promise<{ success: boolean; url?: string; error?: string }> => {
  if (!pageId || !token) return { success: false, error: '未設定 Page ID 或 Token' };

  try {
    let postId: string;
    const cleanToken = token.trim();

    if (mediaUrl) {
      const isBase64 = mediaUrl.startsWith('data:');
      const isVideo = mediaUrl.includes('.mp4') || mediaUrl.startsWith('data:video');

      if (isBase64) {
          const blob = await base64ToBlob(mediaUrl);
          const formData = new FormData();
          if (isVideo) {
              formData.append('description', message);
              formData.append('source', blob, 'video.mp4');
              const res = await graphApi(`${pageId}/videos`, cleanToken, 'POST', formData);
              postId = res.id;
          } else {
              formData.append('caption', message);
              formData.append('source', blob, 'image.png');
              const res = await graphApi(`${pageId}/photos`, cleanToken, 'POST', formData);
              postId = res.id || res.post_id;
          }
      } else {
          const endpoint = isVideo ? `${pageId}/videos` : `${pageId}/photos`;
          const payload: any = isVideo ? { description: message, file_url: mediaUrl } : { caption: message, url: mediaUrl };
          const res = await graphApi(endpoint, cleanToken, 'POST', payload);
          postId = res.id || res.post_id;
      }
    } else {
      const res = await graphApi(`${pageId}/feed`, cleanToken, 'POST', { message });
      postId = res.id;
    }

    if (firstComment && postId) {
      try { await graphApi(`${postId}/comments`, cleanToken, 'POST', { message: firstComment }); } catch (e) {}
    }

    return { success: true, url: `https://facebook.com/${postId}` };
  } catch (e: any) {
    return { success: false, error: e.message };
  }
};

export const fetchPageAnalytics = async (pageId: string, token?: string): Promise<AnalyticsData | null> => {
  if (!pageId || !token) return null; 
  const cleanToken = token.trim();
  try {
    const pageInfo = await graphApi(`${pageId}?fields=followers_count`, cleanToken);
    // 降級處理：如果 insights 無法讀取，給予 0
    let reach = 0;
    try {
        const reachData = await graphApi(`${pageId}/insights?metric=page_impressions_unique&period=days_28`, cleanToken);
        reach = reachData.data?.[0]?.values?.[0]?.value || 0;
    } catch (e) { console.warn("Analytics reach fetch failed", e); }

    return {
      followers: pageInfo.followers_count || 0,
      followersGrowth: 0,
      reach: reach,
      engagementRate: 0,
      period: '28天'
    };
  } catch (e) { throw e; }
};

export const fetchPageTopPosts = async (pageId: string, token: string): Promise<{ topReach?: TopPostData, topEngagement?: TopPostData }> => {
    const cleanToken = token.trim();
    try {
        // 簡化欄位請求，移除可能報錯的 insights 指標
        const fields = 'id,message,created_time,full_picture,permalink_url';
        const res = await graphApi(`${pageId}/feed?limit=15&fields=${fields}`, cleanToken);
        const posts = res.data || [];
        if (posts.length === 0) return {};
        const processed = posts.map((p: any) => ({
            id: p.id,
            message: p.message || '',
            imageUrl: p.full_picture,
            created_time: p.created_time,
            permalink_url: p.permalink_url,
            reach: 0,
            engagedUsers: 0
        }));
        return { topReach: processed[0] };
    } catch (e) { return {}; }
};

export const fetchRecentPostCaptions = async (pageId: string, token: string, limit = 20): Promise<string[]> => {
    const cleanToken = token.trim();
    const res = await graphApi(`${pageId}/feed?fields=message&limit=${limit}`, cleanToken);
    return (res.data || []).map((p: any) => p.message).filter(Boolean);
};

module.exports = async function (req, res) {
  // CORS Headers
  res.setHeader('Access-Control-Allow-Credentials', true);
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,OPTIONS,PATCH,DELETE,POST,PUT');
  res.setHeader(
    'Access-Control-Allow-Headers',
    'X-CSRF-Token, X-Requested-With, Accept, Accept-Version, Content-Length, Content-MD5, Content-Type, Date, X-Api-Version'
  );

  if (req.method === 'OPTIONS') {
    res.status(200).end();
    return;
  }

  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method Not Allowed' });
  }

  // Check body existence
  if (!req.body) {
      return res.status(400).json({ error: 'Missing Request Body' });
  }

  // --- Multi-Key Manager & Load Balancing Logic ---
  class KeyManager {
      constructor() {
          // Load Gemini keys from possible env vars
          this.geminiKeys = [
              process.env.API_KEY,
              process.env.API_KEY_2,
              process.env.API_KEY_3,
              process.env.API_KEY_4,
              process.env.API_KEY_5
          ].filter(k => k && k.length > 0 && k !== 'undefined'); 

          // Load OpenAI Key for Ultimate Fallback
          this.openAIKey = process.env.OPENAI_API_KEY;

          // RANDOM START INDEX (Load Balancing)
          // Instead of starting at 0, we start at a random index. 
          // This ensures that concurrent users hit different keys, preventing a bottleneck on Key #1.
          this.currentIndex = this.geminiKeys.length > 0 
              ? Math.floor(Math.random() * this.geminiKeys.length) 
              : 0;
      }

      getCurrentKey() {
          if (this.geminiKeys.length === 0) return null;
          return this.geminiKeys[this.currentIndex];
      }

      getCurrentKeySlotIndex() {
          return this.currentIndex + 1; // 1-based index for logging
      }

      getOpenAIKey() {
          return this.openAIKey;
      }

      // Check specifically which slots are configured (for UI monitoring)
      getKeyConfigStatus() {
          return [
              !!(process.env.API_KEY && process.env.API_KEY !== 'undefined'),
              !!(process.env.API_KEY_2 && process.env.API_KEY_2 !== 'undefined'),
              !!(process.env.API_KEY_3 && process.env.API_KEY_3 !== 'undefined'),
              !!(process.env.API_KEY_4 && process.env.API_KEY_4 !== 'undefined'),
              !!(process.env.API_KEY_5 && process.env.API_KEY_5 !== 'undefined')
          ];
      }

      switchToNextKey() {
          // Circular switching (Round Robin fallback)
          if (this.geminiKeys.length > 1) {
              const oldIndex = this.currentIndex;
              this.currentIndex = (this.currentIndex + 1) % this.geminiKeys.length;
              console.warn(`[KeyManager] ⚠️ Switching Key: Slot ${oldIndex + 1} -> Slot ${this.currentIndex + 1}`);
              return true;
          }
          return false;
      }
  }

  const keyManager = new KeyManager();
  const delay = (ms) => new Promise(resolve => setTimeout(resolve, ms));

  // Helper: OpenAI DALL-E 3 Generation (Fallback)
  async function generateOpenAIImage(prompt) {
      const apiKey = keyManager.getOpenAIKey();
      if (!apiKey) throw new Error("No OpenAI API Key provided for fallback.");

      console.log("[Fallback] Switching to OpenAI DALL-E 3...");
      const response = await fetch("https://api.openai.com/v1/images/generations", {
          method: "POST",
          headers: {
              "Content-Type": "application/json",
              "Authorization": `Bearer ${apiKey}`
          },
          body: JSON.stringify({
              model: "dall-e-3",
              prompt: prompt,
              n: 1,
              size: "1024x1024",
              response_format: "b64_json"
          })
      });

      const data = await response.json();
      if (data.error) throw new Error(`OpenAI Error: ${data.error.message}`);
      return data.data[0].b64_json;
  }

  // Retry Wrapper with Exponential Backoff & Key Rotation
  async function executeWithRetry(operation, retryCount = 0, keysTried = 1) {
      if (!keyManager.getCurrentKey()) {
          throw new Error("Server Configuration Error: API_KEY is missing in environment variables.");
      }

      // Max retries per key = 1 (Fast Failover). 
      // Max total keys tried = Total available keys.

      try {
          const apiKey = keyManager.getCurrentKey();

          // Dynamic Import SDK
          let GoogleGenAI;
          try {
              const sdk = await import("@google/genai");
              GoogleGenAI = sdk.GoogleGenAI;
          } catch (e) {
              throw new Error(`Failed to load @google/genai SDK: ${e.message}`);
          }

          const ai = new GoogleGenAI({ apiKey: apiKey });
          return await operation(ai);

      } catch (error) {
          const msg = error.message || '';
          console.warn(`[API Error Slot ${keyManager.getCurrentKeySlotIndex()}] ${msg}`);

          // Identify Quota/Overload Errors
          // 429: Too Many Requests, 503: Service Unavailable
          const isQuotaError = msg.includes('429') || msg.includes('Quota') || msg.includes('exhausted') || msg.includes('503') || msg.includes('403');

          if (isQuotaError) {
              // Strategy: If current key fails, try next key IMMEDIATELY without waiting too long.
              // We only wait if we have exhausted all keys.

              if (keysTried < keyManager.geminiKeys.length) {
                  // Switch to next available key
                  keyManager.switchToNextKey();
                  return executeWithRetry(operation, 0, keysTried + 1);
              } else {
                  // All keys exhausted. Now we wait and retry on current (last) key.
                  if (retryCount < 1) {
                      const waitTime = 2000;
                      console.warn(`[API] All keys exhausted. Waiting ${waitTime}ms to retry...`);
                      await delay(waitTime);
                      return executeWithRetry(operation, retryCount + 1, keysTried);
                  } else {
                      throw new Error("ALL_KEYS_EXHAUSTED");
                  }
              }
          } else {
              // Non-quota error (e.g. invalid prompt, filter), throw immediately
              throw error;
          }
      }
  }

  try {
    const { action, payload } = req.body;

    if (!action) {
        return res.status(400).json({ error: "Missing 'action' in request body" });
    }

    // --- Action: getServiceStatus (NEW) ---
    if (action === 'getServiceStatus') {
        const status = keyManager.getKeyConfigStatus();
        return res.status(200).json({ 
            keyStatus: status,
            totalConfigured: status.filter(s => s).length,
            hasOpenAI: !!keyManager.getOpenAIKey()
        });
    }

    // --- Action: fetchRss ---
    if (action === 'fetchRss') {
        const { url } = payload;
        try {
            const rssRes = await fetch(url);
            const text = await rssRes.text();
            return res.status(200).json({ text });
        } catch (rssError) {
            throw new Error(`Failed to fetch RSS: ${rssError.message}`);
        }
    }

    // --- Action: fetchOgImage ---
    else if (action === 'fetchOgImage') {
        const { url } = payload;
        try {
            const htmlRes = await fetch(url, {
                headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36' }
            });
            const html = await htmlRes.text();
            const match = html.match(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i);
            const ogImage = match ? match[1] : null;
            return res.status(200).json({ imageUrl: ogImage });
        } catch (e) {
            console.warn("OG Fetch failed", e);
            return res.status(200).json({ imageUrl: null });
        }
    }

    // --- Action: generateContent ---
    else if (action === 'generateContent') {
      const { model, contents, config } = payload;

      const runGeneration = async (currentModel) => {
          return await executeWithRetry(async (ai) => {
              const response = await ai.models.generateContent({ 
                  model: currentModel, 
                  contents, 
                  config 
              });
              return { text: response.text };
          });
      };

      try {
          const result = await runGeneration(model);
          return res.status(200).json(result);
      } catch (e) {
          // Gemini Fallback Logic for text
          if (model.includes('gemini-3-pro') || model.includes('gemini-1.5-pro')) {
              console.warn(`[API] ${model} failed. Downgrading to gemini-2.5-flash.`);
              try {
                  const fallbackResult = await runGeneration('gemini-2.5-flash');
                  return res.status(200).json(fallbackResult);
              } catch (fallbackError) {
                  throw e;
              }
          }
          throw e;
      }
    }

    // --- Action: generateImages ---
    else if (action === 'generateImages') {
      const { prompt, safetySettings } = payload;

      // Helper: Generate via generateContent
      const generateViaContent = async (ai, modelName) => {
          console.log(`[Image Gen] Attempting with ${modelName}...`);
          const response = await ai.models.generateContent({
              model: modelName,
              contents: { parts: [{ text: prompt }] },
              config: { 
                  imageConfig: { aspectRatio: "1:1" },
                  safetySettings: safetySettings 
              }
          });

          let b64 = null;
          if (response.candidates?.[0]?.content?.parts) {
            for (const part of response.candidates[0].content.parts) {
                if (part.inlineData && part.inlineData.data) {
                    b64 = part.inlineData.data;
                    break;
                }
            }
          }
          if (!b64) throw new Error(`No image data received from ${modelName}`);
          return { base64: b64 };
      };

      // Helper: Generate via generateImages
      const generateViaImagen = async (ai, modelName) => {
          console.log(`[Image Gen] Attempting with ${modelName}...`);
          const response = await ai.models.generateImages({
              model: modelName,
              prompt: prompt,
              config: { 
                  numberOfImages: 1,
                  aspectRatio: "1:1",
                  safetySettings: safetySettings 
              }
          });

          const imgBytes = response.generatedImages?.[0]?.image?.imageBytes;
          if (!imgBytes) throw new Error(`No image bytes received from ${modelName}`);
          return { base64: imgBytes };
      };

      // === WATERFALL STRATEGY ===
      // PRIORITY 1: Imagen 3.0
      try {
          const result = await executeWithRetry(async (ai) => {
              return await generateViaImagen(ai, 'imagen-3.0-generate-002');
          });
          return res.status(200).json(result);
      } catch (errorImagen3) {
          console.warn(`[Image Gen] Imagen 3.0 failed. Trying Gemini 2.5 Flash Image...`);

          // PRIORITY 2: Gemini 2.5 Flash Image
          try {
             const result = await executeWithRetry(async (ai) => {
                 return await generateViaContent(ai, 'gemini-2.5-flash-image');
             });
             return res.status(200).json(result);
          } catch (errorFlash) {
             console.warn(`[Image Gen] Gemini Flash failed. Checking OpenAI...`);

             // PRIORITY 3: OpenAI DALL-E 3
             if (keyManager.getOpenAIKey()) {
                 try {
                     const openAIBase64 = await generateOpenAIImage(prompt);
                     return res.status(200).json({ base64: openAIBase64 });
                 } catch (openAIError) {
                     return res.status(500).json({ error: "Backend Image Generation Failed (All Models Exhausted)." });
                 }
             } else {
                 return res.status(500).json({ error: "Backend Image Generation Failed (Gemini exhausted, no OpenAI key)." });
             }
          }
      }
    }

    // --- Action: generateVideos ---
    else if (action === 'generateVideos') {
       const { model, prompt, config } = payload;
       const result = await executeWithRetry(async (ai) => {
           let operation = await ai.models.generateVideos({ model, prompt, config });
           let attempts = 0;
           const maxAttempts = 20;
           while (!operation.done && attempts < maxAttempts) { 
               await delay(3000);
               operation = await ai.operations.getVideosOperation({ operation: operation });
               attempts++;
           }
           if (!operation.done) throw new Error("Video generation timed out.");
           const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
           if (!videoUri) throw new Error("No video URI returned");

           const currentKey = keyManager.getCurrentKey();
           const videoRes = await fetch(`${videoUri}&key=${currentKey}`);
           const arrayBuffer = await videoRes.arrayBuffer();
           const base64Video = Buffer.from(arrayBuffer).toString('base64');
           return { videoBase64: base64Video };
       });
       return res.status(200).json(result);
    }

    else {
        return res.status(400).json({ error: `Unknown action: ${action}` });
    }

  } catch (error) {
    console.error('[API Error]:', error);
    return res.status(500).json({ 
        error: error.message || 'Internal Server Error'
    });
  }
};

import { ThreadsAccount } from "../types";

const THREADS_API_BASE = 'https://graph.threads.net/v1.0';
const THREADS_GRAPH_BASE = 'https://graph.threads.net';

/**
 * Publishes a TEXT post to Threads.
 * Note: Threads API for Image/Video requires a public URL accessible by Meta's servers.
 */
export const publishThreadsPost = async (
  account: ThreadsAccount,
  text: string,
  imageUrl?: string,
  replyToId?: string // New: Optional param for replying
): Promise<{ success: boolean; id?: string; error?: string }> => {

  if (!account.userId || !account.token) {
    return { success: false, error: '帳號設定不完整 (缺 ID 或 Token)' };
  }

  try {
    // 1. Create Media Container
    const params = new URLSearchParams();
    params.append('access_token', account.token);
    params.append('text', text);

    // If replying, use the generic threads endpoint but with reply_to_id? 
    // Actually, for Threads API, creating a reply is the same as creating a thread, just adding reply_to_id usually in params or specific edge?
    // According to docs: POST /me/threads with 'reply_to_id' param.
    if (replyToId) {
        params.append('reply_to_id', replyToId);
    }

    let endpoint = `${THREADS_API_BASE}/${account.userId}/threads`;

    // Attempt Image if URL is public (http/https)
    // Note: DataURI (base64) is NOT supported by Threads API directly via URL param.
    // Threads strictly requires public URLs.
    if (imageUrl && (imageUrl.startsWith('http://') || imageUrl.startsWith('https://'))) {
        params.append('media_type', 'IMAGE');
        params.append('image_url', imageUrl);
    } else {
        params.append('media_type', 'TEXT');
    }

    const containerRes = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: params
    });

    const containerData = await containerRes.json();

    if (containerData.error) {
        throw new Error(`建立貼文容器失敗: ${containerData.error.message}`);
    }

    const creationId = containerData.id;

    // 2. Publish Media Container
    // POST /{user_id}/threads_publish
    // params: creation_id, access_token
    const publishParams = new URLSearchParams();
    publishParams.append('access_token', account.token);
    publishParams.append('creation_id', creationId);

    const publishRes = await fetch(`${THREADS_API_BASE}/${account.userId}/threads_publish`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: publishParams
    });

    const publishData = await publishRes.json();

    if (publishData.error) {
        throw new Error(`發佈貼文失敗: ${publishData.error.message}`);
    }

    return { success: true, id: publishData.id };

  } catch (e: any) {
    console.error("Threads API Error:", e);
    return { success: false, error: e.message };
  }
};

/**
 * Fetch User's Recent Threads
 */
export const fetchUserThreads = async (account: ThreadsAccount, limit = 5) => {
    try {
        const fields = 'id,text,permalink,timestamp,media_type,media_url';
        const url = `${THREADS_API_BASE}/${account.userId}/threads?fields=${fields}&limit=${limit}&access_token=${account.token}`;
        const res = await fetch(url);
        const data = await res.json();
        if (data.error) throw new Error(data.error.message);
        return data.data || [];
    } catch (e: any) {
        console.error("Fetch threads failed", e);
        return [];
    }
};

/**
 * Fetch Replies for a specific Media Object (Thread)
 * Note: Threads API 'replies' edge might be restricted or require specific scopes.
 * If 'replies' edge is not available on v1, we might simulate empty or use 'conversation' if avail.
 * Assuming v1 standard 'replies' edge availability.
 */
export const fetchMediaReplies = async (account: ThreadsAccount, mediaId: string) => {
    try {
        // Requesting replies
        const fields = 'id,text,timestamp,username,permalink'; // username might need expansion if field exists, else from owner node
        const url = `${THREADS_API_BASE}/${mediaId}/replies?fields=${fields}&access_token=${account.token}`;
        const res = await fetch(url);
        const data = await res.json();
        if (data.error) throw new Error(data.error.message);
        return data.data || [];
    } catch (e: any) {
        // console.warn("Fetch replies failed (API might strictly limit reading others)", e);
        return [];
    }
};

/**
 * Refresh Long-Lived Token
 * GET https://graph.threads.net/refresh_access_token?grant_type=th_refresh_token&access_token=...
 */
export const refreshThreadsToken = async (token: string): Promise<{ success: boolean; newToken?: string; error?: string }> => {
    try {
        const res = await fetch(`${THREADS_GRAPH_BASE}/refresh_access_token?grant_type=th_refresh_token&access_token=${token}`);
        const data = await res.json();

        if (data.access_token) {
            return { success: true, newToken: data.access_token };
        } else if (data.error) {
            throw new Error(data.error.message);
        }
        throw new Error("API 回傳格式未知");
    } catch (e: any) {
        return { success: false, error: e.message };
    }
};

/**
 * Validate Threads Token & ID
 */
export const validateThreadsToken = async (userId: string, token: string): Promise<{ valid: boolean; username?: string; error?: string }> => {
    try {
        const url = `${THREADS_API_BASE}/${userId}?fields=id,username&access_token=${token}`;
        const res = await fetch(url);
        const data = await res.json();

        if (data.error) {
            return { valid: false, error: data.error.message };
        }

        if (data.id) {
            return { valid: true, username: data.username };
        }

        return { valid: false, error: "無法識別用戶資訊" };
    } catch (e: any) {
        return { valid: false, error: e.message };
    }
};

import React, { useState, useEffect } from 'react';
import { BrandSettings, ReferenceFile } from '../types';
import { validateFacebookToken, fetchRecentPostCaptions } from '../services/facebookService';
import { analyzeBrandTone, analyzeProductFile } from '../services/geminiService';
import { getCurrentUser, updateUserSettings } from '../services/authService';
import TokenTutorialModal from './TokenTutorialModal';

interface Props {
  onSave: (settings: BrandSettings) => void;
  initialSettings: BrandSettings;
}

interface BrandProfile {
    id: string;
    name: string;
    settings: BrandSettings;
}

const SettingsForm: React.FC<Props> = ({ onSave, initialSettings }) => {
  const [profiles, setProfiles] = useState<BrandProfile[]>([]);
  const [currentProfileId, setCurrentProfileId] = useState<string>('default');
  const [formData, setFormData] = useState<BrandSettings>(initialSettings);

  const [tokenStatus, setTokenStatus] = useState<'idle' | 'checking' | 'valid' | 'invalid' | 'partial'>('idle');
  const [missingPerms, setMissingPerms] = useState<string[]>([]);
  const [validationError, setValidationError] = useState('');
  const [debugData, setDebugData] = useState<any>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [isAnalyzingTone, setIsAnalyzingTone] = useState(false);
  const [showTutorial, setShowTutorial] = useState(false);

  useEffect(() => {
      const savedProfiles = localStorage.getItem('autosocial_brand_profiles');
      if (savedProfiles) {
          const parsed = JSON.parse(savedProfiles);
          setProfiles(parsed);
          const lastId = localStorage.getItem('autosocial_last_profile_id');
          if (lastId && parsed.find((p: any) => p.id === lastId)) {
              setCurrentProfileId(lastId);
              const target = parsed.find((p: any) => p.id === lastId);
              if(target) loadSettingsIntoForm(target.settings);
          } else if (parsed.length > 0) {
              setCurrentProfileId(parsed[0].id);
              loadSettingsIntoForm(parsed[0].settings);
          }
      } else {
          const defaultProfile = { id: 'default', name: initialSettings.industry || '預設品牌', settings: initialSettings };
          setProfiles([defaultProfile]);
          setCurrentProfileId('default');
          loadSettingsIntoForm(initialSettings);
      }
  }, []);

  const loadSettingsIntoForm = (settings: BrandSettings) => {
      setFormData({
          ...initialSettings,
          ...settings,
          // competitors: settings.competitors || [], // Removed
          referenceFiles: settings.referenceFiles || []
      });
      setTokenStatus('idle');
      setValidationError('');
      setMissingPerms([]);
      setDebugData(null);
  };

  useEffect(() => {
      if (profiles.length > 0) localStorage.setItem('autosocial_brand_profiles', JSON.stringify(profiles));
  }, [profiles]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (name === 'facebookToken') {
        setTokenStatus('idle');
        setValidationError('');
        setDebugData(null);
    }
  };

  const checkToken = async () => {
    if (!formData.facebookToken) {
        setValidationError('請先填寫 Token');
        setTokenStatus('invalid');
        return;
    }

    setTokenStatus('checking');
    setValidationError('');
    setMissingPerms([]);
    setDebugData(null);

    try {
        // Only Verify Validity & Permissions
        const res = await validateFacebookToken(formData.facebookToken);

        if (res.valid) {
            setTokenStatus(res.status === 'VALID' ? 'valid' : 'partial');
            setMissingPerms(res.missingPermissions);
            setDebugData(res.debugInfo);
        } else {
            setTokenStatus('invalid');
            setValidationError(res.error || 'Token 無效');
            setDebugData(res.debugInfo);
        }
    } catch (e: any) {
        setTokenStatus('invalid');
        setValidationError(e.message || '發生錯誤');
    }
  };

  const handleAutoAnalyzeStyle = async () => {
      if (!formData.facebookPageId || !formData.facebookToken) {
          alert("請先填寫並驗證 Facebook Page ID 與 Token");
          return;
      }

      setIsAnalyzingTone(true);
      try {
          // 1. Fetch recent posts
          const posts = await fetchRecentPostCaptions(formData.facebookPageId, formData.facebookToken, 15);
          if (posts.length < 3) {
              alert("貼文數量過少，無法有效分析 (至少需要 3 篇)。");
              setIsAnalyzingTone(false);
              return;
          }

          // 2. AI Analyze
          const styleGuide = await analyzeBrandTone(posts);

          // 3. Update Form
          setFormData(prev => ({ ...prev, brandStyleGuide: styleGuide }));
          alert("✅ 分析完成！已更新「品牌風格指南」。\nAI 將依據此風格撰寫貼文。");
      } catch (e: any) {
          alert(`分析失敗: ${e.message}`);
      } finally {
          setIsAnalyzingTone(false);
      }
  };

  const handleRefFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const text = await file.text();
      const newFile: ReferenceFile = { name: file.name, content: text };
      setFormData(prev => ({ ...prev, referenceFiles: [...(prev.referenceFiles || []), newFile] }));
  };

  const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file && file.size < 500000) {
          const reader = new FileReader();
          reader.onload = (ev) => setFormData(p => ({ ...p, logoUrl: ev.target?.result as string }));
          reader.readAsDataURL(file);
      } else alert("檔案過大（上限 500KB）");
  };

  const handleSaveWrapper = async () => {
      setIsSaving(true);
      try {
          const updatedProfiles = profiles.map(p => p.id === currentProfileId ? { ...p, settings: formData } : p);
          setProfiles(updatedProfiles);
          onSave(formData);
          const user = getCurrentUser();
          if (user) await updateUserSettings(user.uid, formData);
          alert("設定已儲存");
      } catch (e) {
          alert("儲存失敗");
      } finally {
          setIsSaving(false);
      }
  };

  return (
    <div className="max-w-5xl mx-auto p-6 bg-card rounded-xl border border-gray-700 animate-fade-in pb-24">
      <div className="flex justify-between items-center mb-8 border-b border-gray-700 pb-4">
          <div className="flex flex-col">
              <label className="text-xs text-gray-500 mb-1 font-bold">當前品牌身份</label>
              <select 
                value={currentProfileId} 
                onChange={(e) => {
                    const target = profiles.find(p => p.id === e.target.value);
                    if (target) { 
                        setCurrentProfileId(e.target.value); 
                        loadSettingsIntoForm(target.settings); 
                        localStorage.setItem('autosocial_last_profile_id', e.target.value);
                    }
                }} 
                className="bg-dark border border-primary rounded p-2 text-white font-bold text-xl outline-none"
              >
                  {profiles.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
          </div>
          <button onClick={() => {
              const name = prompt("請輸入新品牌名稱:");
              if (name) {
                  const id = 'brand_' + Date.now();
                  const newProfiles = [...profiles, { id, name, settings: initialSettings }];
                  setProfiles(newProfiles);
                  setCurrentProfileId(id); 
                  loadSettingsIntoForm(initialSettings);
              }
          }} className="bg-green-700 hover:bg-green-600 text-white px-4 py-2 rounded text-sm transition-colors">+ 新增品牌</button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* 左側：API & 基礎資訊 */}
        <div className="lg:col-span-1 space-y-6 border-r border-gray-800 pr-4">
          <h3 className="text-lg font-bold text-primary border-l-4 border-primary pl-3">1. API 連結設定</h3>

          <div>
            <label className="block text-sm text-gray-400 mb-1">Facebook 粉絲專頁 ID</label>
            <input name="facebookPageId" value={formData.facebookPageId || ''} onChange={handleChange} className="w-full bg-dark border border-gray-600 rounded p-2 text-white text-sm" placeholder="Page ID" />
          </div>

          <div>
            <label className="block text-sm text-gray-400 mb-1 flex justify-between">
                <span>Facebook Access Token</span>
                <button onClick={() => setShowTutorial(true)} className="text-primary hover:underline text-xs flex items-center gap-1">
                    ❓ 如何獲取 Token
                </button>
            </label>
            <div className="flex gap-2">
              <input name="facebookToken" type="password" value={formData.facebookToken || ''} onChange={handleChange} className="flex-1 bg-dark border border-gray-600 rounded p-2 text-white text-sm" placeholder="EAA..." />
              <button onClick={checkToken} disabled={tokenStatus === 'checking'} className={`px-3 rounded text-white text-xs font-bold ${tokenStatus === 'valid' || tokenStatus === 'partial' ? 'bg-green-600' : 'bg-gray-700 hover:bg-gray-600'}`}>
                {tokenStatus === 'checking' ? '...' : '驗證'}
              </button>
            </div>
            {tokenStatus === 'valid' && debugData && <p className="text-[10px] text-green-400 mt-1">✅ 已連線: {debugData.name}</p>}
            {tokenStatus === 'partial' && <p className="text-[10px] text-yellow-400 mt-1">⚠️ 部分權限缺失 (Page Token 可略過)</p>}
            {tokenStatus === 'invalid' && <p className="text-[10px] text-red-400 mt-1">❌ {validationError}</p>}
