      if (file) {
          const reader = new FileReader();
          reader.onload = (ev) => setGeneratedPosts(prev => prev.map(p => p.id === postId ? { ...p, uploadedImageBase64: ev.target?.result as string, imageSourceType: 'upload' } : p));
          reader.readAsDataURL(file);
      }
  };

