export const getApiServiceStatus = async (): Promise<{ keyStatus: boolean[], totalConfigured: number, hasOpenAI: boolean }> => {
    if (isMock) return { keyStatus: [true, true, true, false, false], totalConfigured: 3, hasOpenAI: true };
    try {
