                                  {/* NEW: Style Preset Dropdown (AUTHENTIC TAIWAN STYLE) */}
                                  <select 
                                      className="w-full bg-gray-800 border border-gray-700 rounded px-2 py-1 mb-2 text-white text-[10px] outline-none"
